from urllib.parse import urlsplit, urlunsplit

def convert_to_idn(url):
    """
    Convert a URL to IDN notation. It checks if the host can be encoded in ASCII.
    If not, it converts the host to IDN form.

    Input-Output Arguments
    :param url: String. The URL to be converted to IDN notation.
    :return: String. The URL in IDN notation.
    """
    parts = urlsplit(url)

    hostname = parts.hostname
    if hostname is None:
        return url

    try:
        hostname.encode("ascii")
        idn_host = hostname
    except UnicodeEncodeError:
        idn_host = hostname.encode("idna").decode("ascii")

    netloc = idn_host

    if parts.port:
        netloc += f":{parts.port}"

    if parts.username:
        if parts.password:
            netloc = f"{parts.username}:{parts.password}@{netloc}"
        else:
            netloc = f"{parts.username}@{netloc}"

    return urlunsplit((
        parts.scheme,
        netloc,
        parts.path,
        parts.query,
        parts.fragment
    ))

