routes: List[RouteInfo] = []

def walk(node, prefix: str = ""):
    if node is None:
        return

    # If the node itself represents a route endpoint, collect it
    if hasattr(node, "route") and node.route is not None:
        route = node.route
        routes.append(
            RouteInfo(
                path=prefix or "/",
                name=getattr(route, "name", None),
                methods=getattr(route, "methods", None),
                handler=getattr(route, "handler", None),
            )
        )

    # Walk common child containers used in compiled router structures
    for attr in ("children", "static_routes", "dynamic_routes", "routes"):
        if hasattr(node, attr):
            children = getattr(node, attr)
            if isinstance(children, dict):
                for segment, child in children.items():
                    next_prefix = f"{prefix}/{segment}".replace("//", "/")
                    walk(child, next_prefix)
            elif isinstance(children, (list, tuple)):
                for child in children:
                    segment = getattr(child, "segment", "")
                    next_prefix = f"{prefix}/{segment}".replace("//", "/")
                    walk(child, next_prefix)

    # Walk explicitly named branches if present
    for attr in ("static", "dynamic", "param", "wildcard"):
        if hasattr(node, attr):
            child = getattr(node, attr)
            segment = getattr(child, "segment", attr if child is not None else "")
            next_prefix = f"{prefix}/{segment}".replace("//", "/")
            walk(child, next_prefix)

