class FileMemory:
    def read_transaction(self):
        """
        This function creates a read transaction for the FileMemory instance. When the transaction begins
        (__enter__ method), it acquires a reader lock, ensuring thread-safe read access to a shared resource.
        Upon completion or exit of the transaction (__exit__ method), it releases this reader lock.

        Input-Output Arguments
        :param self: FileMemory. An instance of the FileMemory class.
        :return: ReadTransaction. The created ReadTransaction instance.
        """
        file_memory = self

        class ReadTransaction:
            def __enter__(self):
                file_memory.reader_lock.acquire()
                return file_memory

            def __exit__(self, exc_type, exc_val, exc_tb):
                file_memory.reader_lock.release()
                return False

        return ReadTransaction()

class DocumentFlattener:
    def format_document(self, document):
        """
        This function flattens the given document and returns a dictionary with the flattened keys and values.
        It uses a recursive approach to flatten the document.

        Example:
            {"a": 2, "b": {"c": {"d": 5}}, "e": [6, 7, 8]}
        becomes:
            {"a": 2, "b.c.d": 5, "e.0": 6, "e.1": 7, "e.2": 8}

        :param self: DocumentFlattener. An instance of the DocumentFlattener class.
        :param document: Dictionary. The document to be flattened.
        :return: Dictionary. The flattened document.
        """
        flattened = {}

        def _flatten(value, parent_key=""):
            if isinstance(value, dict):
                for key, val in value.items():
                    new_key = f"{parent_key}.{key}" if parent_key else str(key)
                    _flatten(val, new_key)
            elif isinstance(value, list):
                for index, item in enumerate(value):
                    new_key = f"{parent_key}.{index}" if parent_key else str(index)
                    _flatten(item, new_key)
            else:
                flattened[parent_key] = value

        _flatten(document)
        return flattened

