import base64

def decode_base64_values(doc):
    # Looks for '{"$base64": true..., "encoded": ...}' values and decodes them

    """
    Decode the base64 encoded values in the given document. It looks for the values with the format '{"$base64": true..., "encoded": ...}' and decodes them.
    Input-Output Arguments
    :param doc: Dictionary. The input document containing base64 encoded values.
    :return: Dictionary. The document with base64 encoded values decoded.
    """
    if isinstance(doc, dict):
        # If this dict itself is a base64 marker object, decode it
        if doc.get("$base64") is True and "encoded" in doc:
            encoded_value = doc["encoded"]
            if isinstance(encoded_value, str):
                return base64.b64decode(encoded_value)
            return encoded_value

        # Otherwise recursively process dictionary values
        return {key: decode_base64_values(value) for key, value in doc.items()}

    elif isinstance(doc, list):
        # Recursively process list items
        return [decode_base64_values(item) for item in doc]

    # Return unchanged for all other types
    return doc

