class DateChunker:
    def to_chunks(self, df, chunk_size='D', func=None, **kwargs):
        """
        This function chunks the dataframe/series by dates based on the given chunk size.
        It then applies the given function to each chunk generated by the chunker.
        The function cannot modify the date column of the dataframe.

        Input-Output Arguments
        :param df: pandas dataframe or series. The dataframe or series to be chunked.
        :param chunk_size: str. Any valid Pandas frequency string.
        :param func: function. The function to be applied to each chunk generated by the chunker.
                     This function CANNOT modify the date column of the dataframe.
        :param kwargs: Additional keyword arguments.
        :return: generator. A generator that produces tuples:
                 (start date, end date, chunk_size, dataframe/series).
        """
        import pandas as pd

        if df is None:
            raise ValueError("df cannot be None")

        if not isinstance(df, (pd.DataFrame, pd.Series)):
            raise TypeError("df must be a pandas DataFrame or Series")

        if func is not None and not callable(func):
            raise TypeError("func must be callable")

        # Determine the datetime source: DatetimeIndex or a date-like column
        date_col = kwargs.get("date_col", None)

        if isinstance(df.index, pd.DatetimeIndex):
            working = df.sort_index()
            grouper = pd.Grouper(freq=chunk_size)
            grouped = working.groupby(grouper)
            use_index = True
        else:
            if date_col is None:
                # Try to infer a datetime column
                datetime_cols = []
                if isinstance(df, pd.DataFrame):
                    datetime_cols = [
                        col for col in df.columns
                        if pd.api.types.is_datetime64_any_dtype(df[col])
                    ]
                if len(datetime_cols) == 1:
                    date_col = datetime_cols[0]
                else:
                    raise ValueError(
                        "df must have a DatetimeIndex or a datetime column specified via 'date_col'"
                    )

            if isinstance(df, pd.Series):
                raise ValueError("For Series input, a DatetimeIndex is required")

            working = df.copy()
            working[date_col] = pd.to_datetime(working[date_col])
            working = working.sort_values(by=date_col)
            grouped = working.groupby(pd.Grouper(key=date_col, freq=chunk_size))
            use_index = False

        for start_date, chunk in grouped:
            if chunk is None or len(chunk) == 0:
                continue

            original_date_values = chunk.index.copy() if use_index else chunk[date_col].copy()

            result = chunk
            if func is not None:
                result = func(chunk.copy(), **kwargs)

                if result is None:
                    result = chunk

                # Validate that the date column/index was not modified
                if use_index:
                    if not result.index.equals(original_date_values):
                        raise ValueError("func cannot modify the datetime index")
                else:
                    if date_col not in result.columns:
                        raise ValueError("func cannot remove the date column")
                    if not pd.Series(result[date_col]).reset_index(drop=True).equals(
                        pd.Series(original_date_values).reset_index(drop=True)
                    ):
                        raise ValueError("func cannot modify the date column")

            end_date = chunk.index.max() if use_index else chunk[date_col].max()
            yield (start_date, end_date, chunk_size, result)

