import sys

@contextmanager
def save_sys_std():
    """
    This function is a context manager that saves the current values of
    `sys.stdin`, `sys.stdout`, and `sys.stderr`, and flushes these file
    handles before and after switching them out, finally restoring them.
    Input-Output Arguments
    :param: No input parameters.
    :return: No return values.
    """
    old_stdin = sys.stdin
    old_stdout = sys.stdout
    old_stderr = sys.stderr

    for stream in (old_stdout, old_stderr):
        try:
            stream.flush()
        except Exception:
            pass

    try:
        yield
    finally:
        for stream in (sys.stdout, sys.stderr):
            try:
                stream.flush()
            except Exception:
                pass

        sys.stdin = old_stdin
        sys.stdout = old_stdout
        sys.stderr = old_stderr

        for stream in (sys.stdout, sys.stderr):
            try:
                stream.flush()
            except Exception:
                pass

import os

def which(cmd, path=None):
    """
    This function searches for the executable named *cmd* in the specified *path*. If *path* is not specified, it defaults to :envvar:`PATH`. It returns ``None`` if no such executable is found.

    Input-Output Arguments
    :param cmd: str. The name of the executable to search for.
    :param path: str. The path to search for the executable. Defaults to :envvar:`PATH`.
    :return: Optional[str]. The path to the executable if found, otherwise ``None``.
    """
    if not cmd:
        return None

    if path is None:
        path = os.environ.get("PATH", "")

    def _is_executable(file_path):
        return os.path.isfile(file_path) and os.access(file_path, os.X_OK)

    # If cmd already contains a path component, check it directly
    if os.path.dirname(cmd):
        return cmd if _is_executable(cmd) else None

    for directory in path.split(os.pathsep):
        if not directory:
            directory = os.curdir
        full_path = os.path.join(directory, cmd)
        if _is_executable(full_path):
            return full_path

    return None

