import itertools
import re


def subpaths_for_path_range(path_range, hardening_chars="'pH"):
    """
    This function returns an iterator of paths based on the given path range.
    It processes the input path range like the format "xx/xx/x-x" and returns
    an iterator of paths based on the given conditions "xx/xx/x1, xx/xx/x2"
    and so on.

    Input-Output Arguments
    :param path_range: String. The input path range.
    :param hardening_chars: String. The characters that indicate hardening.
                            Defaults to "'pH".
    :return: Iterator. An iterator of paths based on the given path range.
    """

    if path_range is None:
        return iter(())

    path_range = str(path_range).strip()
    if not path_range:
        return iter(())

    hardening_set = set(hardening_chars)

    def split_part(part):
        part = part.strip()
        hardened = False
        if part and part[-1] in hardening_set:
            hardened = True
            part = part[:-1]
        return part, hardened

    def expand_part(part):
        base, hardened = split_part(part)

        if not base:
            raise ValueError(f"Invalid path component: {part!r}")

        if "-" in base:
            if base.count("-") != 1:
                raise ValueError(f"Invalid range component: {part!r}")
            start_str, end_str = base.split("-")
            if not start_str.isdigit() or not end_str.isdigit():
                raise ValueError(f"Invalid range component: {part!r}")
            start, end = int(start_str), int(end_str)
            if end < start:
                raise ValueError(f"Range end before start in component: {part!r}")
            values = [str(i) for i in range(start, end + 1)]
        else:
            if not re.fullmatch(r"\d+", base):
                raise ValueError(f"Invalid path component: {part!r}")
            values = [base]

        if hardened:
            values = [v + "'" for v in values]

        return values

    parts = [p for p in path_range.split("/") if p != ""]
    expanded_parts = [expand_part(part) for part in parts]

    return ("/".join(combo) for combo in itertools.product(*expanded_parts))

