def extract_nets(obj, seen=None):
    if seen is None:
        seen = set()

    nets = []

    if obj is None:
        return nets

    # Prevent infinite recursion on cyclic references
    obj_id = id(obj) if not isinstance(obj, str) else obj
    if obj_id in seen:
        return nets
    seen.add(obj_id)

    # Direct network string/object
    if isinstance(obj, str):
        if obj in net_defs:
            nets.extend(extract_nets(net_defs[obj], seen))
        elif obj in svc_defs:
            nets.extend(extract_nets(svc_defs[obj], seen))
        else:
            nets.append(obj)
        return nets

    if isinstance(obj, dict):
        # Common direct network fields
        for key in ("network", "net", "subnet", "cidr"):
            if key in obj and obj[key] is not None:
                nets.append(obj[key])

        # Nested references
        for key in ("object", "objects", "members", "children", "networks", "services"):
            if key in obj and obj[key] is not None:
                value = obj[key]
                if isinstance(value, list):
                    for item in value:
                        nets.extend(extract_nets(item, seen.copy()))
                else:
                    nets.extend(extract_nets(value, seen.copy()))

        # Named references in db
        for key in ("name", "ref", "id"):
            if key in obj:
                ref = obj[key]
                if ref in net_defs:
                    nets.extend(extract_nets(net_defs[ref], seen.copy()))
                elif ref in svc_defs:
                    nets.extend(extract_nets(svc_defs[ref], seen.copy()))

        return nets

    if isinstance(obj, (list, tuple, set)):
        for item in obj:
            nets.extend(extract_nets(item, seen.copy()))
        return nets

    return nets

