def compare_ip_token(options, db):
  """
  This function checks if a network IP is contained in a network object. It iterates through the list of IPs and checks if each IP is in the network object. It then returns a string stating the results.

  Input-Output Arguments
  :param options: The options sent to the script.
  :param db: Network and service definitions.
  :return: String. The end-user string stating the results.
  """

  # Try to locate the network token/object from options
  token = (
    options.get("token")
    or options.get("network")
    or options.get("network_token")
    or options.get("object")
  )

  # Try to locate the list/string of IPs from options
  ip_values = (
    options.get("ips")
    or options.get("ip")
    or options.get("ip_list")
    or options.get("addresses")
    or []
  )

  if not token:
    return "No network token provided."

  # Normalize IP input into a list
  if isinstance(ip_values, str):
    ip_list = [ip.strip() for ip in ip_values.split(",") if ip.strip()]
  elif isinstance(ip_values, (list, tuple, set)):
    ip_list = [str(ip).strip() for ip in ip_values if str(ip).strip()]
  else:
    return "Invalid IP input."

  if not ip_list:
    return "No IPs provided."

  # Resolve the token into a network definition
  network_value = None

  if isinstance(db, dict):
    if token in db:
      network_value = db[token]
    elif "networks" in db and isinstance(db["networks"], dict) and token in db["networks"]:
      network_value = db["networks"][token]

  if network_value is None:
    return f"Network token '{token}' not found."

  # Support db entries that are strings or dicts containing network fields
  if isinstance(network_value, dict):
    network_value = (
      network_value.get("network")
      or network_value.get("cidr")
      or network_value.get("value")
      or network_value.get("subnet")
    )

  if not network_value:
    return f"Network token '{token}' does not contain a valid network definition."

  try:
    network_obj = ipaddress.ip_network(str(network_value), strict=False)
  except ValueError:
    return f"Invalid network definition for token '{token}': {network_value}"

  results = []
  for ip in ip_list:
    try:
      ip_obj = ipaddress.ip_address(ip)
      if ip_obj.version != network_obj.version:
        results.append(f"{ip} is not in {token} ({network_obj})")
      elif ip_obj in network_obj:
        results.append(f"{ip} is in {token} ({network_obj})")
      else:
        results.append(f"{ip} is not in {token} ({network_obj})")
    except ValueError:
      results.append(f"{ip} is not a valid IP address")

  return "\n".join(results)

