        """
        if length < 0:
            raise ValueError("length must be non-negative")

        # Use the provider's random generator if available so seeded instances
        # remain deterministic; otherwise fall back to os.urandom.
        if hasattr(self, "random") and self.random is not None:
            return bytes(self.random.getrandbits(8) for _ in range(length))

        import os
        return os.urandom(length)

