def dfs(model):
    if model in visited:
        return
    if model in visiting:
        raise ValueError("Circular dependency detected")

    visiting.add(model)

    for dependency in get_dependencies(model) or []:
        if dependency in models:
            dfs(dependency)

    visiting.remove(model)
