from typing import Any, Tuple


def numeric_expectations(
    name: str, summary: dict, batch: Any, *args
) -> Tuple[str, dict, Any]:
    """
    It checks the numeric expectations of the given batch and returns the name, summary, and batch.

    Input-Output Arguments
    :param name: str. The name of the column.
    :param summary: dict. The summary of the column.
    :param batch: Any. The batch of data to be checked.
    :param *args: Any. Additional arguments.
    :return: Tuple[str, dict, Any]. The name, summary, and batch.
    """
    if summary is None:
        summary = {}

    # Initialize numeric expectation container
    summary.setdefault("numeric_expectations", {})

    values = None

    # Try to extract column values from common batch types
    try:
        if hasattr(batch, "__getitem__"):
            values = batch[name]
        elif hasattr(batch, name):
            values = getattr(batch, name)
    except Exception:
        values = None

    # Fallback: use batch directly if it looks iterable
    if values is None:
        values = batch

    numeric_values = []
    non_numeric_count = 0
    null_count = 0

    try:
        iterator = list(values)
    except Exception:
        iterator = [values]

    for value in iterator:
        if value is None:
            null_count += 1
            continue
        try:
            numeric_values.append(float(value))
        except (TypeError, ValueError):
            non_numeric_count += 1

    count = len(iterator)
    numeric_count = len(numeric_values)

    expectations = {
        "count": count,
        "numeric_count": numeric_count,
        "non_numeric_count": non_numeric_count,
        "null_count": null_count,
        "all_numeric": non_numeric_count == 0,
    }

    if numeric_values:
        expectations.update(
            {
                "min": min(numeric_values),
                "max": max(numeric_values),
                "mean": sum(numeric_values) / numeric_count,
            }
        )

    summary["numeric_expectations"][name] = expectations

    return name, summary, batch

