from typing import Optional

def sort_column_names(dct: dict, sort: Optional[str]) -> dict:
    """
    Sort the column names of the given dictionary in ascending or descending
    order based on the input parameter. If the sort parameter is None, the
    original dictionary is returned.

    Input-Output Arguments
    :param dct: Dict. The input dictionary to be sorted.
    :param sort: Optional string. The sorting order. It can be "ascending",
                 "descending" or None.
    :return: Dict. The sorted dictionary.
    """
    if sort is None:
        return dct

    if sort == "ascending":
        return {key: dct[key] for key in sorted(dct.keys())}
    elif sort == "descending":
        return {key: dct[key] for key in sorted(dct.keys(), reverse=True)}
    else:
        raise ValueError("sort must be 'ascending', 'descending', or None")

