if etag_str is None:
    return []

etag_str = etag_str.strip()
if not etag_str:
    return []

if etag_str == "*":
    return ["*"]

etags = []
i = 0
n = len(etag_str)

while i < n:
    # Skip whitespace and commas between values
    while i < n and etag_str[i] in " \t,":
        i += 1

    if i >= n:
        break

    # Optional weak validator prefix: W/
    if etag_str.startswith("W/", i):
        i += 2
        while i < n and etag_str[i] in " \t":
            i += 1

    # Expect quoted string
    if i < n and etag_str[i] == '"':
        start = i
        i += 1
        escaped = False

        while i < n:
            ch = etag_str[i]
            if escaped:
                escaped = False
            elif ch == "\\":
                escaped = True
            elif ch == '"':
                i += 1
                etags.append(etag_str[start:i])
                break
            i += 1
        else:
            # Unterminated quoted string; stop parsing
            break
    else:
        # Skip invalid token until next comma
        while i < n and etag_str[i] != ",":
            i += 1

return etags

import numpy as np

def gamma_transform(img, gamma):
    """
    This function applies gamma correction to the input image. It first checks the data type of the input image and then applies the gamma correction accordingly.

    Input-Output Arguments
    :param img: Numpy array. The input image.
    :param gamma: Float. The gamma value for the transformation.
    :return: Numpy array. The transformed image after applying gamma correction.
    """
    if gamma <= 0:
        raise ValueError("gamma must be greater than 0")

    img = np.asarray(img)

    if np.issubdtype(img.dtype, np.integer):
        max_val = np.iinfo(img.dtype).max
        img_norm = img.astype(np.float32) / max_val
        transformed = np.power(img_norm, gamma)
        transformed = np.clip(transformed * max_val, 0, max_val)
        return transformed.astype(img.dtype)

    elif np.issubdtype(img.dtype, np.floating):
        transformed = np.power(img, gamma)
        return transformed.astype(img.dtype)

    else:
        raise TypeError("Unsupported image dtype. Use integer or floating-point image arrays.")

factor = factor % 4

