import typing


class ReplayCompose:
    @staticmethod
    def replay(saved_augmentations: typing.Dict[str, typing.Any], **kwargs) -> typing.Dict[str, typing.Any]:
        """
        This function replays the saved augmentations on the input data and returns the augmented data.

        Input-Output Arguments
        :param saved_augmentations: Dict. A dictionary containing the saved augmentations.
        :param **kwargs: Any. Additional keyword arguments to be passed to the augmentations.
        :return: Dict. The augmented data after replaying the saved augmentations.
        """
        if not isinstance(saved_augmentations, dict):
            raise TypeError("saved_augmentations must be a dictionary")

        transforms = saved_augmentations.get("transforms", [])
        data = dict(kwargs)

        for transform in transforms:
            if not isinstance(transform, dict):
                continue

            applied = transform.get("applied", True)
            if not applied:
                continue

            transform_fn = transform.get("transform") or transform.get("fn")
            params = transform.get("params", {})

            if transform_fn is None:
                continue

            if not callable(transform_fn):
                raise TypeError("Saved transform must be callable")

            result = transform_fn(**data, **params)

            if isinstance(result, dict):
                data.update(result)
            else:
                raise TypeError("Transform replay must return a dictionary")

        return data

