class IPUStats:
    def sample(self) -> None:
        """
        This function samples the IPU stats and logs the metrics for the devices.
        It first gets the devices and their metrics. Then, it filters the metrics
        based on the user process id and logs the metrics for the devices that have
        not been called before or have variable metric keys. An exception will be
        thrown if any errors occur.

        Input-Output Arguments
        :param self: IPUStats. An instance of the IPUStats class.
        :return: None. No return value.
        """
        try:
            devices = self.get_devices()
            metrics_by_device = self.get_device_metrics(devices)

            for device_id, metrics in metrics_by_device.items():
                if not isinstance(metrics, dict):
                    continue

                user_pid = getattr(self, "pid", None)
                metric_pid = metrics.get("pid")

                if user_pid is not None and metric_pid is not None and metric_pid != user_pid:
                    continue

                should_log = False

                if not hasattr(self, "_seen_devices"):
                    self._seen_devices = set()

                if not hasattr(self, "_metric_keys_by_device"):
                    self._metric_keys_by_device = {}

                current_keys = set(metrics.keys())
                previous_keys = self._metric_keys_by_device.get(device_id)

                if device_id not in self._seen_devices:
                    should_log = True
                    self._seen_devices.add(device_id)
                elif previous_keys is None or previous_keys != current_keys:
                    should_log = True

                self._metric_keys_by_device[device_id] = current_keys

                if should_log:
                    if hasattr(self, "log_metrics") and callable(self.log_metrics):
                        self.log_metrics(device_id, metrics)
                    elif hasattr(self, "logger"):
                        self.logger.info("IPU device %s metrics: %s", device_id, metrics)

        except Exception as exc:
            raise RuntimeError(f"Failed to sample IPU stats: {exc}") from exc

