import math

def log1mexp(x, *, negative_input=False):
    """
    This function returns the log of 1 minus the exponential of the negative input.
    It is designed to be numerically more stable than the naive approach.

    Input-Output Arguments
    :param x: Numeric. The input value.
    :param negative_input: Bool. Whether the input is negative. Defaults to False.
                           If False, computes log(1 - exp(-x)) for x >= 0.
                           If True, computes log(1 - exp(x)) for x <= 0.
    :return: Numeric. The log of 1 minus the exponential term.
    """
    log2 = math.log(2.0)

    if negative_input:
        # x is assumed <= 0, compute log(1 - exp(x))
        if x > 0:
            raise ValueError("x must be <= 0 when negative_input=True")
        if x == 0:
            return float("-inf")
        if x < -log2:
            return math.log1p(-math.exp(x))
        else:
            return math.log(-math.expm1(x))
    else:
        # x is assumed >= 0, compute log(1 - exp(-x))
        if x < 0:
            raise ValueError("x must be >= 0 when negative_input=False")
        if x == 0:
            return float("-inf")
        if x <= log2:
            return math.log(-math.expm1(-x))
        else:
            return math.log1p(-math.exp(-x))

