from datetime import date, timedelta
import calendar


def daterange(start, stop, step=1, inclusive=False):
    """
    This function is a generator that yields a sequence of datetime.date objects,
    starting at the start date, incrementing by step, until the stop date is reached.
    It can also yield an infinite sequence of dates if the stop date is set to None.

    Input-Output Arguments
    :param start (datetime.date): The starting date. The first value in the sequence.
    :param stop (datetime.date): The stopping date. By default not included in return.
        Can be `None` to yield an infinite sequence.
    :param step (int): The value to increment *start* by to reach *stop*. Can be an
        :class:`int` number of days, a :class:`datetime.timedelta`, or a
        :class:`tuple` of integers, `(year, month, day)`. Positive and negative
        *step* values are supported.
    :param inclusive (bool): Whether or not the *stop* date can be returned. *stop*
        is only returned when a *step* falls evenly on it.
    :return: A generator that yields a sequence of datetime.date objects.
    """

    def add_ymd(d, y=0, m=0, day=0):
        year = d.year + y
        month = d.month + m

        while month > 12:
            year += 1
            month -= 12
        while month < 1:
            year -= 1
            month += 12

        max_day = calendar.monthrange(year, month)[1]
        new_day = min(d.day, max_day)

        result = date(year, month, new_day)
        if day:
            result += timedelta(days=day)
        return result

    if isinstance(step, int):
        if step == 0:
            raise ValueError("step must not be zero")
        step_delta = timedelta(days=step)
        step_fn = lambda d: d + step_delta
        step_sign = 1 if step > 0 else -1

    elif isinstance(step, timedelta):
        if step == timedelta(0):
            raise ValueError("step must not be zero")
        step_fn = lambda d: d + step
        step_sign = 1 if step > timedelta(0) else -1

    elif isinstance(step, tuple) and len(step) == 3:
        y, m, day = step
        if y == 0 and m == 0 and day == 0:
            raise ValueError("step must not be zero")

        def step_fn(d):
            return add_ymd(d, y, m, day)

        probe = step_fn(start)
        if probe == start:
            raise ValueError("step must advance date")
        step_sign = 1 if probe > start else -1

    else:
        raise TypeError("step must be int, datetime.timedelta, or (year, month, day) tuple")

    current = start

    if stop is None:
        while True:
            yield current
            current = step_fn(current)
    else:
        if step_sign > 0:
            cmp = (lambda d: d <= stop) if inclusive else (lambda d: d < stop)
        else:
            cmp = (lambda d: d >= stop) if inclusive else (lambda d: d > stop)

        while cmp(current):
            yield current
            current = step_fn(current)

class OneToOne:
    def update(self, dict_or_iterable, **kw):

        """
        Update the OneToOne instance with the given dictionary or iterable and keyword arguments. It first checks if the input is a dictionary or an iterable and then updates the instance with the input values.
        Input-Output Arguments
        :param self: OneToOne. An instance of the OneToOne class.
        :param dict_or_iterable: Dictionary or Iterable. The dictionary or iterable to update the instance with.
        :param kw: Keyword arguments. Additional keyword arguments to update the instance with.
        :return: No return values.
        """
        if hasattr(dict_or_iterable, "keys"):
            for key in dict_or_iterable:
                self[key] = dict_or_iterable[key]
        else:
            for key, value in dict_or_iterable:
                self[key] = value

        for key, value in kw.items():
            self[key] = value

class FrozenDict:
    def updated(self, *a, **kw):
        """
        Make a copy of the FrozenDict and add items from a dictionary or iterable
        (and/or keyword arguments), overwriting values under an existing key.

        Input-Output Arguments
        :param self: FrozenDict. An instance of the FrozenDict class.
        :param *a: Tuple. A tuple of dictionaries or iterables.
        :param **kw: Dict. A dictionary of keyword arguments.
        :return: The updated FrozenDict instance.
        """
        data = dict(self)

        if len(a) > 1:
            raise TypeError(
                "updated expected at most 1 positional argument, got %d" % len(a)
            )

        if a:
            other = a[0]
            if hasattr(other, "keys"):
                for key in other:
                    data[key] = other[key]
            else:
                for key, value in other:
                    data[key] = value

        if kw:
            data.update(kw)

        return self.__class__(data)

