import inspect
import importlib

def _validator(value):
    obj = value

    if isinstance(value, str):
        if "." not in value:
            raise TypeError(f"String value '{value}' is not a valid fully-qualified callable name")
        module_name, attr_name = value.rsplit(".", 1)
        try:
            module = importlib.import_module(module_name)
            obj = getattr(module, attr_name)
        except (ImportError, AttributeError) as exc:
            raise TypeError(f"Could not resolve callable '{value}'") from exc

    if not callable(obj):
        raise TypeError(f"Expected a callable, got {type(obj).__name__}")

    if arity != -1:
        try:
            sig = inspect.signature(obj)
        except (TypeError, ValueError) as exc:
            raise TypeError(f"Cannot determine signature for callable '{obj}'") from exc

        positional_params = [
            p for p in sig.parameters.values()
            if p.kind in (inspect.Parameter.POSITIONAL_ONLY,
                          inspect.Parameter.POSITIONAL_OR_KEYWORD)
        ]
        required_count = len(positional_params)

        if required_count != arity:
            raise TypeError(
                f"Callable must have arity {arity}, got {required_count}"
            )

    return obj

return _validator

