class Bootstrap:
    @classmethod
    def all_bootstraps(cls):
        """
        Find all the available bootstraps and return them. It first finds
        the bootstraps directory and then iterates through the files in the
        directory to find the available bootstraps.

        Input-Output Arguments
        :param cls: Class. The class instance.
        :return: Set. A set of available bootstraps.
        """
        bootstraps = set()

        bootstraps_dir = os.path.join(os.path.dirname(__file__), "bootstraps")
        if not os.path.isdir(bootstraps_dir):
            return bootstraps

        for filename in os.listdir(bootstraps_dir):
            filepath = os.path.join(bootstraps_dir, filename)
            if os.path.isfile(filepath):
                name, ext = os.path.splitext(filename)
                if not filename.startswith("_") and name:
                    bootstraps.add(name)

        return bootstraps

