from typing import Any
from enum import Enum


def color_properties(colors: Any, *prop: str) -> Any:
    """
    This function adds properties(Bold, Italics, etc...) to Enum Colors in theme files.
    It creates a new Enum with the given properties and returns it.

    Input-Output Arguments
    :param colors: Any. The Enum colors to which properties are to be added.
    :param prop: str. The properties to be added to the Enum colors.
    :return: Any. The updated Enum with the added properties.
    """
    if not issubclass(colors, Enum):
        raise TypeError("colors must be an Enum class")

    properties = [str(p) for p in prop if p is not None]

    new_members = {}
    for member in colors:
        value = member.value

        if isinstance(value, tuple):
            new_value = value + tuple(properties)
        else:
            new_value = (value, *properties)

        new_members[member.name] = new_value

    return Enum(f"{colors.__name__}WithProperties", new_members)

