import functools
import warnings


def deprecated_method(new_func=None):
    """
    This function is a decorator that can be used to mark deprecated methods.
    It will report a DeprecationWarning being emitted to stderr when the
    deprecated method is used.

    Input-Output Arguments
    :param new_func: Function. The new function that replaces the deprecated method.
    :return: The deprecated_method_wrapper function.
    """

    def decorator(old_func):
        @functools.wraps(old_func)
        def deprecated_method_wrapper(*args, **kwargs):
            if new_func is not None:
                message = (
                    f"'{old_func.__name__}' is deprecated and will be removed in a "
                    f"future version. Use '{new_func.__name__}' instead."
                )
            else:
                message = (
                    f"'{old_func.__name__}' is deprecated and will be removed in a "
                    f"future version."
                )

            warnings.warn(message, category=DeprecationWarning, stacklevel=2)
            return old_func(*args, **kwargs)

        return deprecated_method_wrapper

    return decorator

