class JID:
    @classmethod
    def fromstr(cls, s, *, strict=True):
        """
        Construct a JID instance from a string containing it. It parses the
        input string and constructs a JID instance based on the parsed
        components.

        Input-Output Arguments
        :param s: The string to parse.
        :type s: :class:`str`
        :param strict: Whether to enable strict parsing.
        :type strict: :class:`bool`
        :raises: See :class:`JID`
        :return: The parsed JID
        :rtype: :class:`JID`
        """
        if not isinstance(s, str):
            raise TypeError("s must be a str")

        localpart = None
        domainpart = None
        resourcepart = None

        # Split resourcepart first: local@domain/resource
        if "/" in s:
            bare, resourcepart = s.split("/", 1)
        else:
            bare = s

        # Split localpart from domainpart: local@domain
        if "@" in bare:
            localpart, domainpart = bare.split("@", 1)
        else:
            domainpart = bare

        # Normalize empty strings to None where appropriate
        if localpart == "":
            localpart = None
        if domainpart == "":
            domainpart = None
        if resourcepart == "":
            resourcepart = None

        if strict and domainpart is None:
            raise ValueError("JID must contain a domainpart")

        return cls(localpart=localpart, domainpart=domainpart, resourcepart=resourcepart, strict=strict)

