            chosen = records.pop()
        else:
            total_weight = sum(get_attr(r, "weight", 1) for r in records)

            if total_weight <= 0:
                chosen = records.pop(rng.randrange(len(records)))
            else:
                pick = rng.uniform(0, total_weight)
                running = 0
                chosen_index = len(records) - 1

                for i, r in enumerate(records):
                    running += get_attr(r, "weight", 1)
                    if pick < running:
                        chosen_index = i
                        break

                chosen = records.pop(chosen_index)

        ordered.append((
            get_attr(chosen, "target", 3),
            get_attr(chosen, "port", 2),
        ))

return ordered

