                result["subjectAltName"].append((name.strip(), value.strip()))
            else:
                result["subjectAltName"].append(entry)

return result

import asyncio
import functools


class AdHocSignal:
    @classmethod
    def ASYNC_WITH_LOOP(cls, loop=None):
        """
        The function creates a wrapper for the given function to be executed asynchronously
        with the given event loop. It first checks if the loop is provided, if not, it gets
        the default event loop. Then, it creates a wrapper for the given function to be
        executed asynchronously with the provided loop.

        Input-Output Arguments
        :param cls: Class. The class instance.
        :param loop: Event loop. The event loop to be used for asynchronous execution.
                     Defaults to None.
        :return: Wrapper function. The wrapper function for the given function to be
                 executed asynchronously with the provided loop.
        """
        if loop is None:
            loop = asyncio.get_event_loop()

        def decorator(func):
            @functools.wraps(func)
            def wrapper(*args, **kwargs):
                if asyncio.iscoroutinefunction(func):
                    return loop.create_task(func(*args, **kwargs))
                return loop.run_in_executor(None, functools.partial(func, *args, **kwargs))
            return wrapper

        return decorator

class AdHocSignal:
    def SPAWN_WITH_LOOP(cls, loop):
        """
        Create a spawn function that can be used to spawn a coroutine function. It ensures that the function is a coroutine and then adds a done callback to the task to log the spawned task.
        Input-Output Arguments
        :param cls: AdHocSignal. The class instance.
        :param loop: The event loop to be used. If not specified, the default event loop is used.
        :return: The spawn function.
        """
        import asyncio
        import inspect
        import logging

        logger = logging.getLogger(__name__)

        def _log_spawned_task(task):
            try:
                exc = task.exception()
                if exc is not None:
                    logger.exception("Spawned task failed", exc_info=exc)
            except asyncio.CancelledError:
                logger.debug("Spawned task was cancelled")
            except Exception:
                logger.exception("Error while inspecting spawned task")

        def spawn(func, *args, **kwargs):
            if inspect.iscoroutinefunction(func):
                coro = func(*args, **kwargs)
            else:
                coro = func(*args, **kwargs)
                if not inspect.iscoroutine(coro):
                    raise TypeError("spawn() expected a coroutine function or coroutine result")

            task = loop.create_task(coro)
            task.add_done_callback(_log_spawned_task)
            return task

        return spawn

import asyncio

def first_signal(*signals):
    """
    This function connects to multiple signals and waits for the first signal to emit.
    It returns an awaitable for the first signal to emit. The awaitable returns
    the first argument passed to the signal. If the first argument is an exception,
    the exception is re-raised from the awaitable.

    :param signals: Signals to connect to. It can be of type AdHocSignal.
    :return: An awaitable for the first signal to emit.
    """
    loop = asyncio.get_event_loop()
    future = loop.create_future()
    connections = []

    def disconnect_all():
        for signal, handler in connections:
            try:
                if hasattr(signal, "disconnect"):
                    signal.disconnect(handler)
                elif hasattr(signal, "remove"):
                    signal.remove(handler)
            except Exception:
                pass
        connections.clear()

    def handler(*args, **kwargs):
        if future.done():
            return

        disconnect_all()

        value = args[0] if args else None
        if isinstance(value, BaseException):
            future.set_exception(value)
        else:
            future.set_result(value)

    for signal in signals:
        if hasattr(signal, "connect"):
            signal.connect(handler)
            connections.append((signal, handler))
        elif hasattr(signal, "append"):
            signal.append(handler)
            connections.append((signal, handler))
        else:
            raise TypeError(f"Unsupported signal type: {type(signal)!r}")

    return future

