# X.509 Certificate ::= SEQUENCE {
#     tbsCertificate       TBSCertificate,
#     signatureAlgorithm   AlgorithmIdentifier,
#     signatureValue       BIT STRING
# }
#
# TBSCertificate ::= SEQUENCE {
#     ...
#     subjectPublicKeyInfo SubjectPublicKeyInfo,
#     ...
# }
#
# SubjectPublicKeyInfo ::= SEQUENCE {
#     algorithm            AlgorithmIdentifier,
#     subjectPublicKey     BIT STRING
# }

try:
    tbs_certificate = pyasn1_struct.getComponentByPosition(0)
    subject_public_key_info = tbs_certificate.getComponentByName('subjectPublicKeyInfo')
except Exception:
    # Fallback for schemas without named components
    tbs_certificate = pyasn1_struct.getComponentByPosition(0)
    # In TBSCertificate, subjectPublicKeyInfo is typically the 7th field
    # when version is present, but pyasn1 schemas may vary.
    # Try common position first.
    try:
        subject_public_key_info = tbs_certificate.getComponentByPosition(6)
    except Exception:
        # Last-resort scan for a component named like SubjectPublicKeyInfo
        subject_public_key_info = None
        for i in range(len(tbs_certificate)):
            comp = tbs_certificate.getComponentByPosition(i)
            if comp is None:
                continue
            if comp.__class__.__name__ == 'SubjectPublicKeyInfo':
                subject_public_key_info = comp
                break
        if subject_public_key_info is None:
            raise ValueError("Could not locate subjectPublicKeyInfo in certificate structure")

return encode(subject_public_key_info)

