class TaskPool:
    def spawn(self, __groups, __coro_fun, *args, **kwargs):

        """
        This function starts a new coroutine and adds it to the pool atomically. It checks if the groups have free slots available for the coroutine to be spawned and raises a RuntimeError if the limit on any of the groups or the total limit is exhausted.
        Input-Output Arguments
        :param self: TaskPool. An instance of the TaskPool class.
        :param __groups: Set of group keys. The groups the coroutine belongs to.
        :param __coro_fun: Coroutine function to run.
        :param args: Positional arguments to pass to `coro_fun`.
        :param kwargs: Keyword arguments to pass to `coro_fun`.
        :raise RuntimeError: If the limit on any of the groups or the total limit is exhausted.
        :return: asyncio.Task. The task in which the coroutine runs.
        """
        groups = set(__groups or ())

        # Check total pool limit, if configured.
        total_limit = getattr(self, "_limit", None)
        if total_limit is not None:
            tasks = getattr(self, "_tasks", None)
            if tasks is None:
                tasks = getattr(self, "tasks", set())
            if len(tasks) >= total_limit:
                raise RuntimeError("task pool total limit exhausted")

        # Check per-group limits, if configured.
        group_limits = getattr(self, "_group_limits", None)
        group_tasks = getattr(self, "_group_tasks", None)

        if group_limits is not None:
            for group in groups:
                limit = group_limits.get(group)
                if limit is None:
                    continue
                current = 0
                if group_tasks is not None:
                    current = len(group_tasks.get(group, ()))
                if current >= limit:
                    raise RuntimeError(f"group limit exhausted for {group!r}")

        # Create the coroutine and task.
        coro = __coro_fun(*args, **kwargs)
        task = asyncio.create_task(coro)

        # Register task in pool structures.
        tasks = getattr(self, "_tasks", None)
        if tasks is None:
            self._tasks = set()
            tasks = self._tasks
        tasks.add(task)

        if not hasattr(self, "_task_groups"):
            self._task_groups = {}
        self._task_groups[task] = groups

        if not hasattr(self, "_group_tasks"):
            self._group_tasks = {}
        for group in groups:
            self._group_tasks.setdefault(group, set()).add(task)

        # Cleanup callback when task finishes.
        def _done_callback(t):
            self._tasks.discard(t)
            task_groups = self._task_groups.pop(t, set())
            for g in task_groups:
                group_set = self._group_tasks.get(g)
                if group_set is not None:
                    group_set.discard(t)
                    if not group_set:
                        self._group_tasks.pop(g, None)

        task.add_done_callback(_done_callback)
        return task

