            _, uri, localname, qname, attrs = event
            dest.startElementNS((uri, localname), qname, attrs)
        else:
            raise ValueError("invalid start event: {!r}".format(event))

    elif kind == "end":
        # ("end", name)
        if len(event) == 2:
            _, name = event
            dest.endElement(name)
        # ("end", uri, localname, qname)
        elif len(event) == 4:
            _, uri, localname, qname = event
            dest.endElementNS((uri, localname), qname)
        else:
            raise ValueError("invalid end event: {!r}".format(event))

    elif kind == "text":
        # ("text", content)
        if len(event) != 2:
            raise ValueError("invalid text event: {!r}".format(event))
        _, content = event
        dest.characters(content)

    elif kind == "startDocument":
        dest.startDocument()

    elif kind == "endDocument":
        dest.endDocument()

    elif kind == "processingInstruction":
        # ("processingInstruction", target, data)
        if len(event) != 3:
            raise ValueError(
                "invalid processingInstruction event: {!r}".format(event)
            )
        _, target, data = event
        dest.processingInstruction(target, data)

    elif kind == "ignorableWhitespace":
        # ("ignorableWhitespace", content)
        if len(event) != 2:
            raise ValueError(
                "invalid ignorableWhitespace event: {!r}".format(event)
            )
        _, content = event
        dest.ignorableWhitespace(content)

    elif kind == "skippedEntity":
        # ("skippedEntity", name)
        if len(event) != 2:
            raise ValueError("invalid skippedEntity event: {!r}".format(event))
        _, name = event
        dest.skippedEntity(name)

    else:
        raise ValueError("unknown event type: {!r}".format(kind))

import hashlib


def _calculate_hash(algo, hash_input):
    """
    Calculate the hash of the given input using the specified algorithm.

    Input-Output Arguments
    :param algo: String. The algorithm to be used for hashing.
    :param hash_input: The input data to be hashed.
    :return: The hash of the input data using the specified algorithm.
    """
    if not isinstance(algo, str):
        raise TypeError("algo must be a string")

    try:
        hasher = hashlib.new(algo.lower())
    except ValueError as exc:
        raise ValueError(f"Unsupported hash algorithm: {algo}") from exc

    if isinstance(hash_input, str):
        hash_input = hash_input.encode("utf-8")
    elif not isinstance(hash_input, (bytes, bytearray)):
        hash_input = str(hash_input).encode("utf-8")

    hasher.update(hash_input)
    return hasher.hexdigest()

