from typing import List

def _interpolation_search(arr: List[int], x: int) -> int:
    """
    This function returns the position i of a sorted array so that arr[i] <= x < arr[i+1].
    Raise `IndexError` if the array is empty or if the query is outside the array values.

    Input-Output Arguments
    :param arr: List[int]. A non-empty sorted list of integers.
    :param x: int. The query.
    :return: int. The position i so that arr[i] <= x < arr[i+1].
    """
    if not arr:
        raise IndexError("Array is empty")

    if x < arr[0] or x >= arr[-1]:
        raise IndexError("Query is outside the array values")

    low, high = 0, len(arr) - 1

    while low <= high and arr[low] <= x < arr[high]:
        if arr[high] == arr[low]:
            break

        pos = low + ((x - arr[low]) * (high - low)) // (arr[high] - arr[low])

        if pos >= len(arr) - 1:
            pos = len(arr) - 2

        if arr[pos] <= x < arr[pos + 1]:
            return pos
        elif x < arr[pos]:
            high = pos - 1
        else:
            low = pos + 1

    for i in range(max(0, low - 1), min(len(arr) - 1, high + 1)):
        if arr[i] <= x < arr[i + 1]:
            return i

    raise IndexError("Query is outside the array values")

