class DatasetDict:
    def align_labels_with_mapping(self, label2id: Dict, label_column: str) -> "DatasetDict":
        """
        Align the labels with the given mapping. It aligns the labels of the dataset
        with the given label2id mapping based on the label_column.

        Input-Output Arguments
        :param self: DatasetDict. An instance of the DatasetDict class.
        :param label2id: Dict. A dictionary that maps labels to ids.
        :param label_column: String. The name of the label column.
        :return: DatasetDict. The updated DatasetDict instance.
        """

        def _map_labels(example):
            value = example[label_column]

            # Handle sequence labels like token classification
            if isinstance(value, list):
                return {
                    label_column: [
                        label2id[v] if v in label2id else label2id[str(v)] if str(v) in label2id else v
                        for v in value
                    ]
                }

            # Handle single labels
            if value in label2id:
                return {label_column: label2id[value]}
            if str(value) in label2id:
                return {label_column: label2id[str(value)]}

            return {label_column: value}

        for split, dataset in self.items():
            self[split] = dataset.map(_map_labels)

        return self

