from dataclasses import fields, is_dataclass

def asdict(obj):
    """
    Convert an object to its dictionary representation recursively. It first checks if the object is a dataclass instance. If it is, it converts the object to a dictionary representation. If not, it checks if the object is a namedtuple, list, tuple, or dictionary and converts it accordingly.
    Input-Output Arguments
    :param obj: Any. The object to be converted to a dictionary representation.
    :return: Dict. The dictionary representation of the input object.
    """
    if is_dataclass(obj) and not isinstance(obj, type):
        return {f.name: asdict(getattr(obj, f.name)) for f in fields(obj)}
    elif isinstance(obj, tuple) and hasattr(obj, "_fields"):  # namedtuple
        return {key: asdict(value) for key, value in obj._asdict().items()}
    elif isinstance(obj, list):
        return [asdict(item) for item in obj]
    elif isinstance(obj, tuple):
        return tuple(asdict(item) for item in obj)
    elif isinstance(obj, dict):
        return {asdict(key): asdict(value) for key, value in obj.items()}
    else:
        return obj

class MetadataConfigs:
    @classmethod
    def from_dataset_card_data(cls, dataset_card_data: DatasetCardData) -> "MetadataConfigs":
        """
        Create a MetadataConfigs instance based on the given dataset card data. It first checks
        if the dataset card data contains the field name. If it does, it processes the metadata
        configurations and creates a MetadataConfigs instance.

        Input-Output Arguments
        :param cls: Class. The class itself.
        :param dataset_card_data: DatasetCardData. The dataset card data to be used to create
            the MetadataConfigs instance.
        :return: MetadataConfigs. The created MetadataConfigs instance.
        """
        field_name = getattr(cls, "FIELD_NAME", None)
        if field_name is None:
            raise AttributeError(f"{cls.__name__} must define FIELD_NAME")

        if dataset_card_data is None:
            return cls()

        data = None

        if isinstance(dataset_card_data, dict):
            data = dataset_card_data.get(field_name)
        else:
            data = getattr(dataset_card_data, field_name, None)
            if data is None:
                try:
                    data = dataset_card_data[field_name]
                except (TypeError, KeyError):
                    pass

        if data is None:
            return cls()

        if isinstance(data, cls):
            return data

        if isinstance(data, dict):
            return cls(**data)

        if isinstance(data, list):
            try:
                return cls(data)
            except TypeError:
                return cls(*data)

        return cls(data)

