import importlib
import typing


def import_from_string(import_str: str) -> typing.Any:
    """
    This function imports a module and retrieves an attribute from it based on the given import string.
    The import string should be in the format "<module>:<attribute>".
    It raises an exception if the module or attribute is not found.

    Input-Output Arguments
    :param import_str: String. The import string in the format "<module>:<attribute>".
    :return: Any. The retrieved attribute from the imported module.
    """
    if not isinstance(import_str, str):
        raise TypeError("import_str must be a string")

    try:
        module_str, attr_str = import_str.split(":", 1)
    except ValueError as exc:
        raise ValueError(
            'Import string must be in format "<module>:<attribute>"'
        ) from exc

    if not module_str or not attr_str:
        raise ValueError(
            'Import string must be in format "<module>:<attribute>"'
        )

    try:
        module = importlib.import_module(module_str)
    except ImportError as exc:
        raise ImportError(f'Could not import module "{module_str}"') from exc

    try:
        return getattr(module, attr_str)
    except AttributeError as exc:
        raise AttributeError(
            f'Module "{module_str}" does not define attribute "{attr_str}"'
        ) from exc

