class Table:
    def update_global_secondary_index(self, global_indexes):
        """
        This function updates the global index(es) in DynamoDB after the table has been created. It takes a dictionary of global indexes as input and updates the read and write capacity units for each index. It then updates the table with the new global index information.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param global_indexes: Dictionary. A dictionary specifying the global indexes to be updated. Each key in the dictionary represents the index name, and the corresponding value is another dictionary containing the read and write capacity units for the index.
        :return: Bool. Returns True if the global indexes are successfully updated, False otherwise.
        """
        try:
            if not global_indexes or not isinstance(global_indexes, dict):
                return False

            global_secondary_index_updates = []

            for index_name, provisioned_throughput in global_indexes.items():
                if not isinstance(provisioned_throughput, dict):
                    return False

                read_capacity_units = provisioned_throughput.get('read_capacity_units')
                write_capacity_units = provisioned_throughput.get('write_capacity_units')

                if read_capacity_units is None or write_capacity_units is None:
                    return False

                global_secondary_index_updates.append({
                    'Update': {
                        'IndexName': index_name,
                        'ProvisionedThroughput': {
                            'ReadCapacityUnits': read_capacity_units,
                            'WriteCapacityUnits': write_capacity_units
                        }
                    }
                })

            self.connection.update_table(
                TableName=self.table_name,
                GlobalSecondaryIndexUpdates=global_secondary_index_updates
            )
            return True
        except Exception:
            return False

class Table:
    def update(self, throughput=None, global_indexes=None):
        """
        This function updates the attributes and global indexes of a table in DynamoDB.
        It accepts optional parameters for throughput and global indexes.

        If provided, the throughput parameter should be a dictionary with 'read' and
        'write' keys, each associated with an integer value.

        The global_indexes parameter should also be a dictionary, where each key is
        the index name and the value is a dictionary with 'read' and 'write' keys,
        each associated with an integer value.

        The function returns True on success.

        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param throughput: Dictionary. Optional. Specifies the read and write capacity
                           units for the table. Defaults to None.
        :param global_indexes: Dictionary. Optional. Specifies the read and write
                               capacity units for the global indexes of the table.
                               Defaults to None.
        :return: bool. True if the update is successful, False otherwise.
        """
        try:
            update_payload = {}

            if throughput is not None:
                if not isinstance(throughput, dict):
                    return False
                if 'read' not in throughput or 'write' not in throughput:
                    return False

                update_payload['ProvisionedThroughput'] = {
                    'ReadCapacityUnits': throughput['read'],
                    'WriteCapacityUnits': throughput['write']
                }

            if global_indexes is not None:
                if not isinstance(global_indexes, dict):
                    return False

                gsi_updates = []
                for index_name, index_throughput in global_indexes.items():
                    if not isinstance(index_throughput, dict):
                        return False
                    if 'read' not in index_throughput or 'write' not in index_throughput:
                        return False

                    gsi_updates.append({
                        'Update': {
                            'IndexName': index_name,
                            'ProvisionedThroughput': {
                                'ReadCapacityUnits': index_throughput['read'],
                                'WriteCapacityUnits': index_throughput['write']
                            }
                        }
                    })

                if gsi_updates:
                    update_payload['GlobalSecondaryIndexUpdates'] = gsi_updates

            if not update_payload:
                return False

            # If a DynamoDB table resource/client method exists, use it.
            if hasattr(self, 'table') and hasattr(self.table, 'update'):
                self.table.update(**update_payload)
            elif hasattr(self, 'update_table') and callable(self.update_table):
                self.update_table(**update_payload)
            elif hasattr(self, 'client') and hasattr(self.client, 'update_table'):
                params = dict(update_payload)
                if hasattr(self, 'name'):
                    params['TableName'] = self.name
                elif hasattr(self, 'table_name'):
                    params['TableName'] = self.table_name
                else:
                    return False
                self.client.update_table(**params)
            else:
                # Fallback: store the update locally if no backend is attached.
                self._last_update = update_payload

            return True
        except Exception:
            return False

class Table:
    def _put_item(self, item_data, expects=None):
        """
        This function is used by the Item instances to save themselves to a Table instance.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param item_data: Item. Several Item instances to be saved.
        :param expects: Optional. The expected conditions for the save operation.
        :return: Bool. Returns True after saving the item to the table.
        """
        if not hasattr(self, "_items"):
            self._items = []

        if expects is not None:
            if callable(expects):
                if not expects(item_data):
                    return False
            elif isinstance(expects, dict):
                for key, expected_value in expects.items():
                    if item_data.get(key) != expected_value:
                        return False
            elif not expects:
                return False

        self._items.append(item_data)
        return True

class Table:
    def create_global_secondary_index(self, global_index):
        """
        This function creates a global secondary index in DynamoDB after the table has been created. It takes a `global_index` parameter, which should be a subclass of `GlobalBaseIndexField` representing the desired index. It updates the `global_indexes` information on the `Table` by calling `Table.describe`. It returns `True` on success.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param global_index: GlobalBaseIndexField subclass. The desired global index to be created.
        :return: Bool. Returns `True` if the global index is created successfully, otherwise `False`.
        """
        if global_index is None:
            return False

        try:
            index_name = getattr(global_index, "name", None) or getattr(global_index, "index_name", None)
            hash_key = getattr(global_index, "hash_key", None)
            range_key = getattr(global_index, "range_key", None)
            projection = getattr(global_index, "projection", None)
            throughput = getattr(global_index, "provisioned_throughput", None)

            if not index_name or not hash_key:
                return False

            attribute_definitions = []

            def _append_attr(attr):
                if not attr:
                    return
                attr_name = getattr(attr, "name", None) or getattr(attr, "attr_name", None) or attr
                attr_type = getattr(attr, "data_type", None) or getattr(attr, "attr_type", None)
                if isinstance(attr, str):
                    attr_type = attr_type or "S"
                if attr_name and attr_type:
                    definition = {
                        "AttributeName": attr_name,
                        "AttributeType": attr_type
                    }
                    if definition not in attribute_definitions:
                        attribute_definitions.append(definition)

            _append_attr(hash_key)
            _append_attr(range_key)

            key_schema = []
            hash_name = getattr(hash_key, "name", None) or getattr(hash_key, "attr_name", None) or hash_key
            key_schema.append({
                "AttributeName": hash_name,
                "KeyType": "HASH"
            })

            if range_key:
                range_name = getattr(range_key, "name", None) or getattr(range_key, "attr_name", None) or range_key
                key_schema.append({
                    "AttributeName": range_name,
                    "KeyType": "RANGE"
                })

            projection_dict = {"ProjectionType": "ALL"}
            if projection is not None:
                projection_type = getattr(projection, "projection_type", None) or getattr(projection, "type", None)
                non_key_attributes = getattr(projection, "non_key_attributes", None)

                if isinstance(projection, str):
                    projection_type = projection
                elif isinstance(projection, dict):
                    projection_type = projection.get("ProjectionType", "ALL")
                    non_key_attributes = projection.get("NonKeyAttributes")

                if projection_type:
                    projection_dict["ProjectionType"] = projection_type
                if non_key_attributes:
                    projection_dict["NonKeyAttributes"] = non_key_attributes

            if throughput is None:
                throughput = {
                    "ReadCapacityUnits": 1,
                    "WriteCapacityUnits": 1
                }
            elif not isinstance(throughput, dict):
                throughput = {
                    "ReadCapacityUnits": getattr(throughput, "read", 1) or getattr(throughput, "read_capacity_units", 1),
                    "WriteCapacityUnits": getattr(throughput, "write", 1) or getattr(throughput, "write_capacity_units", 1)
                }

            self.connection.update_table(
                TableName=self.name,
                AttributeDefinitions=attribute_definitions,
                GlobalSecondaryIndexUpdates=[
                    {
                        "Create": {
                            "IndexName": index_name,
                            "KeySchema": key_schema,
                            "Projection": projection_dict,
                            "ProvisionedThroughput": throughput
                        }
                    }
                ]
            )

            self.describe()
            return True
        except Exception:
            return False

class Table:
    def get_key_fields(self):
        """
        This function returns the fields necessary to make a key for a table. If the table does not already have a populated schema, it requests it. It returns a list of field names.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :return: List of field names (strings) that are necessary to make a key for the table.
        """
        if not hasattr(self, "schema") or not self.schema:
            if hasattr(self, "get_schema") and callable(self.get_schema):
                self.get_schema()
            else:
                return []

        key_fields = []

        fields = self.schema.get("fields", []) if isinstance(self.schema, dict) else []
        for field in fields:
            if isinstance(field, dict) and field.get("key", False):
                name = field.get("name")
                if name is not None:
                    key_fields.append(name)

        return key_fields

class Table:
    def delete_item(self, expected=None, conditional_operator=None, **kwargs):

        """
        This function deletes a single item from a table in DynamoDB. It allows for conditional deletes, where the item is only deleted if specific conditions are met. The function takes in the expected attribute values of the item to be deleted and the key attributes of the item. It returns True if the delete operation is successful and False if the conditional delete fails.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param expected: Dictionary. Optional. A dictionary of expected attribute value conditions.
        :param conditional_operator: String. Optional. The conditional operator to apply to the expected attribute value conditions. Defaults to 'AND'.
        :param kwargs: Key attributes of the item to be deleted.
        :return: Bool. True if the delete operation is successful, False if the conditional delete fails.
        """
        params = {
            'TableName': self.name,
            'Key': kwargs
        }

        if expected is not None:
            params['Expected'] = expected

        if conditional_operator is not None:
            params['ConditionalOperator'] = conditional_operator

        try:
            self.connection.delete_item(**params)
            return True
        except Exception as e:
            error_code = getattr(e, 'response', {}).get('Error', {}).get('Code')
            if error_code == 'ConditionalCheckFailedException':
                return False
            raise

class Table:
    def _build_filters(self, filter_kwargs, using=QUERY_OPERATORS):

        """
        This function is an internal method used to convert query/scan-style keyword arguments into the raw structure that DynamoDB expects for filtering. It creates a dictionary of filters based on the input filter_kwargs.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param filter_kwargs: Dictionary. The query/scan-style keyword arguments to be converted into filters.
        :param using: Dictionary. The dictionary of query operators to be used for comparison. It defaults to QUERY_OPERATORS if not specified.
        :return: None.
        """
        filters = {}

        if not filter_kwargs:
            return filters

        for key, value in filter_kwargs.items():
            parts = key.rsplit('__', 1)

            if len(parts) == 2 and parts[1] in using:
                field_name, op_name = parts
                operator = using[op_name]
            else:
                field_name = key
                operator = using.get('eq', 'EQ')

            if not isinstance(value, (list, tuple)):
                value = [value]

            filters[field_name] = {
                'AttributeValueList': list(value),
                'ComparisonOperator': operator
            }

        return filters

class Table:
    def batch_get(self, keys, consistent=False, attributes=None):
        """
        This function fetches multiple specific items in batch from a table. It takes a list of dictionaries as the keys parameter, where each dictionary consists of the key values to specify. It also accepts optional parameters such as consistent (boolean) for specifying whether to use strongly consistent read or not, and attributes (tuple) for specifying the attributes to fetch from DynamoDB. It returns a ResultSet object that handles the pagination of results.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param keys: List of dictionaries. The keys values to specify for fetching items.
        :param consistent: Bool. Whether to use strongly consistent read. Defaults to False.
        :param attributes: Tuple. The attributes to fetch from DynamoDB.
        :return: ResultSet. The ResultSet object that handles the pagination of results.
        """
        request = {
            self.name: {
                "Keys": keys,
                "ConsistentRead": consistent
            }
        }

        if attributes is not None:
            request[self.name]["AttributesToGet"] = list(attributes)

        return ResultSet(
            self.connection,
            limit=None,
            operation='batch_get_item',
            kwargs={"RequestItems": request},
            item_class=self.item_class
        )

class BatchTable:
    def __init__(self):
        self._items = []

    def put_item(self, data, overwrite=False):
        """
        This function adds an item to the BatchTable instance. It appends the input data
        to the list of items to be put in the BatchTable. It also can flush the items.

        Input-Output Arguments
        :param self: BatchTable. An instance of the BatchTable class.
        :param data: The data to be added to the BatchTable.
        :param overwrite: Bool. Whether to overwrite existing data with the same key.
                          Defaults to False.
        :return: No return values.
        """
        if data is None:
            raise ValueError("data cannot be None")

        item = {
            "data": data,
            "overwrite": overwrite
        }

        self._items.append(item)

        if hasattr(self, "flush") and callable(self.flush):
            max_batch_size = getattr(self, "max_batch_size", None)
            if max_batch_size is not None and len(self._items) >= max_batch_size:
                self.flush()

class BaseSchemaField:
    def definition(self):
        """
        This function returns the attribute definition structure that DynamoDB expects for a schema field. It includes the attribute name and attribute type.
        Input-Output Arguments
        :param self: BaseSchemaField. An instance of the BaseSchemaField class.
        :return: Dictionary. The attribute definition structure that DynamoDB expects.
        """
        return {
            'AttributeName': self.name,
            'AttributeType': self.data_type
        }

class BaseIndexField:
    def definition(self):
        """
        This function returns the attribute definition structure that DynamoDB expects for the index field. It iterates over the parts of the index field and creates a list of dictionaries, where each dictionary represents an attribute with its name and data type.
        Input-Output Arguments
        :param self: BaseIndexField. An instance of the BaseIndexField class.
        :return: List of dictionaries. The attribute definition structure that DynamoDB expects. Each dictionary contains the name and data type of an attribute.
        """
        return [
            {
                'AttributeName': part.name,
                'AttributeType': part.data_type
            }
            for part in self.parts
        ]

class BatchTable:
    def flush(self):
        """
        This function flushes the batch data by preparing the data to be inserted or deleted.
        It also handles any unprocessed items.

        Input-Output Arguments
        :param self: BatchTable. An instance of the BatchTable class.
        :return: bool. Returns True after flushing the batch data.
        """
        # Ensure batch containers exist
        if not hasattr(self, "to_insert"):
            self.to_insert = []
        if not hasattr(self, "to_delete"):
            self.to_delete = []
        if not hasattr(self, "unprocessed"):
            self.unprocessed = []

        # Prepare current batch data
        insert_batch = list(self.to_insert)
        delete_batch = list(self.to_delete)

        # Handle unprocessed items by re-queueing them
        if self.unprocessed:
            for item in self.unprocessed:
                if isinstance(item, dict) and item.get("action") == "delete":
                    delete_batch.append(item.get("data"))
                else:
                    insert_batch.append(item)
            self.unprocessed.clear()

        # Store flushed data if needed by caller/system
        self.last_flushed = {
            "insert": insert_batch,
            "delete": delete_batch,
        }

        # Clear current queues after flushing
        self.to_insert.clear()
        self.to_delete.clear()

        return True

class BaseIndexField:
    def schema(self):

        """
        This function returns the schema structure that DynamoDB expects for the given index field. It constructs the schema by iterating over the parts of the index field and appending their schemas to the key schema.
        Input-Output Arguments
        :param self: BaseIndexField. An instance of the BaseIndexField class.
        :return: Dict. The schema structure that DynamoDB expects for the index field. The structure includes the index name, key schema, and projection type.
        """
        key_schema = []
        for part in self.parts:
            key_schema.append(part.schema())

        return {
            "IndexName": self.name,
            "KeySchema": key_schema,
            "Projection": {
                "ProjectionType": "ALL"
            }
        }

class Item:
    def get_raw_keys(self):
        """
        This function returns a dictionary of the keys and their corresponding values in DynamoDB-style format. It iterates over the keys and values and encodes the values before adding them to the dictionary.
        Input-Output Arguments
        :param self: Item. An instance of the Item class.
        :return: Dict. A dictionary containing the keys and their corresponding encoded values in DynamoDB-style format.
        """
        raw_keys = {}

        for key, value in self.keys.items():
            raw_keys[key] = self._encode_value(value)

        return raw_keys

class Item:
    def prepare_full(self):
        """
        This function prepares the data of an Item object to be saved in DynamoDB.
        It encodes each field of the Item object and returns the encoded data
        as a dictionary.

        Input-Output Arguments
        :param self: Item. An instance of the Item class.
        :return: Dict. The encoded data of the Item object as a dictionary.
        """
        data = {}

        for key, value in self.__dict__.items():
            if value is None:
                continue

            if hasattr(value, "prepare_full") and callable(value.prepare_full):
                data[key] = value.prepare_full()
            elif isinstance(value, list):
                encoded_list = []
                for item in value:
                    if hasattr(item, "prepare_full") and callable(item.prepare_full):
                        encoded_list.append(item.prepare_full())
                    else:
                        encoded_list.append(item)
                data[key] = encoded_list
            elif isinstance(value, dict):
                encoded_dict = {}
                for k, v in value.items():
                    if hasattr(v, "prepare_full") and callable(v.prepare_full):
                        encoded_dict[k] = v.prepare_full()
                    else:
                        encoded_dict[k] = v
                data[key] = encoded_dict
            else:
                data[key] = value

        return data

class Item:
    def build_expects(self, fields=None):

        """
        This function builds up a dictionary of expectations to be passed to DynamoDB when saving an item. It iterates through the fields provided (or all fields if none are specified), checks their state (new, unchanged, modified, or deleted), and adds the corresponding expectation to the dictionary. It also encodes the value if necessary.
        Input-Output Arguments
        :param self: Item. An instance of the Item class.
        :param fields: List of strings. The fields to include in the expectations. If None, all fields are included. Defaults to None.
        :return: Dictionary. A dictionary of expectations to be passed to DynamoDB.
        """
        expects = {}

        if fields is None:
            fields = self.keys()

        for field in fields:
            if field not in self:
                continue

            value = self[field]

            # Determine the field state using common item-tracking conventions.
            # New/deleted fields generally should not produce equality expectations.
            if hasattr(self, "_deleted") and field in self._deleted:
                expects[field] = {"Exists": False}
            elif hasattr(self, "_original") and field in self._original:
                original_value = self._original[field]
                if original_value is None:
                    expects[field] = {"Exists": False}
                else:
                    if hasattr(self, "encode"):
                        original_value = self.encode(original_value)
                    expects[field] = {"Value": original_value}
            else:
                # If the field is new, expect it not to exist yet.
                expects[field] = {"Exists": False}

        return expects

class Item:
    def prepare_partial(self):

        """
        This function prepares the changed or deleted fields of an Item instance to be encoded and handed off to DynamoDB for an update operation. It determines the alterations made to the fields, encodes the values, and creates a data structure with the necessary actions and values for each field.
        Input-Output Arguments
        :param self: Item. An instance of the Item class.
        :return: Tuple. A tuple containing the final data structure with actions and values for each field, and a set of fields that were altered.
        """
        updates = {}
        altered_fields = set()

        # Get changed/deleted fields from common tracking attributes if present.
        changed_fields = getattr(self, "_changed_fields", set()) or set()
        deleted_fields = getattr(self, "_deleted_fields", set()) or set()

        # Support dict/list/tuple inputs as well.
        if isinstance(changed_fields, dict):
            changed_fields = set(changed_fields.keys())
        else:
            changed_fields = set(changed_fields)

        if isinstance(deleted_fields, dict):
            deleted_fields = set(deleted_fields.keys())
        else:
            deleted_fields = set(deleted_fields)

        # Handle changed fields.
        for field in changed_fields:
            value = getattr(self, field, None)

            # Use custom encoder if available, otherwise pass through.
            if hasattr(self, "encode") and callable(getattr(self, "encode")):
                encoded_value = self.encode(value)
            elif hasattr(self, "_encode") and callable(getattr(self, "_encode")):
                encoded_value = self._encode(value)
            else:
                encoded_value = value

            updates[field] = {
                "Action": "PUT",
                "Value": encoded_value
            }
            altered_fields.add(field)

        # Handle deleted fields.
        for field in deleted_fields:
            updates[field] = {
                "Action": "DELETE"
            }
            altered_fields.add(field)

        return updates, altered_fields

class Item:
    def partial_save(self):
        """
        This function saves only the changed data of an Item instance to DynamoDB. It updates only the fields that have been modified, rather than pushing the entire item. This helps prevent accidental overwrites and reduces the amount of data transferred over the network.

        Input-Output Arguments
        :param self: Item. An instance of the Item class.
        :return: bool. Returns True if the save operation is successful, False if no save was performed or if the write failed.
        """
        try:
            # Ensure the object can report changed fields
            if not hasattr(self, "_changed_fields"):
                return False

            changed_fields = self._changed_fields
            if not changed_fields:
                return False

            # Ensure required DynamoDB metadata exists
            if not hasattr(self, "_table") or self._table is None:
                return False
            if not hasattr(self, "_primary_key"):
                return False

            key = {}
            primary_key = self._primary_key

            if isinstance(primary_key, (list, tuple)):
                for k in primary_key:
                    if not hasattr(self, k):
                        return False
                    key[k] = getattr(self, k)
            else:
                if not hasattr(self, primary_key):
                    return False
                key[primary_key] = getattr(self, primary_key)

            update_expressions = []
            expression_attribute_names = {}
            expression_attribute_values = {}

            for field in changed_fields:
                if field in key:
                    continue

                attr_name_placeholder = f"#_{field}"
                attr_value_placeholder = f":_{field}"

                expression_attribute_names[attr_name_placeholder] = field
                expression_attribute_values[attr_value_placeholder] = getattr(self, field)
                update_expressions.append(
                    f"{attr_name_placeholder} = {attr_value_placeholder}"
                )

            if not update_expressions:
                return False

            response = self._table.update_item(
                Key=key,
                UpdateExpression="SET " + ", ".join(update_expressions),
                ExpressionAttributeNames=expression_attribute_names,
                ExpressionAttributeValues=expression_attribute_values,
                ReturnValues="UPDATED_NEW",
            )

            # Clear changed fields after successful update
            if response.get("ResponseMetadata", {}).get("HTTPStatusCode") == 200:
                self._changed_fields = set()
                return True

            return False

        except Exception:
            return False

