class ACLAuthorizationPolicy:
    def principals_allowed_by_permission(self, context, permission):
        """
        This function returns the set of principals that are explicitly granted
        the specified permission according to the ACL (Access Control List)
        attached to the context and any inherited ACLs based on the lineage.

        Input-Output Arguments
        :param self: ACLAuthorizationPolicy. An instance of the ACLAuthorizationPolicy class.
        :param context: The context object to which the ACL is attached.
        :param permission: The name of the permission.
        :return: Set of principals. The set of principals that are explicitly granted the specified permission.
        """
        allowed = set()
        denied = set()

        # Walk up the lineage, checking ACLs from the current context outward.
        for location in lineage(context):
            acl = getattr(location, '__acl__', None)
            if acl is None:
                continue

            # Support callable ACLs as well as static ACLs.
            if callable(acl):
                acl = acl()

            for ace in acl:
                if len(ace) != 3:
                    continue

                action, principal, permissions = ace

                # Normalize permissions to an iterable of permission names.
                if permissions == ALL_PERMISSIONS:
                    matches = True
                else:
                    if not isinstance(permissions, (list, tuple, set, frozenset)):
                        permissions = [permissions]
                    matches = permission in permissions

                if not matches:
                    continue

                if action == Allow:
                    if principal not in denied:
                        allowed.add(principal)
                elif action == Deny:
                    denied.add(principal)
                    allowed.discard(principal)

        return allowed

