class CookieCSRFStoragePolicy:
    def new_csrf_token(self, request):
        """
        This function generates a new CSRF token and sets it into the request cookies. It also adds a response callback to set the CSRF token into the response cookies.
        Input-Output Arguments
        :param self: CookieCSRFStoragePolicy. An instance of the CookieCSRFStoragePolicy class.
        :param request: The request object.
        :return: String. The generated CSRF token.
        """
        import os
        import binascii

        token = binascii.hexlify(os.urandom(20)).decode("ascii")

        if not hasattr(request, "cookies") or request.cookies is None:
            request.cookies = {}
        request.cookies["csrf_token"] = token

        def set_csrf_cookie(request, response):
            if hasattr(response, "set_cookie"):
                response.set_cookie("csrf_token", token)

        if hasattr(request, "add_response_callback"):
            request.add_response_callback(set_csrf_cookie)

        return token

