        )

class Introspector:
    def relate(self, *pairs):
        """
        This function establishes relationships among introspectables based on the given
        category name and discriminator pairs. It creates relationships between each pair
        of introspectables by adding a reference from one introspectable to another.

        Input-Output Arguments
        :param self: Introspector. An instance of the Introspector class.
        :param pairs: Variable number of arguments. Each argument is a pair of
                      category name and discriminator to identify one introspectable.
        :return: No return values.
        """
        if len(pairs) < 2:
            return

        introspectables = []
        for pair in pairs:
            if not isinstance(pair, (tuple, list)) or len(pair) != 2:
                raise ValueError(
                    "Each argument to relate() must be a (category_name, discriminator) pair."
                )

            category_name, discriminator = pair

            if not hasattr(self, "get_introspectable"):
                raise AttributeError(
                    "Introspector must define a 'get_introspectable' method."
                )

            introspectable = self.get_introspectable(category_name, discriminator)
            if introspectable is None:
                raise ValueError(
                    f"Introspectable not found for category '{category_name}' "
                    f"and discriminator '{discriminator}'."
                )

            introspectables.append(introspectable)

        for i, source in enumerate(introspectables):
            for j, target in enumerate(introspectables):
                if i == j:
                    continue

                if hasattr(source, "add_related"):
                    source.add_related(target)
                elif hasattr(source, "related"):
                    if source.related is None:
                        source.related = []
                    if target not in source.related:
                        source.related.append(target)
                else:
                    source.related = [target]

class PRoutesCommand:
    def _get_mapper(self, registry):
        """
        This function returns the routes mapper object associated with the given registry.
        Input-Output Arguments
        :param self: PRoutesCommand. An instance of the PRoutesCommand class.
        :param registry: The registry object.
        :return: The routes mapper object associated with the given registry.
        """
        if registry is None:
            return None

        if hasattr(registry, "queryUtility"):
            mapper = registry.queryUtility(IRoutesMapper)
            if mapper is not None:
                return mapper

        if hasattr(registry, "getUtility"):
            try:
                return registry.getUtility(IRoutesMapper)
            except Exception:
                pass

        if hasattr(registry, "routes_mapper"):
            return registry.routes_mapper

        if hasattr(registry, "mapper"):
            return registry.mapper

        return None

class PackageOverrides:
    def filtered_sources(self, resource_name):
        """
        This function iterates over the overrides in the PackageOverrides instance
        and yields the filtered sources based on the given resource name. It will
        yield all possible resources based on different overrides.

        Input-Output Arguments
        :param self: PackageOverrides. An instance of the PackageOverrides class.
        :param resource_name: str. The name of the resource to filter the sources.
        :return: Generator. Yields the filtered sources based on the given resource name.
        """
        for override in self:
            if isinstance(override, dict):
                if resource_name in override:
                    yield override[resource_name]
            else:
                source = getattr(override, resource_name, None)
                if source is not None:
                    yield source

class InstancePropertyMixin:
    def set_property(self, callable, name=None, reify=False):
        """
        This function adds a callable or a property descriptor to an instance.
        Input-Output Arguments
        :param self: InstancePropertyMixin. An instance of the InstancePropertyMixin class.
        :param callable: Callable or property descriptor. The callable or property descriptor to be added to the instance.
        :param name: String. The name of the property. If None, the name will be computed from the name of the callable. Defaults to None.
        :param reify: Bool. Whether the property should be reified. If True, the value of the property is cached and computed only once. Defaults to False.
        :return: No return values.
        """
        if name is None:
            if isinstance(callable, property):
                if callable.fget is None:
                    raise ValueError("Cannot determine property name from property without getter")
                name = callable.fget.__name__
            else:
                name = callable.__name__

        if isinstance(callable, property):
            prop = callable
        else:
            func = callable

            if reify:
                cache_name = f"__reified_{name}"

                def getter(instance, _func=func, _cache_name=cache_name):
                    if not hasattr(instance, _cache_name):
                        setattr(instance, _cache_name, _func())
                    return getattr(instance, _cache_name)
            else:
                def getter(instance, _func=func):
                    return _func()

            prop = property(getter)

        setattr(self.__class__, name, prop)

class MultiView:
    def __call_permissive__(self, context, request):
        """
        This function is a method of the MultiView class. It is used to call the
        matched view with the given context and request. If the matched view is
        call permissive, this custom method is called instead.

        Input-Output Arguments
        :param self: MultiView. An instance of the MultiView class.
        :param context: The context object to be passed to the view.
        :param request: The request object to be passed to the view.
        :return: The result of calling the matched view with the given context and request.
        """
        view = self.match(context, request)

        if view is None:
            raise LookupError("No matching view found")

        permissive = getattr(view, "__call_permissive__", None)
        if callable(permissive):
            return permissive(context, request)

        if callable(view):
            return view(context, request)

        raise TypeError("Matched view is not callable")

class MultiView:
    def __init__(self):
        self.views = []
        self.accepts = []
        self.accept_views = {}

    def add(self, view, order, phash=None, accept=None, accept_order=None):
        """
        This function adds a view to the MultiView instance based on the given conditions. If a view with the same phash value already exists, it updates the existing view. If accept is not specified, it adds the view to the main views list and sorts it based on the order. If accept is specified, it updates the existing view or adds the view to the subset of views for that accept value and sorts it based on the order. It also updates the accept values and sorts them based on the custom order.
        Input-Output Arguments
        :param self: MultiView. An instance of the MultiView class.
        :param view: The view to be added.
        :param order: The order of the view.
        :param phash: The phash value of the view. Defaults to None.
        :param accept: The accept value for the view. Defaults to None.
        :param accept_order: The order of the accept values. Defaults to None.
        :return: No return values.
        """

        item = {
            "view": view,
            "order": order,
            "phash": phash,
        }

        def upsert(target_list):
            if phash is not None:
                for i, existing in enumerate(target_list):
                    if existing.get("phash") == phash:
                        target_list[i] = item
                        break
                else:
                    target_list.append(item)
            else:
                target_list.append(item)

            target_list.sort(key=lambda x: x["order"])

        if accept is None:
            upsert(self.views)
        else:
            if accept not in self.accept_views:
                self.accept_views[accept] = []

            upsert(self.accept_views[accept])

            if accept not in [a["accept"] for a in self.accepts]:
                self.accepts.append({
                    "accept": accept,
                    "order": accept_order if accept_order is not None else 0
                })
            else:
                for a in self.accepts:
                    if a["accept"] == accept and accept_order is not None:
                        a["order"] = accept_order
                        break

            self.accepts.sort(key=lambda x: x["order"])

class Configurator:
    def absolute_asset_spec(self, relative_spec):
        """
        This function takes a potentially relative asset specification string and resolves it into an absolute asset specification string. It uses the package of the Configurator instance as the reference package for generating the absolute asset specification. If the provided relative_spec argument is already absolute or not a string, it is simply returned.
        Input-Output Arguments
        :param self: Configurator. An instance of the Configurator class.
        :param relative_spec: String. The potentially relative asset specification string to be resolved.
        :return: String. The resolved absolute asset specification string.
        """
        if not isinstance(relative_spec, str):
            return relative_spec

        if ':' in relative_spec:
            return relative_spec

        package = getattr(self, 'package', None)
        if not package:
            return relative_spec

        if relative_spec.startswith('.'):
            relative_spec = relative_spec[1:]

        return f"{package}:{relative_spec}"

class Configurator:
    def __getattr__(self, name):
        # allow directive extension names to work

        """
        This function is a method of the Configurator class that allows accessing attributes dynamically and allow directive extension names to work. It checks if the attribute name exists in the registry's directives. If it does, it retrieves the corresponding value and performs additional actions if necessary. Finally, it returns a bound method of the retrieved value.
        Input-Output Arguments
        :param self: Configurator. An instance of the Configurator class.
        :param name: String. The name of the attribute to be accessed.
        :return: Bound method. The bound method of the retrieved attribute value.
        """
        directives = getattr(self.registry, 'directives', None)
        if directives is None or name not in directives:
            raise AttributeError(f"{self.__class__.__name__!s} object has no attribute {name!r}")

        value = directives[name]

        if hasattr(value, '__get__'):
            return value.__get__(self, self.__class__)

        if callable(value):
            return value.__class__.__get__(value, self, self.__class__) if hasattr(value.__class__, '__get__') else value

        return value

