class RouteFactory:
    def get_permission_object_id(self, request, object_id=None):
        """
        This function returns the permission object id for the current request. It determines the object URI based on the request path and the specified object_id. If the request is on a plural endpoint and object_id is provided, it finds the object URI by inspecting the "plural" service and its sibling "object" service.

        Input-Output Arguments
        :param self: RouteFactory. An instance of the RouteFactory class.
        :param request: The current request object.
        :param object_id: The object id to be used in the object URI. Defaults to None.
        :return: The permission object id for the current request.
        """
        path = getattr(request, "path", "") or getattr(request, "path_info", "")

        if object_id is None:
            return path

        service = getattr(request, "service", None)

        # If we're on a plural endpoint, try to resolve the corresponding
        # object endpoint and substitute the provided object_id.
        if service is not None and getattr(service, "type", None) == "plural":
            parent = getattr(service, "parent", None)
            siblings = getattr(parent, "services", []) if parent is not None else []

            object_service = None
            for sibling in siblings:
                if getattr(sibling, "type", None) == "object":
                    object_service = sibling
                    break

            if object_service is not None:
                object_path = getattr(object_service, "path", None)
                if object_path:
                    try:
                        return object_path.format(object_id=object_id)
                    except (KeyError, IndexError, ValueError):
                        pass

        # Fallback: append object_id to the current path if not already present.
        return "{}/{}".format(path.rstrip("/"), object_id)

class RouteFactory:
    def fetch_shared_objects(self, perm, principals, get_bound_permissions):
        """
        This function fetches objects that are readable or writable for the current principals
        based on the given permissions. It sets shared ids to the context with the fetched
        object IDs. If no object is shared, it returns None.

        Input-Output Arguments
        :param self: RouteFactory. An instance of the RouteFactory class.
        :param perm: The permission to check for the objects.
        :param principals: The current principals.
        :param get_bound_permissions: Bool. Whether to get bound permissions for the object ID match.
        :return: List of object IDs that are readable or writable for the current principals.
        """
        shared_ids = []

        # Expect an ACL-like iterable on the instance, defaulting to empty.
        acl = getattr(self, "acl", []) or []

        for ace in acl:
            if not isinstance(ace, (list, tuple)) or len(ace) < 3:
                continue

            action, principal, permissions = ace[:3]

            # Match principal
            if principal not in principals:
                continue

            # Normalize permissions to an iterable
            if isinstance(permissions, str):
                permissions = [permissions]

            # Check permission match
            if perm not in permissions:
                continue

            # If bound permissions are requested, try to extract object ids
            if get_bound_permissions:
                object_ids = None

                if len(ace) > 3:
                    object_ids = ace[3]
                elif isinstance(permissions, dict):
                    object_ids = permissions.get("object_ids")

                if object_ids is None:
                    continue

                if isinstance(object_ids, (list, tuple, set)):
                    shared_ids.extend(object_ids)
                else:
                    shared_ids.append(object_ids)
            else:
                # No bound object ids requested; record the matching permission/principal
                if len(ace) > 3:
                    object_ids = ace[3]
                    if isinstance(object_ids, (list, tuple, set)):
                        shared_ids.extend(object_ids)
                    else:
                        shared_ids.append(object_ids)

        # Deduplicate while preserving order
        seen = set()
        shared_ids = [obj_id for obj_id in shared_ids if not (obj_id in seen or seen.add(obj_id))]

        # Store on context if available
        context = getattr(self, "context", None)
        if context is not None:
            setattr(context, "shared_ids", shared_ids if shared_ids else None)

        return shared_ids if shared_ids else None

for key, value in changes.items():
    if isinstance(value, dict):
        if key not in root or not isinstance(root.get(key), dict):
            root[key] = {}
        recursive_update_dict(root[key], value, ignores)
    elif value in ignores:
        root.pop(key, None)
    else:
        root[key] = value

if not isinstance(d, dict):
    return default

# Direct key match takes precedence
if path in d:
    return d[path]

if not path:
    return default

parts = path.split(".")

# Build all possible root keys:
# e.g. "a.b.c" -> ["a", "a.b", "a.b.c"]
possible_roots = [".".join(parts[:i]) for i in range(1, len(parts) + 1)]

actual_root = None
for root in reversed(possible_roots):
    if root in d:
        actual_root = root
        break

if actual_root is None:
    return default

value = d.get(actual_root)

# If the full path matched, it would already have returned above.
# So if the root value isn't a dict, we can't go deeper.
if not isinstance(value, dict):
    return default

subpath = path[len(actual_root) + 1:]
if not subpath:
    return value

return find_nested_value(value, subpath, default)

class Resource:
    def timestamp(self):
        """
        This function returns the current timestamp of a resource. It first tries to get
        the timestamp from the model associated with the resource. If that fails, it raises
        a read-only error, stores the error information in `http_error`, and raises a
        JSON-formatted response matching the error HTTP API.

        Input-Output Arguments
        :param self: Resource. An instance of the Resource class.
        :return: int. The current timestamp of the resource.
        """
        try:
            return self.model.timestamp()
        except Exception as exc:
            error_info = {
                "error": "read_only",
                "message": str(exc)
            }
            self.http_error = error_info
            raise Exception(error_info)

class ResourceReponses:
    def get_and_bind(self, endpoint_type, method, **kwargs):
        """
        This function wraps resource colander response schemas for a specific endpoint and method.
        It creates a dictionary of status codes mapping cloned and binded responses based on the
        default schemas, endpoint-specific schemas, and method-specific schemas. The response include
        type responses, method args and endpoint args, finded from this instance.

        Input-Output Arguments
        :param self: ResourceReponses. An instance of the ResourceReponses class.
        :param endpoint_type: String. The type of endpoint.
        :param method: String. The HTTP method.
        :param **kwargs: Additional keyword arguments.
        :return: Dict. A dictionary of status codes mapping cloned and binded responses.
        """
        responses = {}

        # Collect response definitions from default, endpoint, and method scopes
        default_responses = getattr(self, "responses", {}) or {}
        endpoint_responses = getattr(self, endpoint_type, {}) or {}
        method_responses = {}

        if isinstance(endpoint_responses, dict):
            method_responses = endpoint_responses.get(method, {}) or {}

        # Merge in order: default -> endpoint -> method
        merged = {}
        merged.update(default_responses)
        if isinstance(endpoint_responses, dict):
            for status, schema in endpoint_responses.items():
                if status != method:
                    merged[status] = schema
        merged.update(method_responses)

        # Gather bind arguments from instance attributes if present
        bind_kwargs = {}
        endpoint_args = getattr(self, "{}_args".format(endpoint_type), {}) or {}
        method_args = getattr(self, "{}_{}_args".format(endpoint_type, method), {}) or {}

        if isinstance(endpoint_args, dict):
            bind_kwargs.update(endpoint_args)
        if isinstance(method_args, dict):
            bind_kwargs.update(method_args)
        bind_kwargs.update(kwargs)

        # Clone and bind each schema/response object when possible
        for status, response in merged.items():
            obj = response

            if hasattr(obj, "clone"):
                obj = obj.clone()

            if hasattr(obj, "bind"):
                obj = obj.bind(**bind_kwargs)

            responses[status] = obj

        return responses

