def http_error(
    httpexception, errno=None, code=None, error=None, message=None, info=None, details=None
):
    """
    This function takes in various parameters related to an HTTP exception and returns a JSON-formatted response that matches the error HTTP API. It constructs a response object with the provided parameters and sets the appropriate attributes and content type.
    Input-Output Arguments
    :param httpexception: Instance of :mod:`~pyramid:pyramid.httpexceptions`. The HTTP exception that occurred.
    :param errno: Integer. A stable application-level error number. Defaults to ERRORS.UNDEFINED if not specified.
    :param code: Integer. The HTTP status code that matches the error. Defaults to the code of the httpexception if not specified.
    :param error: String. A description of the error type. Defaults to the title of the httpexception if not specified.
    :param message: String. Context information about the error. Defaults to None.
    :param info: String. Additional information about the error, such as a URL for troubleshooting. Defaults to None.
    :param details: Any additional structured details about the error, such as conflicting objects. Defaults to colander.drop.
    :return: pyramid.httpexceptions.HTTPException. The formatted response object.
    """
    if errno is None:
        try:
            errno = ERRORS.UNDEFINED
        except Exception:
            errno = 0

    if code is None:
        code = getattr(httpexception, "code", None)

    if error is None:
        error = getattr(httpexception, "title", None) or getattr(
            httpexception, "explanation", None
        ) or httpexception.__class__.__name__

    payload = {
        "code": code,
        "error": error,
        "errno": errno,
    }

    if message is not None:
        payload["message"] = message

    if info is not None:
        payload["info"] = info

    drop_sentinel = _DROP
    if details is not None and details is not drop_sentinel:
        payload["details"] = details

    httpexception.content_type = "application/json"
    httpexception.charset = "utf-8"
    httpexception.text = json.dumps(payload)

    return httpexception

class Resource:
    def get(self):
        """
        This function is the "GET" endpoint for retrieving an object. It performs several checks and operations before returning the object. It checks if the object is found, if it has been modified, and if any partial fields need to be extracted. It then adds a timestamp header and a cache header to the response and returns the object. If have partial fields, it extracts them from the object as the result object. Depending on the situation, different error labels may be raised.
        Input-Output Arguments
        :param self: Resource. An instance of the Resource class.
        :return: The retrieved object.
        """
        obj = self.get_object()

        if obj is None:
            raise Exception("not_found")

        if hasattr(self, "check_modified") and callable(self.check_modified):
            modified = self.check_modified(obj)
            if modified is False:
                raise Exception("not_modified")

        result = obj

        partial_fields = None
        if hasattr(self, "get_partial_fields") and callable(self.get_partial_fields):
            partial_fields = self.get_partial_fields()
        elif hasattr(self, "partial_fields"):
            partial_fields = self.partial_fields

        if partial_fields:
            result = {}
            for field in partial_fields:
                if isinstance(obj, dict) and field in obj:
                    result[field] = obj[field]
                elif hasattr(obj, field):
                    result[field] = getattr(obj, field)

        if hasattr(self, "add_header") and callable(self.add_header):
            if hasattr(self, "get_timestamp") and callable(self.get_timestamp):
                self.add_header("Timestamp", self.get_timestamp())
            else:
                import time
                self.add_header("Timestamp", time.time())

            if hasattr(self, "get_cache_header") and callable(self.get_cache_header):
                self.add_header("Cache-Control", self.get_cache_header())
            else:
                self.add_header("Cache-Control", "no-cache")

        return result

class Resource:
    def delete(self):
        """
        This function deletes an object by sending a DELETE request to the object's endpoint.
        It performs some checks (like id does not match the format, can not get object,
        object is modified) and raises exceptions if necessary. Then retrieve the last
        modified information from a querystring if present, if the modified less or equal
        than current object. Ignore it. After deleting the object, it returns the deleted object.

        Input-Output Arguments
        :param self: Resource. An instance of the Resource class.
        :return: The deleted object.
        """
        import re
        from urllib.parse import urlparse, parse_qs

        # Validate id format
        if not hasattr(self, "id") or self.id is None:
            raise ValueError("Resource id is missing.")

        if not re.match(r"^[A-Za-z0-9\-_]+$", str(self.id)):
            raise ValueError("Resource id does not match the expected format.")

        # Ensure object can be retrieved
        if hasattr(self, "get") and callable(self.get):
            current_obj = self.get()
            if current_obj is None:
                raise LookupError("Cannot get object for deletion.")
        else:
            current_obj = self

        # Check whether object has been modified using querystring last_modified if present
        request_url = getattr(self, "endpoint", "") or getattr(self, "url", "")
        if request_url:
            parsed = urlparse(request_url)
            query_params = parse_qs(parsed.query)
            qs_modified = query_params.get("last_modified", [None])[0]

            if qs_modified is not None and hasattr(self, "last_modified"):
                try:
                    if qs_modified <= self.last_modified:
                        qs_modified = None
                    else:
                        raise RuntimeError("Object is modified.")
                except TypeError:
                    raise RuntimeError("Unable to compare modification timestamps.")

        # Perform DELETE request
        if not hasattr(self, "_delete") or not callable(self._delete):
            raise NotImplementedError("DELETE request method is not implemented.")

        response = self._delete()

        # Basic response validation
        status_code = getattr(response, "status_code", None)
        if status_code is not None and status_code not in (200, 202, 204):
            raise RuntimeError(f"Delete failed with status code {status_code}.")

        return current_obj

