from datetime import datetime, date

def infer_type(values):
    non_null_values = [v for v in values if v is not None]

    if not non_null_values:
        return "NoneType"

    # bool must be checked before int because bool is a subclass of int
    if all(isinstance(v, bool) for v in non_null_values):
        return "bool"

    if all(isinstance(v, int) and not isinstance(v, bool) for v in non_null_values):
        return "int"

    if all(isinstance(v, (int, float)) and not isinstance(v, bool) for v in non_null_values):
        return "float"

    if all(isinstance(v, str) for v in non_null_values):
        # Try date/datetime detection for string values
        datetime_formats = (
            "%Y-%m-%d",
            "%Y-%m-%d %H:%M:%S",
            "%Y-%m-%dT%H:%M:%S",
            "%m/%d/%Y",
            "%d/%m/%Y",
        )
        for fmt in datetime_formats:
            try:
                for v in non_null_values:
                    datetime.strptime(v, fmt)
                return "datetime"
            except ValueError:
                continue
        return "str"

    if all(isinstance(v, date) for v in non_null_values):
        return "date"

    if all(isinstance(v, datetime) for v in non_null_values):
        return "datetime"

    if all(isinstance(v, list) for v in non_null_values):
        return "list"

    if all(isinstance(v, dict) for v in non_null_values):
        return "dict"

    return "mixed"

