        :param _namespace_metadata: Optional MetaData. The metadata associated with the table. Defaults to None.
        :return: DropTableOp. The created DropTableOp instance.
        """
        return cls(
            table_name=table.name,
            schema=table.schema,
            table_kw={
                "comment": table.comment,
                "info": dict(table.info) if table.info else {},
                "prefixes": list(table._prefixes) if getattr(table, "_prefixes", None) else [],
                **(
                    {"_namespace_metadata": _namespace_metadata}
                    if _namespace_metadata is not None
                    else {}
                ),
            },
            _reverse=CreateTableOp.from_table(
                table, _namespace_metadata=_namespace_metadata
            ),
        )

class DropColumnOp:
    def reverse(self) -> AddColumnOp:
        """
