class Record:
    def dump(self) -> bytes:
        """
        This function is used to convert the Record instance into a byte string representation.
        It first serializes the key and calculates the length of the key. Then, it determines
        whether there is an overflow page or not and sets the value accordingly. After that,
        it calculates the length of the value. Finally, it combines all the necessary
        information into a byte string and returns it.

        Input-Output Arguments
        :param self: Record. An instance of the Record class.
        :return: bytes.
        """
        key = self.key if isinstance(self.key, bytes) else str(self.key).encode()
        key_len = len(key)

        if getattr(self, "overflow_page", None) is not None:
            value = (
                self.overflow_page
                if isinstance(self.overflow_page, bytes)
                else str(self.overflow_page).encode()
            )
        else:
            value = self.value if isinstance(self.value, bytes) else str(self.value).encode()

        value_len = len(value)

        return (
            key_len.to_bytes(4, byteorder="big") +
            key +
            value_len.to_bytes(4, byteorder="big") +
            value
        )

class Node:
    @classmethod
    def from_page_data(cls, tree_conf: TreeConf, data: bytes,
                       page: int = None) -> 'Node':
        """
        This function creates a Node instance based on the given tree configuration and data.
        It first extracts the node type from the data and then creates the corresponding
        Node instance based on the node type.

        Input-Output Arguments
        :param cls: Node. The class of the Node instance to be created.
        :param tree_conf: TreeConf. The tree configuration used to create the Node instance.
        :param data: Bytes. The data used to create the Node instance.
        :param page: Int. The page number associated with the Node instance. Defaults to None.
        :return: Node. The created Node instance based on the node type.
        """
        node_type = data[0]

        if node_type == cls.LEAF:
            return LeafNode.from_page_data(tree_conf, data, page)
        elif node_type == cls.INTERNAL:
            return InternalNode.from_page_data(tree_conf, data, page)
        else:
            raise ValueError(f"Unknown node type: {node_type}")

