class ConfigSchema:
    def deserialize(self, values):
        """
        This function validates the given `values` using the config schema. It iterates through each key-value pair in the `values` dictionary and tries to deserialize the value using the corresponding schema in the config. If the key is not found in the schema, it adds an error message to the `errors` dictionary. If the deserialization fails, it adds the error message to the `errors` dictionary and sets the value to None in the `result` dictionary. After iterating through all the keys in the schema, it checks for any deprecated keys and removes them from the `result` dictionary. Finally, it returns a tuple containing the cleaned values in the `result` dictionary and the errors in the `errors` dictionary.
        Input-Output Arguments
        :param self: ConfigSchema. An instance of the ConfigSchema class.
        :param values: dict. A dictionary containing the values to be validated against the config schema.
        :return: tuple. A tuple containing the cleaned values in the `result` dictionary and the errors in the `errors` dictionary.
        """
        result = {}
        errors = {}

        values = values or {}

        # Deserialize provided values
        for key, value in values.items():
            if key not in self.schema:
                errors[key] = "Unknown configuration key."
                continue

            field = self.schema[key]
            try:
                result[key] = field.deserialize(value)
            except Exception as exc:
                result[key] = None
                errors[key] = str(exc)

        # Fill in missing schema keys if defaults exist / validate required fields
        for key, field in self.schema.items():
            if key not in result:
                if hasattr(field, "default"):
                    result[key] = field.default
                elif getattr(field, "required", False):
                    errors[key] = "Missing required configuration key."
                    result[key] = None

        # Remove deprecated keys from result if schema marks them as deprecated
        for key, field in self.schema.items():
            if getattr(field, "deprecated", False) and key in result:
                result.pop(key, None)

        return result, errors

class Float:
    def deserialize(self, value):
        """
        Deserialize a value into a float. It decodes the input value, validates if it is required, and converts it into a float. It then validates if the float value meets the minimum and maximum constraints.
        Input-Output Arguments
        :param self: Float. An instance of the Float class.
        :param value: The value to be deserialized into a float.
        :return: The deserialized float value.
        """
        if hasattr(self, "_deserialize"):
            value = self._deserialize(value)

        if value is None:
            if getattr(self, "required", False):
                raise ValueError("Value is required")
            return None

        try:
            value = float(value)
        except (TypeError, ValueError):
            raise ValueError("Invalid float value")

        minimum = getattr(self, "minimum", None)
        maximum = getattr(self, "maximum", None)

        if minimum is not None and value < minimum:
            raise ValueError(f"Float value {value} is less than minimum {minimum}")

        if maximum is not None and value > maximum:
            raise ValueError(f"Float value {value} is greater than maximum {maximum}")

        return value

class Pair:
    def deserialize(self, value):

        """
        Deserialize a value and return a pair of deserialized values. It first decodes the input value and removes any leading or trailing whitespace. Then, it validates the raw value based on whether it is required or not. If the raw value is empty, it returns None. If the separator is present in the raw value, it splits the value into two parts. If the optional pair flag is set, it assigns the same value to both parts. Otherwise, it raises a ValueError indicating that the config value must include the separator. Finally, it encodes and deserializes each part of the pair using the corresponding subtypes.
        Input-Output Arguments
        :param self: Pair. An instance of the Pair class.
        :param value: The value to be deserialized.
        :return: Tuple. A pair of deserialized values.
        """
        raw_value = self.decode(value).strip()
        self.validate(raw_value)

        if not raw_value:
            return None

        if self.separator in raw_value:
            left, right = raw_value.split(self.separator, 1)
            left = left.strip()
            right = right.strip()
        elif self.optional_pair:
            left = right = raw_value
        else:
            raise ValueError(
                "Config value must include separator {!r}: {!r}".format(
                    self.separator, raw_value
                )
            )

        return (
            self.subtypes[0].deserialize(self.encode(left)),
            self.subtypes[1].deserialize(self.encode(right)),
        )

class Integer:
    def deserialize(self, value):
        """
        Deserialize a value into an Integer object. It decodes the input value,
        validates it based on the specified constraints, and returns the
        deserialized integer value.

        Input-Output Arguments
        :param self: Integer. An instance of the Integer class.
        :param value: The value to be deserialized.
        :return: int. The deserialized integer value.
        """
        if value is None:
            raise ValueError("Value cannot be None")

        try:
            if isinstance(value, bool):
                raise ValueError("Boolean values are not valid integers")

            if isinstance(value, int):
                result = value
            elif isinstance(value, float):
                if not value.is_integer():
                    raise ValueError(f"Cannot deserialize non-integer float: {value}")
                result = int(value)
            elif isinstance(value, str):
                value = value.strip()
                if value == "":
                    raise ValueError("Cannot deserialize empty string")
                result = int(value)
            else:
                result = int(value)

            if hasattr(self, "minimum") and self.minimum is not None and result < self.minimum:
                raise ValueError(f"Value {result} is less than minimum allowed {self.minimum}")

            if hasattr(self, "maximum") and self.maximum is not None and result > self.maximum:
                raise ValueError(f"Value {result} is greater than maximum allowed {self.maximum}")

            return result

        except (TypeError, ValueError) as e:
            raise ValueError(f"Invalid integer value: {value}") from e

class Boolean:
    def deserialize(self, value):

        """
        Deserialize a boolean value from a serialized string representation. It decodes the input value, validates if it is required, and then checks if it matches any of the true or false values. If it doesn't match any, it raises a ValueError.
        Input-Output Arguments
        :param self: Boolean. An instance of the Boolean class.
        :param value: String. The serialized string representation of the boolean value.
        :return: Bool. The deserialized boolean value.
        """
        if isinstance(value, bytes):
            value = value.decode("utf-8")

        if value is None:
            if getattr(self, "required", False):
                raise ValueError("Boolean value is required")
            return None

        true_values = getattr(self, "true_values", {"true", "1", "yes", "on", True})
        false_values = getattr(self, "false_values", {"false", "0", "no", "off", False})

        if isinstance(value, str):
            normalized = value.strip().lower()
        else:
            normalized = value

        normalized_true_values = {
            v.strip().lower() if isinstance(v, str) else v for v in true_values
        }
        normalized_false_values = {
            v.strip().lower() if isinstance(v, str) else v for v in false_values
        }

        if normalized in normalized_true_values:
            return True
        if normalized in normalized_false_values:
            return False

        raise ValueError(f"Invalid boolean value: {value}")

class LogColor:
    def deserialize(self, value):
        """
        Deserialize a value by decoding it and validating if it is a valid choice from a list of colors. It returns the lowercase value.
        Input-Output Arguments
        :param self: LogColor. An instance of the LogColor class.
        :param value: The value to be deserialized.
        :return: The deserialized value.
        """
        if value is None:
            return None

        if isinstance(value, bytes):
            value = value.decode("utf-8")

        value = str(value).lower()

        valid_colors = {"black", "red", "green", "yellow", "blue", "magenta", "cyan", "white"}

        if value not in valid_colors:
            raise ValueError(f"Invalid color: {value}")

        return value

class List:
    def serialize(self, value, display=False):
        """
        Serialize a list of values into a string representation. It iterates through
        each item in the list and serializes each item. The serialized values are then
        joined together with newlines and returned as a string.

        Input-Output Arguments
        :param self: List. An instance of the List class.
        :param value: The list of values to be serialized.
        :param display: Bool. Whether to include additional display information in the
                        serialization. Defaults to False.
        :return: String. The serialized representation of the list.
        """
        serialized = []
        for item in value:
            if hasattr(item, "serialize") and callable(item.serialize):
                serialized.append(item.serialize(display=display))
            else:
                serialized.append(str(item))
        return "\n".join(serialized)

class LogLevel:
    def deserialize(self, value):
        """
        Deserialize a value and return the corresponding log level. It decodes
        the input value, validates it against the available log levels, and
        returns the corresponding log level.

        Input-Output Arguments
        :param self: LogLevel. An instance of the LogLevel class.
        :param value: The value to be deserialized.
        :return: The corresponding log level.
        """
        if isinstance(value, bytes):
            value = value.decode("utf-8")

        if not isinstance(value, str):
            raise TypeError("Log level value must be a string or bytes.")

        value = value.strip().upper()

        valid_levels = {"DEBUG", "INFO", "WARNING", "ERROR", "CRITICAL"}

        if value not in valid_levels:
            raise ValueError(f"Invalid log level: {value}")

        return value

