class Note:
    def to_hertz(self, standard_pitch=440):
        """
        This function converts a given Note instance to Hertz (frequency in cycles per second).

        Input-Output Arguments
        :param self: Note. An instance of the Note class.
        :param standard_pitch: float. The pitch of A-4, from which the rest of the notes are calculated. It defaults to 440 if not specified.
        :return: float. The frequency of the Note in Hertz.
        """
        return standard_pitch * (2 ** (self.semitones_from_a4() / 12))

class Note:
    def to_shorthand(self):
        """
        This function returns the traditional Helmholtz pitch notation for a given note.

        Input-Output Arguments
        :param self: Note, an instance of the Note class.
        :return: str. The Helmholtz pitch notation for the note.
        """
        name = self.name.upper()
        accidental = getattr(self, "accidental", "")
        octave = self.octave

        if octave < 3:
            # Great and contra octaves: uppercase with commas
            return name + accidental + ("," * (3 - octave))
        elif octave == 3:
            # Small octave: lowercase
            return name.lower() + accidental
        else:
            # One-lined and above: lowercase with apostrophes
            return name.lower() + accidental + ("'" * (octave - 3))

