# type: (Text) -> Text

"""
This function normalizes a given path by collapsing back-references (such as "..") and removing duplicated separators ("/"). If the input describes a path that can not be reached, such as "foo/../../bar", an IndexError will be excepted and the function will raise an illegal back reference instead.
Input-Output Arguments
:param path: Text. The path to be normalized. For example, "/foo//bar/frob/../baz".
:return: Text. A valid file system path. For example, '/foo/bar/baz',
"""
is_absolute = path.startswith("/")
parts = path.split("/")
stack = []

try:
    for part in parts:
        if part == "" or part == ".":
            continue
        elif part == "..":
            if not stack:
                raise IndexError
            stack.pop()
        else:
            stack.append(part)
except IndexError:
    raise ValueError("illegal back reference")

normalized = "/".join(stack)

if is_absolute:
    normalized = "/" + normalized

return normalized if normalized else ("/" if is_absolute else ".")

class Bundle:
    def add_file(self, path, entry_point=None):

        """
        This function adds an additional file to the bundle. If the file corresponds to an ELF binary, all of its dependencies will also be pulled into the bundle. The function handles both absolute and relative paths, as well as binary names in `PATH`. Directories will be included recursively for non-entry point dependencies.
        Input-Output Arguments
        :param self: Bundle. An instance of the Bundle class.
        :param path: str. The path of the file to be added. It can be an absolute path, relative path, or a binary name in `PATH`.
        :param entry_point: str, optional. The name of the bundle entry point for an executable. If `True`, the executable's basename will be used.
        :return: The `File` that was added, or `None` if it was a directory that was added recursively.
        """
        import os
        import shutil

        # Resolve the incoming path:
        # - absolute paths are used directly
        # - relative paths are resolved against cwd if they exist
        # - otherwise try to locate them in PATH
        resolved = path
        if not os.path.isabs(resolved):
            if os.path.exists(resolved):
                resolved = os.path.abspath(resolved)
            else:
                found = shutil.which(resolved)
                if found:
                    resolved = found
                else:
                    resolved = os.path.abspath(resolved)

        if not os.path.exists(resolved):
            raise FileNotFoundError(resolved)

        # If this is a directory and not an explicit entry point, recurse into it.
        if os.path.isdir(resolved):
            if entry_point:
                raise ValueError("entry_point may only be used with files, not directories")
            for root, dirs, files in os.walk(resolved):
                for name in files:
                    self.add_file(os.path.join(root, name))
            return None

        # Normalize entry point value
        if entry_point is True:
            entry_point = os.path.basename(resolved)

        # Avoid duplicate additions if the bundle tracks files by source path
        existing = getattr(self, "files", None)
        if isinstance(existing, dict) and resolved in existing:
            f = existing[resolved]
            if entry_point:
                setattr(f, "entry_point", entry_point)
            return f

        # Create/add the file object using whatever storage convention the Bundle uses
        file_obj = None

        # Common patterns for bundle implementations
        if hasattr(self, "File"):
            file_obj = self.File(resolved, entry_point=entry_point)
        else:
            try:
                file_obj = File(resolved, entry_point=entry_point)  # noqa: F821
            except Exception:
                file_obj = {"path": resolved, "entry_point": entry_point}

        if hasattr(self, "files"):
            if isinstance(self.files, dict):
                self.files[resolved] = file_obj
            elif isinstance(self.files, list):
                self.files.append(file_obj)

        # Pull in ELF dependencies if helper methods exist
        is_elf = False
        if hasattr(self, "_is_elf"):
            is_elf = self._is_elf(resolved)
        else:
            try:
                with open(resolved, "rb") as fh:
                    is_elf = fh.read(4) == b"\x7fELF"
            except OSError:
                is_elf = False

        if is_elf:
            deps = []
            if hasattr(self, "_get_elf_dependencies"):
                deps = self._get_elf_dependencies(resolved) or []
            elif hasattr(self, "get_elf_dependencies"):
                deps = self.get_elf_dependencies(resolved) or []

            for dep in deps:
                try:
                    self.add_file(dep)
                except FileNotFoundError:
                    # Skip unresolved runtime dependencies
                    pass

        return file_obj

