import os
import shutil


def file(
    path,
    present=True,
    user=None,
    group=None,
    mode=None,
    touch=False,
    create_remote_dir=True,
    force=False,
    force_backup=True,
    force_backup_dir=None,
):
    """
    This function is used to add, remove, or update files. It performs different actions based on the input parameters. It can create a file, remove a file, or update the properties of an existing file.
    Input-Output Arguments
    :param path: String. The name or path of the remote file.
    :param present: Bool. Whether the file should exist. If set to False, the file will be removed if it exists.
    :param user: String. The user to own the files.
    :param group: String. The group to own the files.
    :param mode: Integer. The permissions of the files.
    :param touch: Bool. Whether to touch the file.
    :param create_remote_dir: Bool. Whether to create the remote directory if it doesn't exist.
    :param force: Bool. If the target exists and is not a file, move or remove it and continue.
    :param force_backup: Bool. Whether to remove any existing non-file when force=True.
    :param force_backup_dir: String. The directory to move any backup to when force=True.
    :return: No return values.
    """
    if not path:
        raise ValueError("path is required")

    parent_dir = os.path.dirname(path) or "."

    if not present:
        if os.path.lexists(path):
            if os.path.isdir(path) and not os.path.islink(path):
                shutil.rmtree(path)
            else:
                os.remove(path)
        return

    if create_remote_dir and not os.path.exists(parent_dir):
        os.makedirs(parent_dir, exist_ok=True)

    if os.path.exists(path) and not os.path.isfile(path):
        if not force:
            raise ValueError(f"Target exists and is not a file: {path}")

        if force_backup_dir:
            os.makedirs(force_backup_dir, exist_ok=True)
            backup_path = os.path.join(force_backup_dir, os.path.basename(path))
            if os.path.exists(backup_path) or os.path.lexists(backup_path):
                raise FileExistsError(f"Backup path already exists: {backup_path}")
            shutil.move(path, backup_path)
        elif force_backup:
            backup_path = f"{path}.bak"
            if os.path.exists(backup_path) or os.path.lexists(backup_path):
                raise FileExistsError(f"Backup path already exists: {backup_path}")
            shutil.move(path, backup_path)
        else:
            if os.path.isdir(path) and not os.path.islink(path):
                shutil.rmtree(path)
            else:
                os.remove(path)

    if not os.path.exists(path):
        open(path, "a").close()

    if touch:
        os.utime(path, None)

    if mode is not None:
        os.chmod(path, mode)

    if user is not None or group is not None:
        shutil.chown(path, user=user, group=group)

from concurrent.futures import ThreadPoolExecutor, as_completed


def connect_all(state: "State"):
    """
    This function connects to all the configured servers in parallel. It reads and writes
    the inventory of the input State instance. It activates the hosts that are initially
    connected to and updates the state accordingly.

    Input-Output Arguments
    :param state: State. The state object containing the inventory to connect to.
    :return: No return values.
    """

    inventory = getattr(state, "inventory", None)
    if inventory is None:
        return

    hosts = getattr(inventory, "hosts", None)
    if not hosts:
        return

    def _connect_host(host):
        try:
            if hasattr(host, "connect") and callable(host.connect):
                result = host.connect()

                if hasattr(host, "active"):
                    host.active = bool(result) if result is not None else True
                elif hasattr(host, "connected"):
                    host.connected = bool(result) if result is not None else True

                return host, True, None

            return host, False, AttributeError("Host has no connect() method")
        except Exception as exc:
            if hasattr(host, "active"):
                host.active = False
            elif hasattr(host, "connected"):
                host.connected = False
            return host, False, exc

    max_workers = min(32, len(hosts)) or 1

    with ThreadPoolExecutor(max_workers=max_workers) as executor:
        futures = [executor.submit(_connect_host, host) for host in hosts]

        for future in as_completed(futures):
            host, success, error = future.result()

            if hasattr(inventory, "active_hosts"):
                if success:
                    if host not in inventory.active_hosts:
                        inventory.active_hosts.append(host)
                else:
                    if host in inventory.active_hosts:
                        inventory.active_hosts.remove(host)

            if hasattr(state, "connection_errors"):
                if error is not None:
                    state.connection_errors[host] = error
                elif host in state.connection_errors:
                    del state.connection_errors[host]

