import ast
from typing import List


class AstTransformer:
    def get_assign_targets_with_attr(self, node: ast.AST) -> List[ast.Attribute]:
        """
        This function takes an AST node as input and returns a list of attribute nodes that are used as assignment targets. It recursively traverses the AST and checks the type of each node to determine if it is an attribute node. If it is, the node is added to the list of assignment targets. If the node is a name, subscript, or starred node, it is skipped. If the node is a tuple or list, the function is called recursively on each element of the tuple or list and the results are concatenated. If the node type is unexpected, a warning message is printed. The format of the message is "WARNING Unexpected node type {node's type} for ast.Assign. Please report to the author github.com/gaogaotiantian/viztracer".
        Input-Output Arguments
        :param self: AstTransformer. An instance of the AstTransformer class.
        :param node: ast.Node. The AST node to process.
        :return: List[ast.Attribute]. A list of attribute nodes that are used as assignment targets.
        """
        if isinstance(node, ast.Attribute):
            return [node]
        elif isinstance(node, (ast.Name, ast.Subscript, ast.Starred)):
            return []
        elif isinstance(node, (ast.Tuple, ast.List)):
            ret = []
            for elt in node.elts:
                ret.extend(self.get_assign_targets_with_attr(elt))
            return ret
        else:
            print(
                f"WARNING Unexpected node type {type(node)} for ast.Assign. "
                "Please report to the author github.com/gaogaotiantian/viztracer"
            )
            return []

class SourceProcessor:
    def process(self, source: Any):
        """
        This function processes the input source by applying a series of transformations to each line. It checks if the source is of type bytes and decodes it to utf-8 if necessary. If the source is not a string, directly return the source. It then iterates over each line in the source and checks if it matches any of the patterns defined in the SourceProcessor instance. If a match is found, the corresponding transformation function is applied to the line and the transformed line is added to a new list. If no match is found, the original line is added to the new list. Finally, the function joins all the lines in the new list with newline characters and returns the processed source.
        Input-Output Arguments
        :param self: SourceProcessor. An instance of the SourceProcessor class.
        :param source: Any. The input source to be processed. It can be of type bytes or str.
        :return: str. The processed source with transformations applied to each line.
        """
        if isinstance(source, bytes):
            source = source.decode("utf-8")

        if not isinstance(source, str):
            return source

        new_lines = []
        for line in source.splitlines():
            transformed = False
            for pattern, transform in self.patterns:
                if pattern.search(line):
                    new_lines.append(transform(line))
                    transformed = True
                    break
            if not transformed:
                new_lines.append(line)

        return "\n".join(new_lines)

class WalELogger:
    def fmt_logline(msg, detail=None, hint=None, structured=None):
        """
        Format a log line with the given message, detail, hint, and structured data. It creates a list to format these information, and the first is "['MSG: {message}', 'DETAIL: {detail}', 'HINT: {hint}', 'STRUCTURED: {structured data}']". Then, it joins them with a newline character to obtain the log line.
        Input-Output Arguments
        :param msg: String. The main message to be included in the log line.
        :param detail: String [optional]. Additional details to be included in the log line.
        :param hint: String [optional]. A hint or suggestion related to the log message.
        :param structured: Dictionary [optional]. Additional structured data to be included in the log line.
        :return: String. The formatted log line.
        """
        parts = [f"MSG: {msg}"]

        if detail is not None:
            parts.append(f"DETAIL: {detail}")

        if hint is not None:
            parts.append(f"HINT: {hint}")

        if structured is not None:
            parts.append(f"STRUCTURED: {structured}")

        return "\n".join(parts)

import os


class WalSegment:
    def __init__(self, name):
        self.name = name

    @staticmethod
    def from_ready_archive_status(xlog_dir):
        """
        This function generates WalSegment instances based on the files in the
        archive_status directory of the given xlog_dir. It iterates through the
        files in the directory, filters out non-segment files, and creates a
        WalSegment instance for each segment file.

        Input-Output Arguments
        :param xlog_dir: String. The directory path where the xlog files are stored.
        :return: Generator. Yields WalSegment instances for each segment file in
                 the archive_status directory.
        """
        archive_status_dir = os.path.join(xlog_dir, "archive_status")

        if not os.path.isdir(archive_status_dir):
            return

        for filename in os.listdir(archive_status_dir):
            if not filename.endswith(".ready"):
                continue

            segment_name = filename[:-6]  # remove ".ready"

            # WAL segment names are typically 24-character hexadecimal strings
            if len(segment_name) != 24:
                continue

            try:
                int(segment_name, 16)
            except ValueError:
                continue

            yield WalSegment(segment_name)

class WalTransferGroup:
    def join(self):

        """
        This function waits for the transfer to exit and raises any errors that occur during the process. It closes the input WalTransferGroup instance. Then, it waits a while for all running greenlets to exit and attempts to force them to exit so join terminates in a reasonable amount of time (e.g., 30).
        Input-Output Arguments
        :param self: WalTransferGroup. An instance of the WalTransferGroup class.
        :return: No return values.
        """
        # Prevent new work from being scheduled.
        self.close()

        # Wait for the transfer loop/main greenlet to finish and propagate errors.
        if hasattr(self, "_transfer_greenlet") and self._transfer_greenlet is not None:
            self._transfer_greenlet.join()
            if getattr(self._transfer_greenlet, "exception", None) is not None:
                raise self._transfer_greenlet.exception

        # Wait for worker greenlets to exit gracefully.
        greenlets = list(getattr(self, "_greenlets", []))
        if greenlets:
            try:
                import gevent
                gevent.joinall(greenlets, timeout=30, raise_error=True)
            except Exception:
                # If some greenlets are still running, kill them so join does not block forever.
                for g in greenlets:
                    if not g.dead:
                        g.kill(block=False)
                gevent.joinall(greenlets, timeout=1, raise_error=True)

from typing import Union, TextIO
import os
import json
import gzip


class ReportBuilder:
    def save(self, output_file: Union[str, TextIO] = "result.html", file_info: bool = True) -> None:
        """
        This function saves the report generated by the ReportBuilder instance to an output file. It supports saving the report in different formats such as HTML, JSON, and GZ. If the output_file parameter is a string, it determines the file format based on the file extension and saves the report accordingly. If the output_file parameter is a file object, it saves the report directly to that file. After saving the report, it appends a message to the message list indicating the command to view the saved report and then prints all the messages. The format of the message is "('view_command', {'output_file': the absolute path of output file})"
        Input-Output Arguments
        :param self: ReportBuilder. An instance of the ReportBuilder class.
        :param output_file: Union[str, TextIO]. The output file where the report will be saved. It can be either a string representing the file path or a file object. Defaults to "result.html".
        :param file_info: bool. Whether to include file information in the report. Defaults to True.
        :return: No return values.
        """

        # Build report content using available builder methods/attributes.
        if hasattr(self, "build_report"):
            report_data = self.build_report(file_info=file_info)
        elif hasattr(self, "report"):
            report_data = self.report(file_info=file_info) if callable(self.report) else self.report
        elif hasattr(self, "to_dict"):
            report_data = self.to_dict(file_info=file_info)
        else:
            raise AttributeError("ReportBuilder instance has no method to generate report data.")

        def _to_html(data) -> str:
            if hasattr(self, "to_html"):
                return self.to_html(file_info=file_info)
            if isinstance(data, str):
                return data
            return (
                "<html><body><pre>"
                + json.dumps(data, indent=2, ensure_ascii=False)
                + "</pre></body></html>"
            )

        def _to_json(data) -> str:
            if isinstance(data, str):
                return data
            return json.dumps(data, indent=2, ensure_ascii=False)

        saved_path = None

        if isinstance(output_file, str):
            ext = os.path.splitext(output_file)[1].lower()

            if ext == ".html":
                content = _to_html(report_data)
                with open(output_file, "w", encoding="utf-8") as f:
                    f.write(content)

            elif ext == ".json":
                content = _to_json(report_data)
                with open(output_file, "w", encoding="utf-8") as f:
                    f.write(content)

            elif ext == ".gz":
                inner_ext = os.path.splitext(os.path.splitext(output_file)[0])[1].lower()
                if inner_ext == ".json":
                    content = _to_json(report_data)
                else:
                    content = _to_html(report_data)

                with gzip.open(output_file, "wt", encoding="utf-8") as f:
                    f.write(content)

            else:
                # Default to HTML for unknown extensions
                content = _to_html(report_data)
                with open(output_file, "w", encoding="utf-8") as f:
                    f.write(content)

            saved_path = os.path.abspath(output_file)

        else:
            # Assume file-like object
            if hasattr(output_file, "name"):
                name = str(output_file.name)
                ext = os.path.splitext(name)[1].lower()
            else:
                ext = ""

            if ext == ".json":
                content = _to_json(report_data)
            else:
                content = _to_html(report_data)

            output_file.write(content)
            if hasattr(output_file, "flush"):
                output_file.flush()

            if hasattr(output_file, "name"):
                saved_path = os.path.abspath(output_file.name)

        if not hasattr(self, "messages") or self.messages is None:
            self.messages = []

        if saved_path is not None:
            self.messages.append(("view_command", {"output_file": saved_path}))

        for message in self.messages:
            print(message)

class TarUploadPool:
    def put(self, tpart):

        """
        This function is used to upload a tar volume. It checks if there is too much work outstanding already and raises errors of previously submitted greenlets that die unexpectedly. If there are not enough resources to start an upload, it raises an exception. Otherwise, it starts the upload.
        Input-Output Arguments
        :param self: TarUploadPool. An instance of the TarUploadPool class.
        :param tpart: The tar volume to be uploaded.
        :return: No return values.
        """
        # Raise any unexpected errors from previously submitted uploads.
        if hasattr(self, "greenlets"):
            for g in list(self.greenlets):
                if getattr(g, "dead", False):
                    exc = getattr(g, "exception", None)
                    if exc is not None:
                        raise exc
                    try:
                        self.greenlets.remove(g)
                    except (ValueError, AttributeError):
                        pass

        # Refuse new work if too much is already outstanding.
        max_outstanding = getattr(self, "max_outstanding", None)
        if max_outstanding is not None and hasattr(self, "greenlets"):
            active = [g for g in self.greenlets if not getattr(g, "dead", False)]
            self.greenlets = active
            if len(active) >= max_outstanding:
                raise RuntimeError("Too much work outstanding already")

        # Ensure resources are available to start a new upload.
        semaphore = getattr(self, "semaphore", None)
        if semaphore is not None:
            acquired = semaphore.acquire(blocking=False)
            if not acquired:
                raise RuntimeError("Not enough resources to start upload")

        # Start the upload.
        try:
            spawn = getattr(self, "spawn", None)
            if spawn is None:
                import gevent
                g = gevent.spawn(self._upload, tpart)
            else:
                g = spawn(self._upload, tpart)

            if not hasattr(self, "greenlets"):
                self.greenlets = []
            self.greenlets.append(g)
        except Exception:
            if semaphore is not None:
                try:
                    semaphore.release()
                except Exception:
                    pass
            raise

