class UploadDirManager:
    def __init__(self):
        self._paths = {}
        self._counter = 0

    def add(self, path):
        """
        This function adds a path to the UploadDirManager instance. If the path has not been added before, it assigns it a name and ensures the file will not be hidden. If the path is a URI, it does not add it and just returns the URI.

        Input-Output Arguments
        :param self: UploadDirManager. An instance of the UploadDirManager class.
        :param path: The path to be added.
        :return: The URI assigned to the path.
        """
        if isinstance(path, str) and (path.startswith("http://") or path.startswith("https://")):
            return path

        if path not in self._paths:
            self._counter += 1
            name = f"upload_{self._counter}"

            # Ensure the file is not hidden by removing a leading dot from the basename
            if isinstance(path, str):
                parts = path.rsplit("/", 1)
                if len(parts) == 2:
                    directory, filename = parts
                    if filename.startswith("."):
                        filename = filename.lstrip(".")
                    visible_path = f"{directory}/{filename}"
                else:
                    visible_path = path.lstrip(".")
            else:
                visible_path = path

            self._paths[path] = {
                "name": name,
                "path": visible_path,
            }

        return self._paths[path]["name"]

class WorkingDirManager:
    def paths(self, type=None):
        """
        This function returns a set of all paths tracked by the WorkingDirManager instance.
        It iterates through the internal data structures and adds the paths to the set
        based on the specified type.

        Input-Output Arguments
        :param self: WorkingDirManager. An instance of the WorkingDirManager class.
        :param type: str. The type of paths to filter. If not specified, all paths are included.
        :return: set. A set of paths tracked by the WorkingDirManager instance.
        """
        result = set()

        for attr_name, attr_value in self.__dict__.items():
            if type is None:
                if isinstance(attr_value, dict):
                    result.update(attr_value.keys())
                elif isinstance(attr_value, (set, list, tuple)):
                    result.update(attr_value)
            elif attr_name == type:
                if isinstance(attr_value, dict):
                    result.update(attr_value.keys())
                elif isinstance(attr_value, (set, list, tuple)):
                    result.update(attr_value)

        return result

class WorkingDirManager:
    def name_to_path(self, type=None):
        """
        This function returns a map that maps the name of files/archives in the setup directory to their corresponding paths. It can be used to build options for Hadoop or to fake them in a bootstrap script.

        Input-Output Arguments
        :param self: WorkingDirManager. An instance of the WorkingDirManager class.
        :param type: str. The type of files/archives to include in the map. It can be either "archive" or "file". If not specified, all files/archives will be included.
        :return: Dictionary. A dictionary that maps the name of files/archives to their corresponding paths.
        """
        name_to_path = {}

        # collect items based on requested type
        if type is None:
            items = []
            if hasattr(self, 'files'):
                items.extend(self.files)
            if hasattr(self, 'archives'):
                items.extend(self.archives)
        elif type == 'file':
            items = getattr(self, 'files', [])
        elif type == 'archive':
            items = getattr(self, 'archives', [])
        else:
            raise ValueError('type must be "archive", "file", or None')

        for item in items:
            if isinstance(item, tuple) and len(item) >= 2:
                name, path = item[0], item[1]
            elif hasattr(item, 'name') and hasattr(item, 'path'):
                name, path = item.name, item.path
            else:
                continue

            name_to_path[name] = path

        return name_to_path

