import os
import glob


def combine_path_lists(*path_seqs):
    """
    This function combines multiple path sequences into a single list. It resolves `~` (home dir)
    and environment variables, and expands globs that refer to the local filesystem.
    It can take single strings as well as lists.

    Input-Output Arguments
    :param path_seqs: Variable number of sequences. The path sequences to be combined.
    :return: List. The combined list of paths after resolving `~`, environment variables,
             and expanding globs.
    """
    combined = []

    for seq in path_seqs:
        if seq is None:
            continue

        if isinstance(seq, str):
            items = [seq]
        else:
            items = seq

        for path in items:
            if path is None:
                continue

            resolved = os.path.expanduser(os.path.expandvars(path))
            expanded = glob.glob(resolved)

            if expanded:
                combined.extend(expanded)
            else:
                combined.append(resolved)

    return combined

