    for chunk in chunks:
        buffer += chunk
        while True:
            idx = buffer.find(b"\n")
            if idx == -1:
                break
            yield buffer[:idx]
            buffer = buffer[idx + 1:]
    if buffer:
        yield buffer

return _iter_lines()

