class MultiProcessCollector:
    def merge(files, accumulate=True):
        """
        Merge metrics from given mmap files. By default, histograms are accumulated, but if writing the merged data back to mmap files, use accumulate=False to avoid compound accumulation.
        Input-Output Arguments
        :param files: List of str. The mmap files to merge metrics from.
        :param accumulate: Bool. Whether to accumulate histograms. Defaults to True.
        :return: The merged metrics.
        """
        merged = {}

        for file_path in files:
            with open(file_path, "r", encoding="utf-8") as f:
                data = f.read().strip()
                if not data:
                    continue

                # Expect each file to contain a Python dict literal or JSON-like dict
                metrics = eval(data, {"__builtins__": {}})

                for key, value in metrics.items():
                    if key not in merged:
                        if isinstance(value, dict):
                            merged[key] = value.copy()
                        elif isinstance(value, list):
                            merged[key] = value[:]
                        else:
                            merged[key] = value
                    else:
                        if isinstance(value, (int, float)):
                            merged[key] += value
                        elif isinstance(value, list):
                            if accumulate:
                                merged[key].extend(value)
                            else:
                                merged[key] = value[:]
                        elif isinstance(value, dict):
                            for subkey, subvalue in value.items():
                                if subkey not in merged[key]:
                                    merged[key][subkey] = subvalue
                                else:
                                    if isinstance(subvalue, (int, float)):
                                        merged[key][subkey] += subvalue
                                    elif accumulate and isinstance(subvalue, list):
                                        merged[key][subkey].extend(subvalue)
                                    else:
                                        merged[key][subkey] = subvalue
                        else:
                            merged[key] = value

        return merged

