    statement: dict,
    resource: str,
    condition_keys: Optional[CaseInsensitiveDict] = None,
) -> bool:
    """
    This function is a helper function that checks if a given resource is present
    in a policy statement. It checks if the resource matches any of the resources
    listed in the 'Resource' field of the statement. If it does, it returns True.
    If 'Resource' not in statement and the 'NotResource' field is present, it checks
    if the resource matches any of the resources listed in that field. If it does,
    it returns False. If neither 'Resource' nor 'NotResource' fields are present,
    it returns True.

    Input-Output Arguments
    :param statement: dict. The policy statement to check.
    :param resource: str. The resource to check for.
    :param condition_keys: Optional[CaseInsensitiveDict]. A dictionary of condition keys.
        Defaults to None.
    :return: bool. True if the resource is in the policy statement, False otherwise.
    """

    def _as_list(value):
        if isinstance(value, (list, tuple, set)):
            return list(value)
        return [value]

    def _match(pattern: str, value: str) -> bool:
        # Prefer a project-provided matcher if available.
        try:
            return _matches(pattern, value, condition_keys=condition_keys)  # type: ignore[name-defined]
        except NameError:
            pass
        except TypeError:
            try:
                return _matches(pattern, value)  # type: ignore[name-defined]
            except Exception:
                pass

        # Fallback to standard wildcard matching.
        from fnmatch import fnmatchcase

        return fnmatchcase(value, pattern)

    if "Resource" in statement:
        resources = _as_list(statement["Resource"])
        return any(_match(res_pattern, resource) for res_pattern in resources)

    if "NotResource" in statement:
        not_resources = _as_list(statement["NotResource"])
        return not any(_match(res_pattern, resource) for res_pattern in not_resources)

    return True

