class Model:
    def compute_rarest_windows(
        self,
        window_len: int,
        use_start_end_tokens: bool = True,
        use_geo_mean: bool = False,
    ):

        """
        This function computes the rarest windows and corresponding likelihood for each session. It uses a sliding window approach to identify the rarest window and its likelihood in each session. The function takes into account the length of the sliding window, whether to use start and end tokens, and whether to use the geometric mean for likelihood calculations.
        Input-Output Arguments
        :param self: Model. An instance of the Model class.
        :param window_len: int. The length of the sliding window for likelihood calculations.
        :param use_start_end_tokens: bool. If True, start and end tokens will be added to each session before calculations.
        :param use_geo_mean: bool. If True, the likelihoods of the sliding windows will be raised to the power of (1/window_len).
        :return: None. The function updates the rarest windows and corresponding likelihoods in the Model instance.
        """

        if window_len <= 0:
            raise ValueError("window_len must be a positive integer")

        self.rarest_windows = []
        self.rarest_window_likelihoods = []

        sessions = getattr(self, "sessions", None)
        if sessions is None:
            raise AttributeError("Model instance must have a 'sessions' attribute")

        start_token = getattr(self, "start_token", "<START>")
        end_token = getattr(self, "end_token", "<END>")

        for session in sessions:
            seq = list(session)

            if use_start_end_tokens:
                seq = [start_token] + seq + [end_token]

            # If the sequence is shorter than the requested window length,
            # use the whole sequence as a single window.
            if len(seq) == 0:
                self.rarest_windows.append([])
                self.rarest_window_likelihoods.append(0.0)
                continue

            if len(seq) < window_len:
                windows = [seq]
            else:
                windows = [
                    seq[i : i + window_len]
                    for i in range(len(seq) - window_len + 1)
                ]

            rarest_window = None
            rarest_likelihood = None

            for window in windows:
                likelihood = 1.0

                # Try to use a transition-probability style model if available.
                if hasattr(self, "transition_probs"):
                    for i in range(len(window) - 1):
                        a, b = window[i], window[i + 1]
                        prob = self.transition_probs.get(a, {}).get(b, 0.0)
                        likelihood *= prob

                # Otherwise try token probabilities.
                elif hasattr(self, "token_probs"):
                    for token in window:
                        prob = self.token_probs.get(token, 0.0)
                        likelihood *= prob

                # Otherwise fall back to a model method if present.
                elif hasattr(self, "compute_window_likelihood"):
                    likelihood = self.compute_window_likelihood(window)

                else:
                    raise AttributeError(
                        "Model must define one of: 'transition_probs', "
                        "'token_probs', or 'compute_window_likelihood'"
                    )

                if use_geo_mean and len(window) > 0:
                    likelihood = likelihood ** (1 / len(window))

                if rarest_likelihood is None or likelihood < rarest_likelihood:
                    rarest_likelihood = likelihood
                    rarest_window = window

            self.rarest_windows.append(rarest_window)
            self.rarest_window_likelihoods.append(rarest_likelihood)

    window: List[Cmd],
    prior_probs: Union[StateMatrix, dict],
    trans_probs: Union[StateMatrix, dict],
    param_cond_cmd_probs: Union[StateMatrix, dict],
    use_start_token: bool,
    use_end_token: bool,
    start_token: str = None,
    end_token: str = None,
) -> float:
    """
    This function computes the likelihood of a given window of commands. It calculates the probability of the window based on prior probabilities, transition probabilities, and parameter conditional command probabilities.
    Input-Output Arguments
    :param window: List[Cmd]. A list of commands representing a session.
    :param prior_probs: Union[StateMatrix, dict]. Computed probabilities of individual commands.
    :param trans_probs: Union[StateMatrix, dict]. Computed probabilities of sequences of commands.
    :param param_cond_cmd_probs: Union[StateMatrix, dict]. Computed probabilities of the parameters conditional on the commands.
    :param use_start_token: Bool. Whether to prepend the start_token to the window before calculating the likelihood.
    :param use_end_token: Bool. Whether to append the end_token to the window before calculating the likelihood.
    :param start_token: Str. A dummy command to signify the start of the session. Defaults to None.
    :param end_token: Str. A dummy command to signify the end of the session. Defaults to None.
    :return: Float. The likelihood of the window.
    """

    def _get_prob(table, *keys, default=0.0):
        """
        Safely fetch probabilities from either nested dicts or StateMatrix-like objects.
        """
        cur = table
        try:
            for key in keys:
                if isinstance(cur, dict):
                    cur = cur[key]
                else:
                    try:
                        cur = cur[key]
                    except Exception:
                        cur = getattr(cur, key)
            return float(cur)
        except Exception:
            return float(default)

    def _cmd_name(cmd):
        """
        Extract command identifier from Cmd-like objects or plain strings.
        """
        if isinstance(cmd, str):
            return cmd
        for attr in ("cmd", "command", "name"):
            if hasattr(cmd, attr):
                return getattr(cmd, attr)
        return str(cmd)

    def _cmd_params(cmd):
        """
        Extract parameters from Cmd-like objects.
        """
        if isinstance(cmd, str):
            return None
        for attr in ("params", "param", "parameters", "args", "arguments"):
            if hasattr(cmd, attr):
                return getattr(cmd, attr)
        return None

    # Build augmented window
    seq = list(window)
    if use_start_token:
        seq = [start_token] + seq
    if use_end_token:
        seq = seq + [end_token]

    if len(seq) == 0:
        return 0.0

    likelihood = 1.0

    # Prior probability for first command
    first_cmd = _cmd_name(seq[0])
    likelihood *= _get_prob(prior_probs, first_cmd, default=0.0)

    # Parameter conditional probability for first command
    first_params = _cmd_params(seq[0])
    if first_params is not None:
        likelihood *= _get_prob(param_cond_cmd_probs, first_cmd, first_params, default=1.0)

    # Transition and parameter probabilities for remaining commands
    for prev, curr in zip(seq[:-1], seq[1:]):
        prev_cmd = _cmd_name(prev)
        curr_cmd = _cmd_name(curr)

        likelihood *= _get_prob(trans_probs, prev_cmd, curr_cmd, default=0.0)

        curr_params = _cmd_params(curr)
        if curr_params is not None:
            likelihood *= _get_prob(param_cond_cmd_probs, curr_cmd, curr_params, default=1.0)

    return likelihood

class Model:
    def compute_scores(self, use_start_end_tokens: bool):
        """
        This function computes various likelihood-based scores/metrics for each session in the model. It calculates the likelihoods and geometric mean of the likelihoods for each session. It also uses a sliding window approach to compute the rarest window likelihoods for each session, with window lengths of 2 and 3.
        Note that if a session has a length of k and a sliding window of length k+1 is used, the rarest window likelihood metric for that session will be np.nan. However, if the parameter `use_start_end_tokens` is set to True, the session will be treated as a session of length k+1 because the start and end tokens will be appended, resulting in a non np.nan value for that session.
        Input-Output Arguments
        :param self: Model. An instance of the Model class.
        :param use_start_end_tokens: Bool. If True, the start and end tokens will be prepended and appended to each session respectively before the calculations are done.
        :return: No return values.
        """
        import numpy as np

        def _safe_prob(token):
            # Try common probability access patterns.
            if hasattr(self, "get_probability") and callable(self.get_probability):
                return self.get_probability(token)
            if hasattr(self, "token_probabilities"):
                return self.token_probabilities.get(token, 0.0)
            if hasattr(self, "probabilities"):
                return self.probabilities.get(token, 0.0)
            if hasattr(self, "model"):
                if hasattr(self.model, "get"):
                    return self.model.get(token, 0.0)
            return 0.0

        def _window_prob(window):
            # Try common window probability access patterns first.
            key = tuple(window)
            if hasattr(self, "get_window_probability") and callable(self.get_window_probability):
                return self.get_window_probability(window)
            if hasattr(self, "window_probabilities"):
                return self.window_probabilities.get(key, 0.0)
            if hasattr(self, "ngram_probabilities"):
                return self.ngram_probabilities.get(key, 0.0)

            # Fallback: product of token probabilities.
            prob = 1.0
            for token in window:
                prob *= _safe_prob(token)
            return prob

        def _geom_mean(values):
            values = np.asarray(values, dtype=float)
            if len(values) == 0:
                return np.nan
            if np.any(values < 0):
                return np.nan
            if np.any(values == 0):
                return 0.0
            return float(np.exp(np.mean(np.log(values))))

        sessions = getattr(self, "sessions", None)
        if sessions is None:
            raise AttributeError("Model instance must have a 'sessions' attribute.")

        start_token = getattr(self, "start_token", "<START>")
        end_token = getattr(self, "end_token", "<END>")

        self.session_likelihoods = []
        self.session_geometric_mean_likelihoods = []
        self.session_rarest_window2_likelihoods = []
        self.session_rarest_window3_likelihoods = []

        for session in sessions:
            seq = list(session)
            if use_start_end_tokens:
                seq = [start_token] + seq + [end_token]

            token_likelihoods = [_safe_prob(token) for token in seq]
            self.session_likelihoods.append(token_likelihoods)
            self.session_geometric_mean_likelihoods.append(_geom_mean(token_likelihoods))

            if len(seq) >= 2:
                window2_probs = [_window_prob(seq[i:i + 2]) for i in range(len(seq) - 1)]
                self.session_rarest_window2_likelihoods.append(float(np.min(window2_probs)))
            else:
                self.session_rarest_window2_likelihoods.append(np.nan)

            if len(seq) >= 3:
                window3_probs = [_window_prob(seq[i:i + 3]) for i in range(len(seq) - 2)]
                self.session_rarest_window3_likelihoods.append(float(np.min(window3_probs)))
            else:
                self.session_rarest_window3_likelihoods.append(np.nan)

    window: List[str],
    prior_probs: Union[StateMatrix, dict],
    trans_probs: Union[StateMatrix, dict],
    use_start_token: bool,
    use_end_token: bool,
    start_token: str = None,
    end_token: str = None,
) -> float:

    """
    This function computes the likelihood of a given window of commands in a session. It calculates the probability of the window based on the prior probabilities of individual commands and the transition probabilities of sequences of commands.
    Input-Output Arguments
    :param window: List[str]. A list of commands representing a window of a session.
    :param prior_probs: Union[StateMatrix, dict]. Computed probabilities of individual commands.
    :param trans_probs: Union[StateMatrix, dict]. Computed probabilities of sequences of commands (length 2).
    :param use_start_token: bool. If set to True, the start_token will be prepended to the window before the likelihood calculation is done.
    :param use_end_token: bool. If set to True, the end_token will be appended to the window before the likelihood calculation is done.
    :param start_token: str. Dummy command to signify the start of the session. Defaults to None.
    :param end_token: str. Dummy command to signify the end of the session. Defaults to None.
    :return: float. The likelihood of the window.
    """
    seq = list(window)

    if use_start_token:
        if start_token is None:
            raise ValueError("start_token must be provided when use_start_token is True")
        seq = [start_token] + seq

    if use_end_token:
        if end_token is None:
            raise ValueError("end_token must be provided when use_end_token is True")
        seq = seq + [end_token]

    if len(seq) == 0:
        return 0.0

    def get_prior_prob(token: str) -> float:
        if isinstance(prior_probs, dict):
            return float(prior_probs.get(token, 0.0))
        try:
            return float(prior_probs[token])
        except Exception:
            return 0.0

    def get_trans_prob(prev_token: str, curr_token: str) -> float:
        if isinstance(trans_probs, dict):
            if prev_token in trans_probs and isinstance(trans_probs[prev_token], dict):
                return float(trans_probs[prev_token].get(curr_token, 0.0))
            return float(trans_probs.get((prev_token, curr_token), 0.0))
        try:
            return float(trans_probs[prev_token][curr_token])
        except Exception:
            try:
                return float(trans_probs[(prev_token, curr_token)])
            except Exception:
                return 0.0

    likelihood = get_prior_prob(seq[0])

    for prev_token, curr_token in zip(seq[:-1], seq[1:]):
        likelihood *= get_trans_prob(prev_token, curr_token)

    return likelihood

    session: List[Cmd],
    prior_probs: Union[StateMatrix, dict],
    trans_probs: Union[StateMatrix, dict],
    param_cond_cmd_probs: Union[StateMatrix, dict],
    window_len: int,
    use_start_end_tokens: bool,
    start_token: str = None,
    end_token: str = None,
    use_geo_mean: bool = False,
) -> List[float]:
    """
    This function computes the likelihoods of a sliding window in a session. It takes a session, prior probabilities, transition probabilities, parameter conditional command probabilities, window length, start and end tokens, and a flag to indicate whether to use geometric mean. It iterates through the session and calculates the likelihood for each sliding window. If the use_geo_mean flag is set to True, it raises each likelihood to the power of (1/window_len) before appending it to the list of likelihoods.
    Input-Output Arguments
    :param session: List[Cmd]. A list of Cmd objects representing a session.
    :param prior_probs: Union[StateMatrix, dict]. Computed probabilities of individual commands.
    :param trans_probs: Union[StateMatrix, dict]. Computed probabilities of sequences of commands (length 2).
    :param param_cond_cmd_probs: Union[StateMatrix, dict]. Computed probabilities of the parameters conditional on the command.
    :param window_len: int. The length of the sliding window for likelihood calculations.
    :param use_start_end_tokens: bool. If True, start and end tokens will be prepended and appended to the session respectively before the calculations are done.
    :param start_token: str. A dummy command to signify the start of the session. Defaults to None.
    :param end_token: str. A dummy command to signify the end of the session. Defaults to None.
    :param use_geo_mean: bool. If True, each likelihood of the sliding windows will be raised to the power of (1/window_len).
    :return: List[float]. A list of likelihoods.
    """
    if window_len <= 0:
        raise ValueError("window_len must be a positive integer")

    working_session = list(session)

    if use_start_end_tokens:
        if start_token is None or end_token is None:
            raise ValueError(
                "start_token and end_token must be provided when use_start_end_tokens is True"
            )
        working_session = [start_token] + working_session + [end_token]

    if len(working_session) < window_len:
        return []

    def _get_cmd_and_params(cmd_obj):
        if isinstance(cmd_obj, str):
            return cmd_obj, None
        if hasattr(cmd_obj, "cmd"):
            return cmd_obj.cmd, getattr(cmd_obj, "params", None)
        if hasattr(cmd_obj, "command"):
            return cmd_obj.command, getattr(cmd_obj, "params", None)
        return str(cmd_obj), getattr(cmd_obj, "params", None)

    def _lookup_prob(table, *keys, default=0.0):
        cur = table
        try:
            for key in keys:
                if isinstance(cur, dict):
                    cur = cur[key]
                else:
                    cur = cur[key]
            return float(cur)
        except (KeyError, TypeError, IndexError):
            return default

    likelihoods = []

    for i in range(len(working_session) - window_len + 1):
        window = working_session[i : i + window_len]

        first_cmd, first_params = _get_cmd_and_params(window[0])
        likelihood = _lookup_prob(prior_probs, first_cmd, default=0.0)

        if first_params is not None:
            param_prob = _lookup_prob(param_cond_cmd_probs, first_cmd, first_params, default=1.0)
            likelihood *= param_prob

        for j in range(1, len(window)):
            prev_cmd, _ = _get_cmd_and_params(window[j - 1])
            curr_cmd, curr_params = _get_cmd_and_params(window[j])

            trans_prob = _lookup_prob(trans_probs, prev_cmd, curr_cmd, default=0.0)
            likelihood *= trans_prob

            if curr_params is not None:
                param_prob = _lookup_prob(
                    param_cond_cmd_probs, curr_cmd, curr_params, default=1.0
                )
                likelihood *= param_prob

        if use_geo_mean:
            likelihood = likelihood ** (1.0 / window_len)

        likelihoods.append(likelihood)

    return likelihoods

    session: List[str],
    prior_probs: Union[StateMatrix, dict],
    trans_probs: Union[StateMatrix, dict],
    window_len: int,
    use_start_end_tokens: bool,
    start_token: str = None,
    end_token: str = None,
    use_geo_mean: bool = False,
) -> List[float]:

    """
    This function computes the likelihoods of a sliding window of commands in a session. It iterates through the session and calculates the likelihood of each window based on the prior probabilities and transition probabilities.
    Input-Output Arguments
    :param session: List[str]. A list of commands in a session.
    :param prior_probs: Union[StateMatrix, dict]. Computed probabilities of individual commands.
    :param trans_probs: Union[StateMatrix, dict]. Computed probabilities of sequences of commands.
    :param window_len: int. The length of the sliding window for likelihood calculations.
    :param use_start_end_tokens: bool. If True, start_token and end_token will be added to the session before calculations.
    :param start_token: str. A dummy command to signify the start of the session.
    :param end_token: str. A dummy command to signify the end of the session.
    :param use_geo_mean: bool. If True, each likelihood of the sliding windows will be raised to the power of (1/window_len).
    :return: List[float]. A list of likelihoods for each sliding window.
    """
    if window_len <= 0:
        raise ValueError("window_len must be a positive integer")

    session_tokens = list(session)
    if use_start_end_tokens:
        if start_token is None or end_token is None:
            raise ValueError(
                "start_token and end_token must be provided when use_start_end_tokens is True"
            )
        session_tokens = [start_token] + session_tokens + [end_token]

    if len(session_tokens) < window_len:
        return []

    def _get_prob(matrix, key1, key2=None):
        if key2 is None:
            if isinstance(matrix, dict):
                return matrix.get(key1, 0.0)
            try:
                return matrix[key1]
            except Exception:
                try:
                    return matrix.get(key1, 0.0)
                except Exception:
                    return 0.0
        else:
            if isinstance(matrix, dict):
                row = matrix.get(key1, {})
                if isinstance(row, dict):
                    return row.get(key2, 0.0)
                try:
                    return row[key2]
                except Exception:
                    return 0.0
            try:
                return matrix[key1][key2]
            except Exception:
                try:
                    row = matrix.get(key1, {})
                    return row.get(key2, 0.0)
                except Exception:
                    return 0.0

    likelihoods = []

    for i in range(len(session_tokens) - window_len + 1):
        window = session_tokens[i : i + window_len]

        likelihood = _get_prob(prior_probs, window[0])

        for j in range(1, len(window)):
            likelihood *= _get_prob(trans_probs, window[j - 1], window[j])

        if use_geo_mean:
            likelihood = likelihood ** (1 / window_len)

        likelihoods.append(likelihood)

    return likelihoods

    param_counts: Union[StateMatrix, dict], param_value_counts: Union[StateMatrix, dict]
) -> set:
    """
    This function determines which parameters should be modeled as categorical variables
    based on simple heuristics.

    A parameter is selected if:
    - it has more than one observed value
    - the number of distinct values is relatively small compared to the number of
      observations for that parameter

    Input-Output Arguments
    :param param_counts: Union[StateMatrix, dict]. The counts of each individual parameter.
    :param param_value_counts: Union[StateMatrix, dict]. The counts of each value conditional on the parameters.
    :return: set. A set of parameters that have been determined to be categorical.
    """

    def _to_dict(obj):
        if isinstance(obj, dict):
            return obj
        if hasattr(obj, "to_dict"):
            return obj.to_dict()
        try:
            return dict(obj)
        except Exception:
            raise TypeError("param_counts and param_value_counts must be dict-like or support to_dict().")

    param_counts_dict = _to_dict(param_counts)
    param_value_counts_dict = _to_dict(param_value_counts)

    params_to_model_values = set()

    for param, total_count in param_counts_dict.items():
        if param not in param_value_counts_dict:
            continue

        value_counts = param_value_counts_dict[param]
        value_counts = _to_dict(value_counts) if not isinstance(value_counts, dict) else value_counts

        num_distinct_values = len(value_counts)

        # Ignore parameters with no variation
        if num_distinct_values <= 1:
            continue

        # Heuristic: treat as categorical if the number of unique values is small
        # relative to the total number of observations.
        if total_count > 0 and num_distinct_values <= max(20, int(total_count ** 0.5)):
            params_to_model_values.add(param)

    return params_to_model_values

    window: List[Cmd],
    prior_probs: Union[StateMatrix, dict],
    trans_probs: Union[StateMatrix, dict],
    param_cond_cmd_probs: Union[StateMatrix, dict],
    value_cond_param_probs: Union[StateMatrix, dict],
    modellable_params: set,
    use_start_token: bool,
    use_end_token: bool,
    start_token: str = None,
    end_token: str = None,
) -> float:
    """
    This function computes the likelihood of a given window of commands. It calculates the probability of the window based on the prior probabilities, transition probabilities, and conditional probabilities of parameters and values.
    Input-Output Arguments
    :param window: List[Cmd]. A list of commands representing a session.
    :param prior_probs: Union[StateMatrix, dict]. Computed probabilities of individual commands.
    :param trans_probs: Union[StateMatrix, dict]. Computed probabilities of sequences of commands.
    :param param_cond_cmd_probs: Union[StateMatrix, dict]. Computed probabilities of the parameters conditional on the commands.
    :param value_cond_param_probs: Union[StateMatrix, dict]. Computed probabilities of the values conditional on the parameters.
    :param modellable_params: set. A set of parameters for which the probabilities of their values will be included in the likelihood calculation.
    :param use_start_token: bool. Whether to prepend the start_token to the window before calculating the likelihood.
    :param use_end_token: bool. Whether to append the end_token to the window before calculating the likelihood.
    :param start_token: str. A dummy command to signify the start of the session. Defaults to None.
    :param end_token: str. A dummy command to signify the end of the session. Defaults to None.
    :return: float. The likelihood of the window.
    """

    def _get_prob(table, *keys, default=0.0):
        """
        Safely retrieve probabilities from either nested dicts or matrix-like objects.
        """
        try:
            if isinstance(table, dict):
                cur = table
                for k in keys:
                    cur = cur[k]
                return float(cur)
            else:
                if len(keys) == 1:
                    return float(table[keys[0]])
                elif len(keys) == 2:
                    return float(table[keys[0], keys[1]])
                else:
                    cur = table
                    for k in keys:
                        cur = cur[k]
                    return float(cur)
        except Exception:
            return default

    # Build augmented window if requested
    seq = list(window)
    if use_start_token:
        seq = [start_token] + seq
    if use_end_token:
        seq = seq + [end_token]

    if len(seq) == 0:
        return 0.0

    likelihood = 1.0

    for i, cmd in enumerate(seq):
        # Handle token commands that may be plain strings
        is_token = isinstance(cmd, str)

        if i == 0:
            cmd_name = cmd if is_token else cmd.cmd
            likelihood *= _get_prob(prior_probs, cmd_name, default=0.0)
        else:
            prev = seq[i - 1]
            prev_name = prev if isinstance(prev, str) else prev.cmd
            cmd_name = cmd if is_token else cmd.cmd
            likelihood *= _get_prob(trans_probs, prev_name, cmd_name, default=0.0)

        # Only real commands have parameters/values
        if not is_token:
            params = getattr(cmd, "params", {}) or {}
            for param, value in params.items():
                likelihood *= _get_prob(param_cond_cmd_probs, cmd.cmd, param, default=0.0)

                if param in modellable_params:
                    likelihood *= _get_prob(value_cond_param_probs, param, value, default=0.0)

    return likelihood

    session: List[Cmd],
    prior_probs: Union[StateMatrix, dict],
    trans_probs: Union[StateMatrix, dict],
    param_cond_cmd_probs: Union[StateMatrix, dict],
    value_cond_param_probs: Union[StateMatrix, dict],
    modellable_params: set,
    window_len: int,
    use_start_end_tokens: bool,
    start_token: str = None,
    end_token: str = None,
    use_geo_mean: bool = False,
) -> List[float]:

    """
    This function computes the likelihoods of a sliding window of a specified length in a given session. It uses the input parameters and calculates the likelihood for each window.
    Input-Output Arguments
    :param session: List[Cmd]. A list of Cmd objects representing a session.
    :param prior_probs: Union[StateMatrix, dict]. Computed probabilities of individual commands.
    :param trans_probs: Union[StateMatrix, dict]. Computed probabilities of sequences of commands (length 2).
    :param param_cond_cmd_probs: Union[StateMatrix, dict]. Computed probabilities of the params conditional on the commands.
    :param value_cond_param_probs: Union[StateMatrix, dict]. Computed probabilities of the values conditional on the params.
    :param modellable_params: set. A set of params for which the probabilities of their values will be included in the likelihood calculation.
    :param window_len: int. The length of the sliding window for likelihood calculations.
    :param use_start_end_tokens: bool. If True, start_token and end_token will be added to the session before calculations.
    :param start_token: str. A dummy command to signify the start of the session.
    :param end_token: str. A dummy command to signify the end of the session.
    :param use_geo_mean: bool. If True, each likelihood of the sliding windows will be raised to the power of (1/window_len).
    :return: List[float]. A list of likelihoods for each sliding window.
    """

    def _get_prob(table, *keys, default=0.0):
        """
        Safely fetch probability from either nested dict-like objects or StateMatrix-like objects.
        """
        cur = table
        try:
            for k in keys:
                cur = cur[k]
            return float(cur)
        except Exception:
            pass

        try:
            if len(keys) == 1:
                return float(table.get(keys[0], default))
            if len(keys) == 2:
                row = table.get(keys[0], {})
                if hasattr(row, "get"):
                    return float(row.get(keys[1], default))
            if len(keys) == 3:
                row = table.get(keys[0], {})
                if hasattr(row, "get"):
                    row2 = row.get(keys[1], {})
                    if hasattr(row2, "get"):
                        return float(row2.get(keys[2], default))
        except Exception:
            pass

        return float(default)

    def _cmd_name(cmd):
        for attr in ("cmd", "command", "name"):
            if hasattr(cmd, attr):
                return getattr(cmd, attr)
        return str(cmd)

    def _cmd_params(cmd):
        for attr in ("params", "arguments", "args"):
            if hasattr(cmd, attr):
                val = getattr(cmd, attr)
                if isinstance(val, dict):
                    return val
        return {}

    if window_len <= 0:
        return []

    proc_session = list(session)

    if use_start_end_tokens:
        if start_token is not None:
            proc_session = [start_token] + proc_session
        if end_token is not None:
            proc_session = proc_session + [end_token]

    if len(proc_session) < window_len:
        return []

    likelihoods = []

    for i in range(len(proc_session) - window_len + 1):
        window = proc_session[i : i + window_len]
        likelihood = 1.0

        for j, cmd in enumerate(window):
            cmd_name = _cmd_name(cmd)

            if j == 0:
                likelihood *= _get_prob(prior_probs, cmd_name, default=0.0)
            else:
                prev_cmd_name = _cmd_name(window[j - 1])
                likelihood *= _get_prob(trans_probs, prev_cmd_name, cmd_name, default=0.0)

            params = _cmd_params(cmd)
            for param, value in params.items():
                likelihood *= _get_prob(param_cond_cmd_probs, cmd_name, param, default=0.0)

                if param in modellable_params:
                    likelihood *= _get_prob(
                        value_cond_param_probs, param, value, default=0.0
                    )

        if use_geo_mean and window_len > 0:
            likelihood = likelihood ** (1.0 / window_len)

        likelihoods.append(likelihood)

    return likelihoods

    seq1_counts: Union[StateMatrix, dict],
    seq2_counts: Union[StateMatrix, dict],
    unk_token: str,
) -> Tuple[StateMatrix, StateMatrix]:

    """
    This function computes the probabilities for individual commands and the probabilities for the transitions of commands. It takes the counts of individual commands and sequence commands as input and returns the computed probabilities.
    Input-Output Arguments
    :param seq1_counts: Union[StateMatrix, dict]. The counts of individual commands.
    :param seq2_counts: Union[StateMatrix, dict]. The counts of sequence commands (length 2).
    :param unk_token: str. A dummy command to represent unseen commands.
    :return: Tuple[StateMatrix, StateMatrix]. The computed probabilities for individual commands and sequence commands (length 2).
    """
    # Convert plain dict inputs to StateMatrix if needed
    seq1 = seq1_counts if isinstance(seq1_counts, StateMatrix) else StateMatrix(seq1_counts)
    seq2 = seq2_counts if isinstance(seq2_counts, StateMatrix) else StateMatrix(seq2_counts)

    # Ensure unk_token exists in unigram counts
    if unk_token not in seq1:
        seq1[unk_token] = 0

    # Unigram probabilities
    total_seq1 = sum(seq1.values())
    seq1_probs = StateMatrix()

    if total_seq1 == 0:
        for cmd in seq1:
            seq1_probs[cmd] = 0.0
    else:
        for cmd, count in seq1.items():
            seq1_probs[cmd] = count / total_seq1

    # Bigram / transition probabilities: P(cmd2 | cmd1)
    seq2_probs = StateMatrix()

    for prev_cmd, next_cmds in seq2.items():
        row_total = sum(next_cmds.values()) if hasattr(next_cmds, "values") else 0
        seq2_probs[prev_cmd] = StateMatrix()

        if row_total == 0:
            if hasattr(next_cmds, "items"):
                for next_cmd in next_cmds:
                    seq2_probs[prev_cmd][next_cmd] = 0.0
        else:
            for next_cmd, count in next_cmds.items():
                seq2_probs[prev_cmd][next_cmd] = count / row_total

        # Ensure unk_token transition exists
        if unk_token not in seq2_probs[prev_cmd]:
            seq2_probs[prev_cmd][unk_token] = 0.0

    # Ensure unk_token row exists in transition probabilities
    if unk_token not in seq2_probs:
        seq2_probs[unk_token] = StateMatrix({unk_token: 0.0})
    elif unk_token not in seq2_probs[unk_token]:
        seq2_probs[unk_token][unk_token] = 0.0

    return seq1_probs, seq2_probs

    value_counts: Union[StateMatrix, dict],
    param_value_counts: Union[StateMatrix, dict],
    unk_token: str,
) -> Tuple[StateMatrix, StateMatrix]:

    """
    This function computes the probabilities of individual values and the probabilities of values conditional on a parameter. It takes the counts of individual values and the counts of values conditional on the parameter as input and returns the corresponding probabilities.
    Input-Output Arguments
    :param value_counts: Union[StateMatrix, dict]. The counts of individual values.
    :param param_value_counts: Union[StateMatrix, dict]. The counts of values conditional on the parameter.
    :param unk_token: str. A dummy command to represent an unseen command.
    :return: Tuple[StateMatrix, StateMatrix]. The probabilities of individual values and the probabilities of values conditional on the parameter.
    """
    # Convert inputs to plain dictionaries if needed
    value_counts_dict = dict(value_counts)
    param_value_counts_dict = dict(param_value_counts)

    # Ensure unk_token exists in value counts
    if unk_token not in value_counts_dict:
        value_counts_dict[unk_token] = 0

    # Compute marginal probabilities P(value)
    total_value_count = sum(value_counts_dict.values())
    if total_value_count > 0:
        value_probs = {
            value: count / total_value_count
            for value, count in value_counts_dict.items()
        }
    else:
        value_probs = {value: 0.0 for value in value_counts_dict}

    # Compute conditional probabilities P(value | param)
    param_value_probs = {}
    for param, counts in param_value_counts_dict.items():
        counts_dict = dict(counts)

        # Ensure unk_token exists for each parameter
        if unk_token not in counts_dict:
            counts_dict[unk_token] = 0

        total_param_count = sum(counts_dict.values())
        if total_param_count > 0:
            param_value_probs[param] = {
                value: count / total_param_count
                for value, count in counts_dict.items()
            }
        else:
            param_value_probs[param] = {
                value: 0.0 for value in counts_dict
            }

    return value_probs, param_value_probs

