def display_time(seconds):
    minute = 60
    hour = minute * 60
    day = hour * 24
    month = day * 31
    year = day * 365
    century = year * 100

    if seconds < 1:
        return "less than a second"
    elif seconds < minute:
        base = round(seconds)
        return f"{base} second" if base == 1 else f"{base} seconds"
    elif seconds < hour:
        base = round(seconds / minute)
        return f"{base} minute" if base == 1 else f"{base} minutes"
    elif seconds < day:
        base = round(seconds / hour)
        return f"{base} hour" if base == 1 else f"{base} hours"
    elif seconds < month:
        base = round(seconds / day)
        return f"{base} day" if base == 1 else f"{base} days"
    elif seconds < year:
        base = round(seconds / month)
        return f"{base} month" if base == 1 else f"{base} months"
    elif seconds < century:
        base = round(seconds / year)
        return f"{base} year" if base == 1 else f"{base} years"
    else:
        return "centuries"

