class SSHPacket:
    def check_end(self) -> None:
        """
        This function checks if all the data in the SSHPacket instance has been consumed.
        If there is any remaining data, it raises an error.

        Input-Output Arguments
        :param self: SSHPacket. An instance of the SSHPacket class.
        :return: No return values.
        """
        if hasattr(self, "_idx") and hasattr(self, "_data"):
            if self._idx != len(self._data):
                raise ValueError(
                    f"Packet not fully consumed: {len(self._data) - self._idx} bytes remaining"
                )
        else:
            raise AttributeError("SSHPacket instance is missing required attributes '_idx' or '_data'")

from cryptography.hazmat.primitives import hashes, hmac
from cryptography.hazmat.primitives.cmac import CMAC
from cryptography.hazmat.primitives.ciphers import algorithms
from cryptography.hazmat.primitives.poly1305 import Poly1305


def get_mac(mac_alg: bytes, key: bytes):
    """
    This function returns a MAC (Message Authentication Code) handler object
    that is initialized with the specified key. The MAC handler can be used
    for data signing and verification.

    :param mac_alg: bytes. The algorithm used for the MAC.
    :param key: bytes. The key used to initialize the MAC handler.
    :return: MAC. The MAC handler object.
    """
    alg = mac_alg.decode().upper() if isinstance(mac_alg, bytes) else str(mac_alg).upper()

    if alg in ("HMAC-SHA1", "SHA1", "HMACSHA1"):
        return hmac.HMAC(key, hashes.SHA1())
    elif alg in ("HMAC-SHA224", "SHA224", "HMACSHA224"):
        return hmac.HMAC(key, hashes.SHA224())
    elif alg in ("HMAC-SHA256", "SHA256", "HMACSHA256"):
        return hmac.HMAC(key, hashes.SHA256())
    elif alg in ("HMAC-SHA384", "SHA384", "HMACSHA384"):
        return hmac.HMAC(key, hashes.SHA384())
    elif alg in ("HMAC-SHA512", "SHA512", "HMACSHA512"):
        return hmac.HMAC(key, hashes.SHA512())
    elif alg in ("CMAC-AES", "AES-CMAC", "CMAC"):
        return CMAC(algorithms.AES(key))
    elif alg in ("POLY1305",):
        return Poly1305(key)
    else:
        raise ValueError(f"Unsupported MAC algorithm: {mac_alg!r}")

class SSHKey:
    def convert_to_public(self) -> 'SSHKey':
        """
        This method converts an SSHKey object that contains a private key into one that contains only the corresponding public key. It first decodes asymmetric encryption. Once decrypted, it proceeds to assign a relevant comment and filename to the associated key. Upon completion of these steps, the method returns the processed data as its final output.
        Input-Output Arguments
        :param self: SSHKey. An instance of the SSHKey class.
        :return: SSHKey. The SSHKey object that contains only the corresponding public key.
        """
        public_key = SSHKey()

        if hasattr(self, "private_key") and self.private_key is not None:
            if hasattr(self.private_key, "public_key"):
                public_key.public_key = self.private_key.public_key()
            else:
                public_key.public_key = self.private_key
        elif hasattr(self, "public_key"):
            public_key.public_key = self.public_key
        else:
            raise ValueError("No private or public key data available to convert.")

        if hasattr(self, "comment"):
            public_key.comment = self.comment

        if hasattr(self, "filename"):
            filename = self.filename
            if isinstance(filename, str) and not filename.endswith(".pub"):
                filename = f"{filename}.pub"
            public_key.filename = filename

        return public_key

class SSHKey:
    def verify(self, data: bytes, sig: bytes) -> bool:
        """
        This function verifies an SSH signature of the specified data using the SSHKey instance. It decodes the signature packet, checks if the signature algorithm is supported, and performs the actual verification.
        Input-Output Arguments
        :param self: SSHKey. An instance of the SSHKey class.
        :param data: bytes. The data to be verified.
        :param sig: bytes. The SSH signature to be verified.
        :return: bool. True if the signature is valid, False otherwise.
        """
        try:
            packet = SSHPacket(sig)
            sig_algorithm = packet.get_string()
            sig_blob = packet.get_string()

            # Reject malformed packets with trailing data
            packet.check_end()

            # Ensure the signature algorithm is one this key supports
            if hasattr(self, "sig_algorithms"):
                if sig_algorithm not in self.sig_algorithms:
                    return False
            elif hasattr(self, "algorithm"):
                if sig_algorithm != self.algorithm:
                    return False

            # Delegate to the key-specific verifier
            if hasattr(self, "_verify"):
                return bool(self._verify(data, sig_algorithm, sig_blob))
            elif hasattr(self, "verify_ssh"):
                return bool(self.verify_ssh(data, sig_algorithm, sig_blob))
            else:
                raise NotImplementedError("No signature verification method available")

        except Exception:
            return False

class SSHAuthorizedKeys:
    def validate(self, key: SSHKey, client_host: str, client_addr: str,
                 cert_principals: Optional[Sequence[str]] = None,
                 ca: bool = False) -> Optional[Mapping[str, object]]:

        """
        This function validates whether a public key or certificate authority (CA) is valid for authentication. It checks if the provided key matches any of the entries in the SSHAuthorizedKeys instance and if the match options (client host, client address, and certificate principals) are satisfied.
        Input-Output Arguments
        :param self: SSHAuthorizedKeys. An instance of the SSHAuthorizedKeys class.
        :param key: SSHKey. The public key or CA to validate.
        :param client_host: str. The hostname of the client.
        :param client_addr: str. The IP address of the client.
        :param cert_principals: Optional[Sequence[str]]. A sequence of certificate principals.
        :param ca: bool. Whether the key is a CA or not. Defaults to False.
        :return: Optional[Mapping[str, object]]. The options associated with the matching entry, or None if no match is found.
        """
        for entry in self._entries:
            entry_key = entry.get('key')
            entry_options = entry.get('options', {})

            if entry_key != key:
                continue

            if bool(entry_options.get('cert-authority', False)) != ca:
                continue

            from_option = entry_options.get('from')
            if from_option:
                matched = False
                for pattern in from_option:
                    if pattern == client_host or pattern == client_addr:
                        matched = True
                        break
                if not matched:
                    continue

            principals_option = entry_options.get('principals')
            if principals_option is not None:
                if not cert_principals:
                    continue
                if not any(principal in principals_option for principal in cert_principals):
                    continue

            return entry_options

        return None

class BudgetAccountant:
    def __repr__(self, n_budget_max=5):

        """
        This function returns a string representation of the BudgetAccountant instance. It includes the values of the instance's attributes in the string representation. For epsilon, it is included if it is not equal to infinity.
        For delta, it is included if it differs from the default value of 1. For slack, it is included if it is greater than 0. The function also checks the spent budget. If length of spent budget exceeds a certain maximum of budget, only a subset of its elements is included, followed an additional ellipsis ("...") to indicate truncation and a replacement of "“" with "". All these attributes will then be appended in the format:{"{attribute name}={attribute value}" like "delta=0.3"}. Finally, the output format is "BudgetAccountant({processed attributes separating each element by a comma and a space} )"
        Input-Output Arguments
        :param self: BudgetAccountant. An instance of the BudgetAccountant class.
        :param n_budget_max: Integer. The maximum number of elements to include in the spent budget. Defaults to 5.
        :return: String. The string representation of the BudgetAccountant instance.
        """
        params = []

        if getattr(self, "epsilon", float("inf")) != float("inf"):
            params.append(f"epsilon={self.epsilon}")

        if getattr(self, "delta", 1) != 1:
            params.append(f"delta={self.delta}")

        if getattr(self, "slack", 0) > 0:
            params.append(f"slack={self.slack}")

        spent_budget = getattr(self, "spent_budget", [])
        if spent_budget:
            if len(spent_budget) > n_budget_max:
                budget_repr = repr(spent_budget[:n_budget_max])[:-1] + ", ...]"
            else:
                budget_repr = repr(spent_budget)

            budget_repr = budget_repr.replace("“", "").replace("”", "")
            params.append(f"spent_budget={budget_repr}")

        return f"BudgetAccountant({', '.join(params)})"

import numpy as np


def clip_to_bounds(array, bounds):
    """
    This function clips the examples of a 2-dimensional array to given bounds. It checks if the input array is a numpy array, then it checks the bounds and clips the array accordingly. It first checks that the bounds are indeed tuple and that shape is an integer. If these conditions are not met, the function raises a error of type. It then extracts the lower and upper bounds, ensuring they are in the correct format and adjusting them to be arrays of the specified data type (dtype). The function enforces that the lower and upper bounds must be of the same shape and dimensionality, specifically either scalar or 1-dimensional arrays.

    Input-Output Arguments
    :param array: np.ndarray. The array to be clipped.
    :param bounds: tuple. The bounds of the form (min, max) which the array is to be clipped to. `min` and `max` must be scalar, unless the array is 2-dimensional.
    :return: np.ndarray. The clipped array.
    """
    if not isinstance(array, np.ndarray):
        raise TypeError("`array` must be a numpy array.")

    if not isinstance(bounds, tuple) or len(bounds) != 2:
        raise TypeError("`bounds` must be a tuple of the form (min, max).")

    lower, upper = bounds

    lower = np.asarray(lower, dtype=array.dtype)
    upper = np.asarray(upper, dtype=array.dtype)

    if lower.shape != upper.shape:
        raise ValueError("Lower and upper bounds must have the same shape.")

    if lower.ndim > 1 or upper.ndim > 1:
        raise ValueError("Bounds must be either scalar or 1-dimensional arrays.")

    if array.ndim == 1:
        if lower.ndim != 0 or upper.ndim != 0:
            raise ValueError("For 1-dimensional arrays, bounds must be scalar.")
    elif array.ndim == 2:
        if lower.ndim == 1 and lower.shape[0] != array.shape[1]:
            raise ValueError(
                "For 2-dimensional arrays, 1-dimensional bounds must match the number of columns."
            )
    else:
        raise ValueError("`array` must be either 1-dimensional or 2-dimensional.")

    return np.clip(array, lower, upper)

import unicodedata


def saslprep(s: str) -> str:
    """
    This function implements the SASLprep profile defined in RFC 4013.
    It takes a string as input and applies a series of string preparation
    steps to it.

    Input-Output Arguments
    :param s: String. The input string to be processed.
    :return: String. The processed string after applying the SASLprep profile.
    """

    def _is_non_ascii_space(ch: str) -> bool:
        cp = ord(ch)
        return cp in {
            0x00A0, 0x1680, 0x2000, 0x2001, 0x2002, 0x2003,
            0x2004, 0x2005, 0x2006, 0x2007, 0x2008, 0x2009,
            0x200A, 0x200B, 0x202F, 0x205F, 0x3000,
        }

    def _is_commonly_mapped_to_nothing(ch: str) -> bool:
        cp = ord(ch)
        return cp in {
            0x00AD, 0x034F, 0x1806, 0x180B, 0x180C, 0x180D,
            0x200B, 0x200C, 0x200D, 0x2060, 0xFE00, 0xFE01,
            0xFE02, 0xFE03, 0xFE04, 0xFE05, 0xFE06, 0xFE07,
            0xFE08, 0xFE09, 0xFE0A, 0xFE0B, 0xFE0C, 0xFE0D,
            0xFE0E, 0xFE0F, 0xFEFF,
        }

    def _in_table_a1(ch: str) -> bool:
        # Unassigned code points
        return unicodedata.category(ch) == "Cn"

    def _in_table_c12(ch: str) -> bool:
        # Non-ASCII space characters
        return _is_non_ascii_space(ch)

    def _in_table_c21_c22(ch: str) -> bool:
        cp = ord(ch)
        # ASCII control characters + non-ASCII control characters
        return (0x00 <= cp <= 0x1F) or cp == 0x7F or unicodedata.category(ch) == "Cc"

    def _in_table_c3(ch: str) -> bool:
        # Private use
        return unicodedata.category(ch) == "Co"

    def _in_table_c4(ch: str) -> bool:
        # Non-character code points
        cp = ord(ch)
        return (
            0xFDD0 <= cp <= 0xFDEF
            or (cp & 0xFFFF) in {0xFFFE, 0xFFFF}
        )

    def _in_table_c5(ch: str) -> bool:
        # Surrogate codes
        return 0xD800 <= ord(ch) <= 0xDFFF

    def _in_table_c6(ch: str) -> bool:
        # Inappropriate for plain text
        return ord(ch) in {
            0xFFF9, 0xFFFA, 0xFFFB, 0xFFFC, 0xFFFD
        }

    def _in_table_c7(ch: str) -> bool:
        # Inappropriate for canonical representation
        return ord(ch) in {
            0x2FF0, 0x2FF1, 0x2FF2, 0x2FF3, 0x2FF4,
            0x2FF5, 0x2FF6, 0x2FF7, 0x2FF8, 0x2FF9,
            0x2FFA, 0x2FFB
        }

    def _in_table_c8(ch: str) -> bool:
        # Change display properties or deprecated
        cp = ord(ch)
        return cp in {
            0x0340, 0x0341, 0x200E, 0x200F, 0x202A, 0x202B,
            0x202C, 0x202D, 0x202E, 0x206A, 0x206B, 0x206C,
            0x206D, 0x206E, 0x206F,
        }

    def _in_table_c9(ch: str) -> bool:
        # Tagging characters
        cp = ord(ch)
        return cp == 0xE0001 or 0xE0020 <= cp <= 0xE007F

    def _is_randalcat(ch: str) -> bool:
        bidi = unicodedata.bidirectional(ch)
        return bidi in ("R", "AL")

    def _is_lcat(ch: str) -> bool:
        return unicodedata.bidirectional(ch) == "L"

    # 1. Mapping
    mapped = []
    for ch in s:
        if _is_commonly_mapped_to_nothing(ch):
            continue
        if _in_table_c12(ch):
            mapped.append(" ")
        else:
            mapped.append(ch)
    s = "".join(mapped)

    # 2. Normalize
    s = unicodedata.normalize("NFKC", s)

    # 3. Prohibit
    for ch in s:
        if (
            _in_table_c12(ch)
            or _in_table_c21_c22(ch)
            or _in_table_c3(ch)
            or _in_table_c4(ch)
            or _in_table_c5(ch)
            or _in_table_c6(ch)
            or _in_table_c7(ch)
            or _in_table_c8(ch)
            or _in_table_c9(ch)
        ):
            raise ValueError(f"Prohibited character in SASLprep string: U+{ord(ch):04X}")

    # 4. Check bidi rules
    contains_randal = any(_is_randalcat(ch) for ch in s)
    contains_l = any(_is_lcat(ch) for ch in s)

    if contains_randal:
        if contains_l:
            raise ValueError("String contains both RandALCat and LCat characters")
        if s and not (_is_randalcat(s[0]) and _is_randalcat(s[-1])):
            raise ValueError("String with RandALCat characters must start and end with RandALCat characters")

    # 5. Check for unassigned code points
    for ch in s:
        if _in_table_a1(ch):
            raise ValueError(f"Unassigned code point in SASLprep string: U+{ord(ch):04X}")

    return s

class _FittingTree:
    def fit(self, X, y):

        """
        This function fits a tree to the given training data. It first checks if the tree has been built, and then applies the tree to the input data to determine the leaves. It calculates the unique leaves and initializes an array to store the values for each leaf. It populates the values for the real leaves based on the target vector. It then populates the values for the empty leaves. Finally, it assigns the calculated values to the tree and returns the fitted tree.
        Input-Output Arguments
        :param self: _FittingTree. An instance of the _FittingTree class.
        :param X: array-like. The training vector with shape (n_samples, n_features), where n_samples is the number of samples and n_features is the number of features.
        :param y: array-like. The target vector relative to X with shape (n_samples,).
        :return: The fitted tree.
        """
        if not hasattr(self, "tree_") or self.tree_ is None:
            raise ValueError("The tree has not been built yet.")

        leaves = self.tree_.apply(X)
        unique_leaves = np.unique(leaves)

        values = np.zeros(self.tree_.node_count, dtype=float)

        for leaf in unique_leaves:
            mask = leaves == leaf
            if np.any(mask):
                values[leaf] = np.mean(y[mask])

        for node in range(self.tree_.node_count):
            if values[node] == 0 and getattr(self.tree_, "children_left", None) is not None:
                if self.tree_.children_left[node] == -1 and self.tree_.children_right[node] == -1:
                    values[node] = 0.0

        self.values_ = values
        return self

