def resolve_invite(invite: Union[Invite, str]) -> ResolvedInvite:
    """
    This function resolves an invite from a Discord invite, URL, or code.
    It returns a data class containing the invite code and the event ID.

    Input-Output Arguments
    :param invite: Union[Invite, str]. The invite to resolve.
    :return: ResolvedInvite. A data class containing the invite code and the event ID.
    """
    if isinstance(invite, Invite):
        return ResolvedInvite(code=invite.code, event=invite.scheduled_event_id)

    if not isinstance(invite, str):
        raise TypeError("invite must be of type Invite or str")

    invite = invite.strip()

    # Plain invite code
    if re.fullmatch(r"[A-Za-z0-9-]+", invite):
        return ResolvedInvite(code=invite, event=None)

    parsed = urlparse(invite)

    if not parsed.scheme or not parsed.netloc:
        raise ValueError("Invalid Discord invite")

    host = parsed.netloc.lower()
    path = parsed.path.strip("/")

    valid_hosts = {
        "discord.gg",
        "www.discord.gg",
        "discord.com",
        "www.discord.com",
        "ptb.discord.com",
        "canary.discord.com",
    }

    if host not in valid_hosts:
        raise ValueError("Invalid Discord invite host")

    parts = path.split("/")

    code: Optional[str] = None
    if host.endswith("discord.gg"):
        if len(parts) >= 1 and parts[0]:
            code = parts[0]
    elif len(parts) >= 2 and parts[0] == "invite" and parts[1]:
        code = parts[1]

    if not code:
        raise ValueError("Invalid Discord invite URL")

    query = parse_qs(parsed.query)
    event = query.get("event", [None])[0]

    if event is not None:
        try:
            event = int(event)
        except (TypeError, ValueError):
            raise ValueError("Invalid event ID")

    return ResolvedInvite(code=code, event=event)

class ReilParser:
    def parse(self, instrs):

        """
        This function parses a list of IR instructions. It converts each instruction to lowercase and checks if it is already present in the cache. If not, it parses the instruction and adds it to the cache. It then retrieves the parsed instruction from the cache, clones it, and adds it to the list of parsed instructions. If an error occurs during parsing, an error message is logged.
        Input-Output Arguments
        :param self: ReilParser. An instance of the ReilParser class.
        :param instrs: List of strings. The list of IR instructions to be parsed.
        :return: List of parsed instructions in REIL format.
        """
        instrs_reil = []

        for instr in instrs:
            instr_lower = instr.lower()

            try:
                if instr_lower not in self._cache:
                    self._cache[instr_lower] = self._parse_instr(instr_lower)

                instr_reil = self._cache[instr_lower].clone()
                instrs_reil.append(instr_reil)

            except Exception as e:
                if hasattr(self, "_logger") and self._logger:
                    self._logger.error("Error parsing instruction '%s': %s", instr, e)
                else:
                    print("Error parsing instruction '{}': {}".format(instr, e))

        return instrs_reil

