        for prop_name in getattr(self, "_prop_names", []):
            if hasattr(self, prop_name):
                value = getattr(self, prop_name)
                if value is not None:
                    props[prop_name] = value

        # Add wildcard properties such as data-* and aria-*
        for wildcard_prefix in getattr(self, "_valid_wildcard_attributes", []):
            for key, value in getattr(self, "__dict__", {}).items():
                if key.startswith(wildcard_prefix) and value is not None:
                    props[key] = value

        return {
            "props": props,
            "type": getattr(self, "_type", self.__class__.__name__),
            "namespace": getattr(self, "_namespace", None),
        }

import json


def load_components(metadata_path, namespace="default_namespace"):
    """
    This function loads React component metadata from a JSON file and converts it
    into a format that Dash can parse. It registers the component library for
    index inclusion and then iterates over each component in the metadata,
    extracting the component name and generating a class for each component.
    The generated classes are added to a list and returned.

    Input-Output Arguments
    :param metadata_path: String. The path to the JSON file created by `react-docgen`.
    :param namespace: String. The namespace to register the component library under.
                      It defaults to "default_namespace" if not specified.
    :return: List of component objects. Each component object has keys
             `type`, `valid_kwargs`, and `setup`.
    """
    with open(metadata_path, "r", encoding="utf-8") as f:
        metadata = json.load(f)

    # Normalize metadata into an iterable of component definitions
    if isinstance(metadata, dict):
        # react-docgen output may be either:
        # 1. {ComponentName: {...}}
        # 2. {...single component metadata...}
        if "displayName" in metadata:
            components_meta = [metadata]
        else:
            components_meta = []
            for name, spec in metadata.items():
                if isinstance(spec, dict):
                    spec = dict(spec)
                    spec.setdefault("displayName", name)
                    components_meta.append(spec)
    elif isinstance(metadata, list):
        components_meta = metadata
    else:
        raise ValueError("Unsupported metadata format in JSON file.")

    components = []

    for component_meta in components_meta:
        component_name = component_meta.get("displayName")
        if not component_name:
            continue

        props = component_meta.get("props", {}) or {}
        valid_kwargs = list(props.keys())

        def setup(meta=component_meta, ns=namespace):
            return {
                "namespace": ns,
                "metadata": meta,
            }

        component = {
            "type": component_name,
            "valid_kwargs": valid_kwargs,
            "setup": setup,
        }
        components.append(component)

    return components

