from urllib.parse import urlparse, unquote


def connect(url, unquote_password=False, **connect_params):
    """
    Connect to a database using the given URL and connection parameters. It parses the URL,
    converts it to a dictionary of connection parameters, updates it with additional parameters,
    and then creates an instance of the appropriate database class using the connection parameters.

    Input-Output Arguments
    :param url: String. The URL of the database to connect to.
    :param unquote_password: Bool. Whether to unquote the password in the URL. Defaults to False.
    :param **connect_params: Additional connection parameters as keyword arguments.
    :return: The instance of the database class created using the connection parameters.
    """
    parsed = urlparse(url)

    params = {}

    if parsed.scheme:
        params["scheme"] = parsed.scheme

    if parsed.hostname:
        params["host"] = parsed.hostname

    if parsed.port:
        params["port"] = parsed.port

    if parsed.username:
        params["user"] = parsed.username

    if parsed.password is not None:
        params["password"] = unquote(parsed.password) if unquote_password else parsed.password

    if parsed.path and parsed.path != "/":
        params["database"] = parsed.path.lstrip("/")

    if parsed.query:
        for pair in parsed.query.split("&"):
            if not pair:
                continue
            if "=" in pair:
                key, value = pair.split("=", 1)
            else:
                key, value = pair, ""
            params[key] = value

    params.update(connect_params)

    db_class = params.pop("database_class", None)
    if db_class is None:
        raise ValueError("A 'database_class' must be provided in connect_params or resolvable from the URL.")

    return db_class(**params)

class DataSet:
    def update_cache(self, table=None):
        """
        Update the cache of the DataSet instance based on the given table. If a table is specified,
        it updates the cache for that table and its related tables. If no table is specified, it
        updates the cache for all tables. It generates and updates the models in the cache based on
        the updated cache.

        Input-Output Arguments
        :param self: DataSet. An instance of the DataSet class.
        :param table: String. The name of the table to update the cache for. Defaults to None.
        :return: No return values.
        """
        # Ensure cache containers exist
        if not hasattr(self, "_cache") or self._cache is None:
            self._cache = {}
        if not hasattr(self, "_models") or self._models is None:
            self._models = {}

        # Determine which tables need to be refreshed
        if table is None:
            if hasattr(self, "tables"):
                tables_to_update = list(self.tables)
            elif hasattr(self, "_tables"):
                tables_to_update = list(self._tables)
            elif hasattr(self, "_cache"):
                tables_to_update = list(self._cache.keys())
            else:
                tables_to_update = []
        else:
            tables_to_update = [table]

            # Include related tables if relationship metadata exists
            related = set()
            if hasattr(self, "relations") and isinstance(self.relations, dict):
                related.update(self.relations.get(table, []))
                for t, rels in self.relations.items():
                    if table in rels:
                        related.add(t)
            elif hasattr(self, "_relations") and isinstance(self._relations, dict):
                related.update(self._relations.get(table, []))
                for t, rels in self._relations.items():
                    if table in rels:
                        related.add(t)

            tables_to_update.extend(x for x in related if x not in tables_to_update)

        # Refresh cache for each selected table
        for tbl in tables_to_update:
            data = None

            # Try common hooks/methods for retrieving table data
            if hasattr(self, "load_table") and callable(getattr(self, "load_table")):
                data = self.load_table(tbl)
            elif hasattr(self, "get_table") and callable(getattr(self, "get_table")):
                data = self.get_table(tbl)
            elif hasattr(self, "_load_table") and callable(getattr(self, "_load_table")):
                data = self._load_table(tbl)
            elif hasattr(self, "data") and isinstance(self.data, dict):
                data = self.data.get(tbl)
            elif hasattr(self, "_data") and isinstance(self._data, dict):
                data = self._data.get(tbl)

            self._cache[tbl] = data

        # Regenerate/update models from cache
        for tbl in tables_to_update:
            cached_data = self._cache.get(tbl)

            if hasattr(self, "generate_model") and callable(getattr(self, "generate_model")):
                self._models[tbl] = self.generate_model(tbl, cached_data)
            elif hasattr(self, "_generate_model") and callable(getattr(self, "_generate_model")):
                self._models[tbl] = self._generate_model(tbl, cached_data)
            else:
                # Fallback: store cached data directly as the model
                self._models[tbl] = cached_data

class Signal:
    def disconnect(self, receiver=None, name=None, sender=None):
        """
        Disconnect a receiver from the Signal instance. It removes the receiver from
        the list of receivers and updates the receiver list accordingly in which every
        element format is (name, receiver, sender).

        Input-Output Arguments
        :param self: Signal. An instance of the Signal class.
        :param receiver: Object. The receiver to be disconnected from the Signal instance.
                         Defaults to None.
        :param name: String. The name of the receiver. If not provided, it is inferred
                     from the receiver's name. Defaults to None.
        :param sender: Object. The sender of the signal. If provided, only the receiver
                       with the specified sender will be disconnected. Defaults to None.
        :return: No return values.
        """
        if not hasattr(self, "receivers"):
            self.receivers = []
            return

        if receiver is None and name is None:
            return

        if name is None and receiver is not None:
            name = getattr(receiver, "__name__", None)

        updated_receivers = []
        for rec_name, rec_receiver, rec_sender in self.receivers:
            remove = False

            if sender is None:
                if receiver is not None and rec_receiver == receiver:
                    remove = True
                elif name is not None and rec_name == name:
                    remove = True
            else:
                if receiver is not None and rec_receiver == receiver and rec_sender == sender:
                    remove = True
                elif name is not None and rec_name == name and rec_sender == sender:
                    remove = True

            if not remove:
                updated_receivers.append((rec_name, rec_receiver, rec_sender))

        self.receivers = updated_receivers

class ChangeLog:
    def install(self, model, skip_fields=None, drop=True, insert=True,
                update=True, delete=True, create_table=True):

        """
        This function is used to install a change log for a model. It creates a table for the change log if the "create_table" parameter is set to True. It then generates and executes SQL statements to create triggers for insert, update, and delete actions on the model.
        Input-Output Arguments
        :param self: ChangeLog. An instance of the ChangeLog class.
        :param model: The model for which the change log is being installed.
        :param skip_fields: List of strings. The fields to skip when generating triggers. Defaults to None.
        :param drop: Bool. Whether to drop existing triggers before installing new ones. Defaults to True.
        :param insert: Bool. Whether to create triggers for insert actions. Defaults to True.
        :param update: Bool. Whether to create triggers for update actions. Defaults to True.
        :param delete: Bool. Whether to create triggers for delete actions. Defaults to True.
        :param create_table: Bool. Whether to create a table for the change log. Defaults to True.
        :return: No return values.
        """
        skip_fields = skip_fields or []

        # Create the changelog table if requested.
        if create_table and hasattr(self, "create_table"):
            self.create_table(model)

        # Build trigger names.
        table_name = getattr(model, "_table", None) or getattr(model, "__name__", "model").lower()
        trigger_names = {
            "insert": f"{table_name}_changelog_insert",
            "update": f"{table_name}_changelog_update",
            "delete": f"{table_name}_changelog_delete",
        }

        # Drop existing triggers if requested.
        if drop:
            for action, trigger_name in trigger_names.items():
                if hasattr(self, "_drop_trigger"):
                    self._drop_trigger(model, trigger_name)
                elif hasattr(self, "execute"):
                    self.execute(f"DROP TRIGGER IF EXISTS {trigger_name};")

        # Collect fields to log.
        fields = []
        if hasattr(model, "_meta") and hasattr(model._meta, "fields"):
            for field in model._meta.fields:
                field_name = getattr(field, "name", None)
                if field_name and field_name not in skip_fields:
                    fields.append(field_name)
        elif hasattr(model, "_fields"):
            for field_name in model._fields:
                if field_name not in skip_fields:
                    fields.append(field_name)

        # Generate and install triggers.
        actions = {
            "insert": insert,
            "update": update,
            "delete": delete,
        }

        for action, enabled in actions.items():
            if not enabled:
                continue

            if hasattr(self, "_create_trigger"):
                sql = self._create_trigger(model=model, action=action, fields=fields)
            else:
                ref = "NEW" if action in ("insert", "update") else "OLD"
                field_list = ", ".join(fields)
                value_list = ", ".join(f"{ref}.{f}" for f in fields)

                log_table = getattr(self, "table_name", f"{table_name}_changelog")
                sql = (
                    f"CREATE TRIGGER {trigger_names[action]} "
                    f"AFTER {action.upper()} ON {table_name} "
                    f"FOR EACH ROW "
                    f"INSERT INTO {log_table} (action, {field_list}) "
                    f"VALUES ('{action}', {value_list});"
                )

            if hasattr(self, "execute"):
                self.execute(sql)

class HTMLFrequencyTable:
    def render(self) -> str:
        """
        This function renders an HTML frequency table based on the content provided. It checks if the content is a list of rows or a single row, and then uses a template to generate the HTML code for the frequency table.
        Input-Output Arguments
        :param self: HTMLFrequencyTable. An instance of the HTMLFrequencyTable class.
        :return: str. The rendered HTML code for the frequency table.
        """
        content = self.content

        if content is None:
            rows = []
        elif isinstance(content, list):
            rows = content
        else:
            rows = [content]

        rendered_rows = []
        for row in rows:
            if isinstance(row, (list, tuple)):
                cells = "".join(f"<td>{cell}</td>" for cell in row)
            else:
                cells = f"<td>{row}</td>"
            rendered_rows.append(f"<tr>{cells}</tr>")

        table_body = "".join(rendered_rows)
        return f"<table>{table_body}</table>"

class BaseSummarizer:
    def summarize(
        self, config: Settings, series: pd.Series, dtype: Type[VisionsBaseType]
    ) -> dict:
        """
        This function summarizes a given series of data based on the specified configuration and data type.
        Input-Output Arguments
        :param self: BaseSummarizer. An instance of the BaseSummarizer class.
        :param config: Settings. The configuration settings for the summarization process.
        :param series: pd.Series. The series of data to be summarized.
        :param dtype: Type[VisionsBaseType]. The data type of the series.
        :return: dict. The summary of the data.
        """
        summary = {
            "n": len(series),
            "count": int(series.count()),
            "n_missing": int(series.isna().sum()),
            "p_missing": float(series.isna().mean()) if len(series) > 0 else 0.0,
            "dtype": getattr(dtype, "__name__", str(dtype)),
        }

        if len(series) == 0:
            return summary

        try:
            summary["n_unique"] = int(series.nunique(dropna=True))
        except Exception:
            summary["n_unique"] = None

        try:
            if pd.api.types.is_numeric_dtype(series):
                summary.update(
                    {
                        "mean": float(series.mean()),
                        "std": float(series.std()),
                        "min": float(series.min()),
                        "max": float(series.max()),
                        "sum": float(series.sum()),
                    }
                )
            else:
                mode = series.mode(dropna=True)
                summary["top"] = mode.iloc[0] if not mode.empty else None
                summary["freq"] = (
                    int((series == summary["top"]).sum())
                    if summary["top"] is not None
                    else 0
                )
        except Exception:
            pass

        return summary

