class MusicSource:
    def search(self, keyword, sources_list) -> list:
        """
        This function searches for a keyword in a list of music sources. It creates multiple threads to search for the keyword in each source concurrently. It then sorts and removes duplicates from the search results based on song title, singer, and file size.
        Input-Output Arguments
        :param self: MusicSource. An instance of the MusicSource class.
        :param keyword: String. The keyword to search for in the music sources.
        :param sources_list: List of strings. The list of music sources to search in.
        :return: List of songs. The search results containing songs that match the keyword.
        """

        results = []
        lock = threading.Lock()
        threads = []

        def worker(source):
            try:
                # Assumes each source name maps to a method on this instance
                # such as self.qq(keyword), self.netease(keyword), etc.
                search_func = getattr(self, source, None)
                if callable(search_func):
                    source_results = search_func(keyword)
                    if source_results:
                        with lock:
                            results.extend(source_results)
            except Exception:
                # Ignore failing sources so one bad source does not break all search
                pass

        for source in sources_list:
            t = threading.Thread(target=worker, args=(source,))
            t.start()
            threads.append(t)

        for t in threads:
            t.join()

        def song_key(song):
            if isinstance(song, dict):
                return (
                    song.get("title") or song.get("song") or "",
                    song.get("singer") or song.get("artist") or "",
                    song.get("size") or song.get("filesize") or 0,
                )
            return (
                getattr(song, "title", getattr(song, "song", "")),
                getattr(song, "singer", getattr(song, "artist", "")),
                getattr(song, "size", getattr(song, "filesize", 0)),
            )

        unique = []
        seen = set()

        for song in results:
            key = song_key(song)
            if key not in seen:
                seen.add(key)
                unique.append(song)

        unique.sort(key=song_key)
        return unique

class HMACAlgorithm:
    def prepare_key(self, key: str | bytes) -> bytes:
        """
        This function prepares the key for use in HMAC algorithm. It converts the key to bytes and checks if it is in PEM or SSH format. If it is, it raises an invalid key error
        "The specified key is an asymmetric key or x509 certificate and should not be used as an HMAC secret."
        Otherwise, the key is returned as bytes.

        Input-Output Arguments
        :param self: HMACAlgorithm. An instance of the HMACAlgorithm class.
        :param key: str or bytes. The key to be prepared for HMAC algorithm.
        :return: bytes. The prepared key for HMAC algorithm.
        """
        if isinstance(key, str):
            key_bytes = key.encode("utf-8")
        elif isinstance(key, bytes):
            key_bytes = key
        else:
            raise TypeError("Expected a string value")

        invalid_key_error = (
            "The specified key is an asymmetric key or x509 certificate "
            "and should not be used as an HMAC secret."
        )

        if key_bytes.startswith(b"-----BEGIN ") or key_bytes.startswith(
            (b"ssh-rsa", b"ssh-ed25519", b"ecdsa-sha2-", b"ssh-dss")
        ):
            raise ValueError(invalid_key_error)

        return key_bytes

