# JWKDict = dict[str, Any]

class HMACAlgorithm:
    @staticmethod
    def from_jwk(jwk: str | JWKDict) -> bytes:
        """
        This function takes a JWK (JSON Web Key) as input and returns the corresponding
        HMAC (Hash-based Message Authentication Code) key. It first checks if the input
        is a valid JSON string or dictionary. Then, it verifies if the key type is "oct"
        (indicating HMAC). Finally, it decodes and returns the HMAC key.

        :param jwk: str or JWKDict. The JWK (JSON Web Key) to extract the HMAC key from.
                    It can be either a JSON string or a dictionary.
        :return: bytes. The extracted HMAC key.
        """
        if isinstance(jwk, str):
            try:
                obj = json.loads(jwk)
            except ValueError as e:
                raise ValueError("Key is not valid JSON") from e
        elif isinstance(jwk, dict):
            obj = jwk
        else:
            raise TypeError("JWK must be a string or a dictionary")

        if obj.get("kty") != "oct":
            raise ValueError("Not an HMAC key")

        if "k" not in obj:
            raise ValueError("Key is missing required parameter 'k'")

        k = obj["k"]
        if not isinstance(k, str):
            raise ValueError("Key parameter 'k' must be a string")

        try:
            from base64 import urlsafe_b64decode
            padding = "=" * (-len(k) % 4)
            return urlsafe_b64decode(k + padding)
        except Exception as e:
            raise ValueError("Invalid base64-encoded key") from e

