PATH_CHANGE_TOKEN = object()

def _iterate(current_dict, prefix=""):
    processed = set()

    def full_key(key):
        return f"{prefix}.{key}" if prefix else str(key)

    # 1. Manually sorted keys first
    for key in manually_sorted_keys:
        if key in current_dict and key not in processed:
            value = current_dict[key]
            processed.add(key)

            current_path = full_key(key)
            if isinstance(value, dict):
                if value:
                    yield current_path, PATH_CHANGE_TOKEN
                    yield from _iterate(value, current_path)
                else:
                    yield current_path, value
            else:
                yield current_path, value

    # 2. Non-dictionary values next, sorted by key
    for key in sorted(current_dict.keys()):
        if key in processed:
            continue
        value = current_dict[key]
        if not isinstance(value, dict):
            processed.add(key)
            yield full_key(key), value

    # 3. Dictionary values last, sorted by key
    for key in sorted(current_dict.keys()):
        if key in processed:
            continue
        value = current_dict[key]
        if isinstance(value, dict):
            processed.add(key)
            current_path = full_key(key)
            if value:
                yield current_path, PATH_CHANGE_TOKEN
                yield from _iterate(value, current_path)
            else:
                yield current_path, value

