        """
        for ingredient in self.traverse_ingredients():
            for cfg_name, cfg in ingredient.named_configs.items():
                full_name = (
                    f"{ingredient.path}.{cfg_name}" if ingredient.path else cfg_name
                )
                yield full_name, cfg

class Source:
