class PackageDependency:
    @classmethod
    def create(cls, mod):
        """
        Create a PackageDependency instance based on the given module. It caches
        the correspondence between module names and package names from the
        metadata "top_level.txt" file in the working set. It then creates the
        PackageDependency instance by retrieving the package name and version
        from the cached dictionary.

        :param cls: type. The PackageDependency class.
        :param mod: Module. The module for which the PackageDependency instance
                    is created.
        :return: PackageDependency. The created PackageDependency instance.
        """
        import pkg_resources

        if not hasattr(cls, "_module_to_package"):
            cls._module_to_package = {}

            for dist in pkg_resources.working_set:
                try:
                    if dist.has_metadata("top_level.txt"):
                        for name in dist.get_metadata("top_level.txt").splitlines():
                            name = name.strip()
                            if name:
                                cls._module_to_package[name] = dist.project_name
                except Exception:
                    continue

        module_name = getattr(mod, "__name__", str(mod)).split(".")[0]
        package_name = cls._module_to_package.get(module_name, module_name)

        version = None
        try:
            version = pkg_resources.get_distribution(package_name).version
        except Exception:
            version = getattr(mod, "__version__", None)

        return cls(package_name, version)

