class FunctionBuilder:
        def get_invocation_str(self):

            """
            This function returns the invocation string of a function based on the arguments and keyword-only arguments of the FunctionBuilder instance.
            Input-Output Arguments
            :param self: FunctionBuilder. An instance of the FunctionBuilder class.
            :return: str. The invocation string of the function.
            """
            parts = list(getattr(self, 'args', []))

            varargs = getattr(self, 'varargs', None)
            if varargs:
                parts.append('*' + varargs)

            kwonlyargs = getattr(self, 'kwonlyargs', [])
            if kwonlyargs:
                if not varargs:
                    parts.append('*')
                parts.extend(['{}={}'.format(arg, arg) for arg in kwonlyargs])

            varkw = getattr(self, 'varkw', None)
            if varkw:
                parts.append('**' + varkw)

            return ', '.join(parts)

import os

def load_config_file(filename):
    """
    Load a configuration file by getting the appropriate handler based on the file extension,
    opening the file, and using the handler to load the configuration data.

    Input-Output Arguments
    :param filename: str. The name of the configuration file to load.
    :return: The loaded configuration data.
    """
    _, ext = os.path.splitext(filename)
    ext = ext.lower()

    handlers = {
        ".json": __import__("json"),
        ".yaml": __import__("yaml"),
        ".yml": __import__("yaml"),
        ".toml": __import__("toml"),
    }

    if ext not in handlers:
        raise ValueError(f"Unsupported configuration file extension: {ext}")

    handler = handlers[ext]

    with open(filename, "r", encoding="utf-8") as file:
        if ext == ".json":
            return handler.load(file)
        elif ext in (".yaml", ".yml"):
            return handler.safe_load(file)
        elif ext == ".toml":
            return handler.load(file)

class FunctionBuilder:
    def get_defaults_dict(self):
        """
        This function returns a dictionary that contains the function arguments along with their default values.
        Input-Output Arguments
        :param self: FunctionBuilder. An instance of the FunctionBuilder class.
        :return: dict. A dictionary that contains the function arguments as keys and their default values as values.
        """
        defaults = {}

        args = getattr(self, 'args', [])
        defaults_values = getattr(self, 'defaults', None)

        if defaults_values:
            for arg, value in zip(args[-len(defaults_values):], defaults_values):
                defaults[arg] = value

        kwonlyargs = getattr(self, 'kwonlyargs', [])
        kwonlydefaults = getattr(self, 'kwonlydefaults', None)

        if kwonlydefaults:
            defaults.update(kwonlydefaults)

        return defaults

