            self.index_map[item] = len(self.items)
            self.items.append(item)

class ParsedException:
    @classmethod
    def from_string(cls, tb_str):
        """
        This function parses a traceback and exception from the given text. It expects the text to be decoded, otherwise it will interpret it as UTF-8. It handles different formats of tracebacks and extracts the relevant information such as frames, source lines, exception type, and exception message.
        Input-Output Arguments
        :param cls: Class. The class that this method belongs to.
        :param tb_str: String. The traceback text to parse.
        :return: ParsedException. An instance of the ParsedException class containing the parsed traceback and exception information.
        """
        import re

        if isinstance(tb_str, bytes):
            tb_str = tb_str.decode("utf-8", errors="replace")
        elif tb_str is None:
            tb_str = ""
        else:
            tb_str = str(tb_str)

        lines = tb_str.splitlines()

        # Create instance
        parsed = cls()

        # Ensure expected attributes exist
        if not hasattr(parsed, "frames"):
            parsed.frames = []
        if not hasattr(parsed, "exc_type"):
            parsed.exc_type = None
        if not hasattr(parsed, "exc_msg"):
            parsed.exc_msg = None
        if not hasattr(parsed, "source_lines"):
            parsed.source_lines = []

        frame_re = re.compile(r'^\s*File "(.+?)", line (\d+), in (.+?)\s*$')
        alt_frame_re = re.compile(r'^\s*File "(.+?)", line (\d+)\s*$')

        i = 0
        while i < len(lines):
            line = lines[i]
            m = frame_re.match(line) or alt_frame_re.match(line)
            if m:
                filename = m.group(1)
                lineno = int(m.group(2))
                func = m.group(3) if len(m.groups()) >= 3 else None

                source = None
                if i + 1 < len(lines):
                    next_line = lines[i + 1]
                    if next_line.startswith("    ") or next_line.startswith("\t"):
                        source = next_line.strip()
                        parsed.source_lines.append(source)
                        i += 1

                parsed.frames.append({
                    "filename": filename,
                    "lineno": lineno,
                    "function": func,
                    "source": source,
                })
            i += 1

        # Find exception line from the bottom
        for line in reversed(lines):
            stripped = line.strip()
            if not stripped:
                continue
            if stripped.startswith("Traceback"):
                continue

            if ": " in stripped:
                exc_type, exc_msg = stripped.split(": ", 1)
                parsed.exc_type = exc_type.strip()
                parsed.exc_msg = exc_msg.strip()
                break
            elif re.match(r"^[A-Za-z_][A-Za-z0-9_.]*$", stripped):
                parsed.exc_type = stripped
                parsed.exc_msg = ""
                break

        return parsed

class Table:
    def from_object(cls, data, headers=_MISSING, max_depth=1, metadata=None):

        """
        Create a Table instance from an object.
        Input-Output Arguments
        :param cls: type. The class of the Table instance.
        :param data: object. The data to create the Table from.
        :param headers: Iterable[str]. The headers of the Table. Defaults to _MISSING.
        :param max_depth: Integer. The level to which nested Tables should be created. Defaults to 1.
        :param metadata: Optional. Additional metadata for the Table. Defaults to None.
        :return: Table. The created Table instance.
        """
        if data is None:
            rows = []
            inferred_headers = [] if headers is _MISSING else list(headers)
            return cls(rows, headers=inferred_headers, metadata=metadata)

        def is_mapping(obj):
            return isinstance(obj, dict)

        def is_sequence(obj):
            return isinstance(obj, (list, tuple))

        def object_to_dict(obj):
            if is_mapping(obj):
                return dict(obj)
            if hasattr(obj, "__dict__"):
                return {
                    key: value
                    for key, value in vars(obj).items()
                    if not key.startswith("_")
                }
            return {"value": obj}

        def convert_value(value, depth):
            if depth > 0 and (is_mapping(value) or hasattr(value, "__dict__")):
                return cls.from_object(value, max_depth=depth - 1)
            if depth > 0 and is_sequence(value) and value and all(
                is_mapping(item) or hasattr(item, "__dict__") for item in value
            ):
                return cls.from_object(value, max_depth=depth - 1)
            return value

        if is_mapping(data) or hasattr(data, "__dict__"):
            data = [data]
        elif not is_sequence(data):
            data = [{"value": data}]

        normalized_rows = []
        inferred_headers = []

        for item in data:
            row_dict = object_to_dict(item)
            converted_row = {}

            for key, value in row_dict.items():
                converted_row[key] = convert_value(value, max_depth - 1)
                if key not in inferred_headers:
                    inferred_headers.append(key)

            normalized_rows.append(converted_row)

        final_headers = inferred_headers if headers is _MISSING else list(headers)

        rows = []
        for row_dict in normalized_rows:
            rows.append([row_dict.get(header) for header in final_headers])

        return cls(rows, headers=final_headers, metadata=metadata)

