class Table:
    def to_text(self, with_headers=True, maxlen=None):
        """
        This function returns the textual representation of a Table object. It includes the header row at the top and formats the data in a table-like structure. Each cell is first tried to be converted to a string. If that fails, it is converted to a repr string. If it exceeds the maximum length, it is truncated and an ellipsis is added. The text is padded with spaces to be centered in the cell. Each column is separated by ' | '. The header row is separated from the data by a line of dashes, where the intersection of each column and the header row is '-|-'.
        Input-Output Arguments
        :param self: Table. An instance of the Table class.
        :param with_headers: bool. Whether to include a header row at the top. It defaults to True if not specified.
        :param maxlen: int. The maximum length of data in each cell. It defaults to None if not specified.
        :return: str. The textual representation of the Table object.
        """

        def cell_to_text(value):
            try:
                text = str(value)
            except Exception:
                text = repr(value)

            if maxlen is not None and len(text) > maxlen:
                if maxlen <= 3:
                    text = "." * maxlen
                else:
                    text = text[:maxlen - 3] + "..."
            return text

        headers = list(getattr(self, "headers", []))
        rows = list(getattr(self, "rows", []))

        text_rows = [[cell_to_text(cell) for cell in row] for row in rows]
        text_headers = [cell_to_text(h) for h in headers] if with_headers and headers else []

        ncols = 0
        if text_headers:
            ncols = len(text_headers)
        for row in text_rows:
            ncols = max(ncols, len(row))

        if ncols == 0:
            return ""

        if text_headers:
            text_headers += [""] * (ncols - len(text_headers))
        text_rows = [row + [""] * (ncols - len(row)) for row in text_rows]

        widths = [0] * ncols
        if text_headers:
            for i, cell in enumerate(text_headers):
                widths[i] = max(widths[i], len(cell))
        for row in text_rows:
            for i, cell in enumerate(row):
                widths[i] = max(widths[i], len(cell))

        def format_row(row):
            return " | ".join(cell.center(widths[i]) for i, cell in enumerate(row))

        lines = []

        if text_headers:
            lines.append(format_row(text_headers))
            lines.append("-|-".join("-" * w for w in widths))

        for row in text_rows:
            lines.append(format_row(row))

        return "\n".join(lines)

class Stats:
    def get_histogram_counts(self, bins=None, **kw):

        """
        This function produces a list of (bin, count) pairs that represents a histogram of the Stats object's data using fixed-width bins.

        Input-Output Arguments
        :param self: Stats. An instance of the Stats class.
        :param bins: int or list of float. The maximum number of bins or the list of floating-point bin boundaries. Defaults to the output of Freedman's algorithm.
        :param bin_digits: int. Number of digits used to round down the bin boundaries. Defaults to 1.
        :return: list of (bin, count) pairs. The histogram counts of the Stats object's data.

        """
        import math

        data = list(self)
        if not data:
            return []

        bin_digits = kw.get("bin_digits", 1)

        # If explicit bin boundaries are provided
        if isinstance(bins, (list, tuple)):
            if len(bins) < 2:
                return []
            edges = list(bins)

        else:
            data_min = min(data)
            data_max = max(data)

            # Determine number of bins
            if bins is None:
                # Freedman-Diaconis rule
                sorted_data = sorted(data)
                n = len(sorted_data)

                def percentile(values, p):
                    if len(values) == 1:
                        return values[0]
                    k = (len(values) - 1) * p
                    f = math.floor(k)
                    c = math.ceil(k)
                    if f == c:
                        return values[int(k)]
                    d0 = values[f] * (c - k)
                    d1 = values[c] * (k - f)
                    return d0 + d1

                q1 = percentile(sorted_data, 0.25)
                q3 = percentile(sorted_data, 0.75)
                iqr = q3 - q1

                if iqr == 0:
                    num_bins = 1
                else:
                    bin_width = 2 * iqr / (n ** (1 / 3))
                    if bin_width <= 0:
                        num_bins = 1
                    else:
                        num_bins = max(1, int(math.ceil((data_max - data_min) / bin_width)))
            else:
                num_bins = max(1, int(bins))

            if data_min == data_max:
                edges = [round(data_min, bin_digits), round(data_max + 1, bin_digits)]
            else:
                width = (data_max - data_min) / num_bins
                edges = [round(data_min + i * width, bin_digits) for i in range(num_bins)]
                edges.append(round(data_max, bin_digits))
                if len(edges) < 2 or edges[-1] <= edges[-2]:
                    edges[-1] = edges[-2] + (10 ** -bin_digits)

        counts = [0] * (len(edges) - 1)

        for x in data:
            placed = False
            for i in range(len(edges) - 1):
                left = edges[i]
                right = edges[i + 1]
                if i == len(edges) - 2:
                    if left <= x <= right:
                        counts[i] += 1
                        placed = True
                        break
                else:
                    if left <= x < right:
                        counts[i] += 1
                        placed = True
                        break
            if not placed:
                if x < edges[0]:
                    counts[0] += 1
                elif x > edges[-1]:
                    counts[-1] += 1

        return list(zip(edges[:-1], counts))

