        if hasattr(self, "inverse") and key in self.inverse:
            values = self.inverse.pop(key)
            if newkey in self.inverse:
                self.inverse[newkey].update(values)
            else:
                self.inverse[newkey] = set(values)

            # Update forward mapping for all related values
            if hasattr(self, "data"):
