            addresses = str(bind).split(",")

        return [addr.strip() for addr in addresses if str(addr).strip()]

import errno
import os
import socket
import stat


def create_sockets(conf, log, fds=None):
    """
    This function creates new sockets based on the configured addresses or file
    descriptors. It checks the type of address and creates either a TCP socket
    or a Unix socket accordingly. It also performs some error checking on the
    SSL configuration.

    Input-Output Arguments
    :param conf: The configuration object.
    :param log: The logging object.
    :param fds: List of file descriptors. Optional. Default is None.
    :return: List of socket objects. The created sockets.
    """

    listeners = []

    # Basic SSL sanity checks
    if getattr(conf, "certfile", None) and not getattr(conf, "keyfile", None):
        raise ValueError("certfile specified without keyfile")
    if getattr(conf, "keyfile", None) and not getattr(conf, "certfile", None):
        raise ValueError("keyfile specified without certfile")

    # Reuse already-open file descriptors if provided
    if fds:
        for fd in fds:
            sock = socket.fromfd(fd, socket.AF_INET, socket.SOCK_STREAM)
            listeners.append(sock)
        return listeners

    for addr in conf.address:
        # Unix socket
        if isinstance(addr, str):
            sock = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)

            # Remove stale socket file if present
            if os.path.exists(addr):
                try:
                    mode = os.stat(addr).st_mode
                    if stat.S_ISSOCK(mode):
                        os.remove(addr)
                except OSError:
                    pass

            try:
                sock.bind(addr)
                sock.listen(getattr(conf, "backlog", 2048))
            except OSError:
                sock.close()
                raise

            listeners.append(sock)
            continue

        # TCP socket
        host, port = addr
        family = socket.AF_INET6 if ":" in str(host) else socket.AF_INET
        sock = socket.socket(family, socket.SOCK_STREAM)

        try:
            sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
            if getattr(conf, "reuse_port", False) and hasattr(socket, "SO_REUSEPORT"):
                try:
                    sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEPORT, 1)
                except OSError as e:
                    if e.errno not in (errno.ENOPROTOOPT, errno.EINVAL, errno.EPERM):
                        raise

            sock.bind((host, port))
            sock.listen(getattr(conf, "backlog", 2048))
        except OSError:
            sock.close()
            raise

        listeners.append(sock)

    if log:
        try:
            log.info("Listening at: %s", ", ".join(str(s.getsockname()) for s in listeners))
        except Exception:
            pass

    return listeners

class IterUnreader:
    def chunk(self):

        """
        This function returns the next chunk of data from the iterator. If the iterator is empty, it returns an empty byte string. If the iterator is exhausted, it sets the iterator to None and returns an empty byte string.
        Input-Output Arguments
        :param self: IterUnreader. An instance of the IterUnreader class.
        :return: bytes. The next chunk of data from the iterator.
        """
        if self.iter is None:
            return b""

        try:
            return next(self.iter)
        except StopIteration:
            self.iter = None
            return b""

class FileTokenManager:
    def pre_refresh_callback(self, authorizer):
        """
        This function loads the refresh token from the file and assigns it to the authorizer if it is not already set.
        Input-Output Arguments
        :param self: FileTokenManager. An instance of the FileTokenManager class.
        :param authorizer: The authorizer object that needs to be refreshed.
        :return: No return values.
        """
        if getattr(authorizer, "refresh_token", None):
            return

        token = None

        if hasattr(self, "get_token") and callable(self.get_token):
            token = self.get_token()
        elif hasattr(self, "token_file"):
            try:
                with open(self.token_file, "r") as f:
                    token = f.read().strip()
            except FileNotFoundError:
                token = None

        if token:
            authorizer.refresh_token = token

class JcCli:
    def yaml_out(self) -> str:
        """
        This function returns a YAML formatted string. If the ruamel.yaml library is installed, it uses it to format the string with color codes. If the library is not installed, it falls back to JSON formatting with a warning message.
        Input-Output Arguments
        :param self: JcCli. An instance of the JcCli class.
        :return: str. The YAML formatted string.
        """
        try:
            from io import StringIO
            from ruamel.yaml import YAML

            yaml = YAML()
            yaml.default_flow_style = False

            stream = StringIO()
            yaml.dump(self.data, stream)
            return stream.getvalue()

        except ImportError:
