class Bootstrap:
    @classmethod
    def get_bootstrap_from_recipes(cls, recipes, ctx):
        """
        This function selects a recommended default bootstrap from a list of
        recipes and returns it. It follows a set of rules to determine the
        appropriate bootstrap based on the given recipes.

        Rules:
        - Use the SDL2 bootstrap if there is an sdl2 dependency.
        - Use the webview bootstrap if we depend on a common web recipe.
        - Otherwise fall back to the default bootstrap.

        :param cls: Class. The Bootstrap class.
        :param recipes: List of strings. The list of recipes to consider when
                        selecting the bootstrap.
        :param ctx: Context. The context in which the function is being called.
        :return: Bootstrap. The selected default bootstrap.
        """
        recipes = set(recipes or [])

        # Common web-related recipes that imply the webview bootstrap
        web_recipes = {
            "flask", "django", "bottle", "aiohttp", "fastapi", "tornado"
        }

        if "sdl2" in recipes:
            bootstrap_name = "sdl2"
        elif recipes.intersection(web_recipes):
            bootstrap_name = "webview"
        else:
            bootstrap_name = "default"

        return cls.get_bootstrap(bootstrap_name, ctx)

