            dep_groups.append([dep])

    # Build all dependency combinations for this recipe
    dep_expansions = [[]]
    for group in dep_groups:
        new_expansions = []
        for current in dep_expansions:
            for option in group:
                new_expansions.append(current + [option])
        dep_expansions = new_expansions

    # Add the recipe itself to each dependency expansion
    recipe_expansions = []
    for deps in dep_expansions:
        combo = [recipe_name]
        for dep in deps:
            if dep not in combo:
                combo.append(dep)
        recipe_expansions.append(combo)

    # Merge with previously expanded combinations
    new_expanded = []
    for current in expanded:
        for addition in recipe_expansions:
            merged = list(current)
            for item in addition:
                if item not in merged:
                    merged.append(item)
            new_expanded.append(merged)
    expanded = new_expanded

