# Get set of recipe/dependency names, clean up and add bootstrap deps:

"""
This function takes in a context, a list of recipe/dependency names, an optional bootstrap instance, and an optional blacklist. It performs various operations on the input names to clean them up and add bootstrap dependencies. It then checks for conflicts and generates all possible order graphs based on the names. It converts each order graph into a linear list and sorts them based on preference. Finally, it returns the chosen order, along with the corresponding recipes, python modules, and bootstrap instance.
Input-Output Arguments
:param ctx: The context in which the function is being called.
:param names: List of strings. The recipe/dependency names.
:param bs: Bootstrap instance. An optional bootstrap instance. Defaults to None.
:param blacklist: Set of strings. An optional set of names to be blacklisted. Defaults to None.
:return: Tuple. The chosen order of dependencies, the corresponding recipes, python modules, and bootstrap instance.
"""
if blacklist is None:
    blacklist = set()
else:
    blacklist = set(blacklist)

# Normalize input names
names = [name for name in names if name]
names = list(dict.fromkeys(names))

# Resolve bootstrap if not provided
if bs is None:
    if hasattr(ctx, "bootstrap") and ctx.bootstrap is not None:
        bs = ctx.bootstrap
    elif hasattr(ctx, "get_bootstrap"):
        bs = ctx.get_bootstrap(names)

# Add bootstrap dependencies if available
if bs is not None:
    bootstrap_deps = []
    if hasattr(bs, "recipe_depends"):
        bootstrap_deps = bs.recipe_depends
    elif hasattr(bs, "depends"):
        bootstrap_deps = bs.depends
    names.extend(bootstrap_deps)
    names = list(dict.fromkeys(names))

# Remove blacklisted items
names = [name for name in names if name not in blacklist]

# Resolve recipes/python modules and collect dependency graph
recipes = {}
python_modules = set()
graph = {}

def resolve_deps(dep_name, visiting=None):
    if visiting is None:
        visiting = set()
    if dep_name in graph:
        return
    if dep_name in visiting:
        raise ValueError("Circular dependency detected involving '{}'".format(dep_name))
    visiting.add(dep_name)

    deps = []
    recipe = None

    try:
        if hasattr(ctx, "recipe_build_order"):
            recipe = ctx.recipe_build_order.get_recipe(dep_name, ctx)
        elif hasattr(ctx, "get_recipe"):
            recipe = ctx.get_recipe(dep_name)
        elif "Recipe" in globals():
            recipe = Recipe.get_recipe(dep_name, ctx)
    except Exception:
        recipe = None

    if recipe is not None:
        recipes[dep_name] = recipe
        if hasattr(recipe, "depends"):
            deps = list(recipe.depends)
    else:
        python_modules.add(dep_name)

    deps = [d for d in deps if d not in blacklist]
    graph[dep_name] = deps

    for dep in deps:
        resolve_deps(dep, visiting)

    visiting.remove(dep_name)

for name in names:
    resolve_deps(name)

# Check for simple conflicts if recipes expose them
selected = set(graph.keys())
for recipe in recipes.values():
    conflicts = getattr(recipe, "conflicts", [])
    for conflict in conflicts:
        if conflict in selected:
            raise ValueError(
                "Conflict detected: '{}' conflicts with '{}'".format(
                    getattr(recipe, "name", str(recipe)), conflict
                )
            )

# Topological sort
temporary = set()
permanent = set()
order = []

def visit(node):
    if node in permanent:
        return
    if node in temporary:
        raise ValueError("Circular dependency detected involving '{}'".format(node))
    temporary.add(node)
    for dep in graph.get(node, []):
        visit(dep)
    temporary.remove(node)
    permanent.add(node)
    order.append(node)

for node in graph:
    visit(node)

# Keep only unique entries in final order
order = list(dict.fromkeys(order))

return order, recipes, python_modules, bs

import os
import shutil
import stat


def copy(src, dst):
    """
    This function copies a file or a folder (recursively) from the source path to the destination path.
    It first checks if the source and destination paths are valid and absolute paths. Then, it creates
    the necessary directories in the destination path if they do not exist. If the source is a file,
    it copies the file to the destination. If the source is a folder, it copies the entire folder to
    the destination. If the source is neither a file nor a folder, it raises a ValueError. Finally,
    it sets the appropriate file permissions for the copied file or folder.

    Input-Output Arguments
    :param src: str. The source file or folder path.
    :param dst: str. The destination file or folder path.
    :return: No return values.
    """
    if not isinstance(src, str) or not isinstance(dst, str):
        raise TypeError("Both src and dst must be strings.")

    if not os.path.isabs(src) or not os.path.isabs(dst):
        raise ValueError("Both src and dst must be absolute paths.")

    if not os.path.exists(src):
        raise FileNotFoundError(f"Source path does not exist: {src}")

    def _set_permissions(path):
        if os.path.isfile(path):
            os.chmod(path, stat.S_IRUSR | stat.S_IWUSR | stat.S_IRGRP | stat.S_IROTH)
        elif os.path.isdir(path):
            os.chmod(
                path,
                stat.S_IRUSR | stat.S_IWUSR | stat.S_IXUSR |
                stat.S_IRGRP | stat.S_IXGRP |
                stat.S_IROTH | stat.S_IXOTH
            )
            for root, dirs, files in os.walk(path):
                for d in dirs:
                    os.chmod(
                        os.path.join(root, d),
                        stat.S_IRUSR | stat.S_IWUSR | stat.S_IXUSR |
                        stat.S_IRGRP | stat.S_IXGRP |
                        stat.S_IROTH | stat.S_IXOTH
                    )
                for f in files:
                    os.chmod(
                        os.path.join(root, f),
                        stat.S_IRUSR | stat.S_IWUSR | stat.S_IRGRP | stat.S_IROTH
                    )

    if os.path.isfile(src):
        parent_dir = os.path.dirname(dst)
        if parent_dir:
            os.makedirs(parent_dir, exist_ok=True)
        shutil.copy2(src, dst)
        _set_permissions(dst)

    elif os.path.isdir(src):
        parent_dir = os.path.dirname(dst)
        if parent_dir:
            os.makedirs(parent_dir, exist_ok=True)
        shutil.copytree(src, dst, dirs_exist_ok=True)
        _set_permissions(dst)

    else:
        raise ValueError("Source path is neither a file nor a folder.")

