class IMAPClient:
    def set_quota(self, quotas):
        """
        This function sets one or more quotas on resources in an IMAPClient instance.
        It takes a list of Quota objects as input and constructs the necessary
        arguments to set the quotas. It then sends the SETQUOTA command to the
        IMAP server and returns the parsed response.

        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :param quotas: List of Quota objects. The quotas to be set on resources.
        :return: Parsed server response.
        """
        if quotas is None:
            raise ValueError("quotas must not be None")

        args = []
        for quota in quotas:
            # Expect each quota object to provide a quota root and resource limits
            root = getattr(quota, "root", None)
            if root is None:
                root = getattr(quota, "quota_root", None)
            if root is None:
                raise ValueError("Each quota must define a quota root")

            resources = getattr(quota, "resources", None)
            if resources is None:
                raise ValueError("Each quota must define resources")

            resource_args = []
            if isinstance(resources, dict):
                items = resources.items()
            else:
                items = resources

            for resource, limit in items:
                resource_args.extend([str(resource), str(limit)])

            args.extend([root, f"({' '.join(resource_args)})"])

        typ, data = self._simple_command("SETQUOTA", *args)
        return self._untagged_response(typ, data, "QUOTA")

class IMAPClient:
    def get_quota_root(self, mailbox):

        """
        This function retrieves the quota roots and associated quotas for a given mailbox from the IMAP server. It sends the appropriate IMAP command to the server and parses the response to extract the quota roots and quotas.
        Input-Output Arguments
        :param self: IMAPClient. An instance of the IMAPClient class.
        :param mailbox: String. The name of the mailbox to retrieve the quota roots for.
        :return: Tuple. A tuple containing the MailboxQuotaRoots object, which represents the quota roots, and a list of Quota objects, which represent the associated quotas.
        """
        typ, data = self._simple_command('GETQUOTAROOT', mailbox)
        typ, data = self._untagged_response(typ, data, 'QUOTAROOT')

        quota_roots = None
        quotas = []

        if not data:
            return quota_roots, quotas

        for response in data:
            if not response:
                continue

            # Expected untagged responses may include:
            # ('QUOTAROOT', mailbox, root1, root2, ...)
            # ('QUOTA', root, ((resource, usage, limit), ...))
            if isinstance(response, tuple):
                if len(response) > 0 and response[0] == 'QUOTAROOT':
                    mailbox_name = response[1] if len(response) > 1 else mailbox
                    roots = list(response[2:]) if len(response) > 2 else []
                    quota_roots = MailboxQuotaRoots(mailbox_name, roots)

                elif len(response) > 0 and response[0] == 'QUOTA':
                    root = response[1] if len(response) > 1 else None
                    resources = response[2] if len(response) > 2 else []

                    if resources:
                        for resource in resources:
                            if len(resource) >= 3:
                                quotas.append(Quota(root, resource[0], resource[1], resource[2]))
                    else:
                        quotas.append(Quota(root, None, None, None))

        return quota_roots, quotas

from datetime import date, datetime

def _normalise_search_criteria(criteria, charset=None):
    """
    This function normalizes the search criteria by converting them into a standardized format.
    It handles different types of criteria and converts them accordingly including
    "int, str, datetime, list, tuple, bytes". If no criteria are specified, it raises
    the corresponding error. If no character set is specified, it defaults to "us-ascii".

    Input-Output Arguments
    :param criteria: The search criteria to be normalized. It can be a string, bytes,
                     list, tuple, int, datetime, or date.
    :param charset: The character set to be used for encoding. Defaults to "us-ascii"
                    if not specified.
    :return: A list of normalized search criteria.
    """
    if criteria is None:
        raise ValueError("No search criteria specified")

    if charset is None:
        charset = "us-ascii"

    def _convert(value):
        if value is None:
            raise ValueError("Search criteria contains None")

        if isinstance(value, bytes):
            return value

        if isinstance(value, str):
            return value.encode(charset)

        if isinstance(value, int):
            return str(value).encode("ascii")

        if isinstance(value, datetime):
            return value.strftime("%d-%b-%Y").encode("ascii")

        if isinstance(value, date):
            return value.strftime("%d-%b-%Y").encode("ascii")

        if isinstance(value, (list, tuple)):
            result = []
            for item in value:
                converted = _convert(item)
                if isinstance(converted, list):
                    result.extend(converted)
                else:
                    result.append(converted)
            return result

        raise TypeError(
            "Unsupported search criteria type: {}".format(type(value).__name__)
        )

    normalized = _convert(criteria)
    return normalized if isinstance(normalized, list) else [normalized]

import time


class FixedOffset:
    def __init__(self, offset_minutes: int):
        self.offset_minutes = offset_minutes

    @classmethod
    def for_system(cls) -> "FixedOffset":
        """
        This function returns a FixedOffset instance based on the current working timezone and DST conditions. It checks if the current time is in daylight saving time and if daylight saving time is enabled. If both conditions are true, it sets the offset to the alternate time zone offset. Otherwise, it sets the offset to the default time zone offset.
        Input-Output Arguments
        :param cls: Class. The class object.
        :return: FixedOffset. The created FixedOffset instance.
        """
        if time.daylight and time.localtime().tm_isdst > 0:
            offset_seconds = -time.altzone
        else:
            offset_seconds = -time.timezone
        return cls(offset_seconds // 60)

