class SimpleXMLElement:
    def add_child(self, name, text=None, ns=True):

        """
        This function adds a child tag to an XML node. It takes the name of the child tag (name), an optional text content (text), and a namespace indicator (ns). Depending on the namespace information provided, it creates a new XML element with the specified name and namespace and appends it as a child to the current node. If text content is provided, it is added as either a CDATA section or a text node to the new child element. The function then returns a new SimpleXMLElement representing the added child element along with the updated XML document and namespace information.
        Input-Output Arguments
        :param self: SimpleXMLElement. An instance of the SimpleXMLElement class.
        :param name: String. The name of the child tag to be added.
        :param text: String or CDATASection. The text content of the child tag. It can be a regular string or a CDATASection object.
        :param ns: Bool or String. Whether to add a namespace to the child tag. If True, the namespace is added based on the instance's namespace. If False or the instance has no namespace, the child tag is added without a namespace. If a string is provided, it is used as the namespace for the child tag.
        :return: SimpleXMLElement. A new SimpleXMLElement instance representing the added child tag.
        """
        # Resolve namespace to use for the child
        namespace = None
        if ns is True:
            namespace = getattr(self, "ns", None)
        elif isinstance(ns, str):
            namespace = ns

        # Create the child element, with namespace if available
        if namespace:
            child = self.document.createElementNS(namespace, name)
        else:
            child = self.document.createElement(name)

        # Append text content if provided
        if text is not None:
            if hasattr(text, "nodeType"):
                text_node = text
            elif text.__class__.__name__ == "CDATASection":
                text_node = self.document.createCDATASection(str(text))
            else:
                text_node = self.document.createTextNode(str(text))
            child.appendChild(text_node)

        # Append child to current element
        self.node.appendChild(child)

        # Return wrapped child element
        return self.__class__(child, self.document, namespace)

class SimpleXMLElement:
    def as_xml(self, filename=None, pretty=False):
        """
        This function returns the XML representation of the document. If the "pretty" parameter is set to False, it returns the XML representation without any formatting. If "pretty" is set to True, it returns the XML representation with indentation and line breaks for better readability.
        Input-Output Arguments
        :param self: SimpleXMLElement. An instance of the SimpleXMLElement class.
        :param filename: String [optional]. The name of the file to save the XML representation. Defaults to None.
        :param pretty: Bool. Whether to format the XML representation with indentation and line breaks. Defaults to False.
        :return: String. The XML representation of the document.
        """
        import xml.etree.ElementTree as ET

        def _indent(elem, level=0):
            i = "\n" + level * "  "
            if len(elem):
                if not elem.text or not elem.text.strip():
                    elem.text = i + "  "
                for child in elem:
                    _indent(child, level + 1)
                if not elem[-1].tail or not elem[-1].tail.strip():
                    elem[-1].tail = i
            if level and (not elem.tail or not elem.tail.strip()):
                elem.tail = i

        # Try to locate the underlying XML element on common attribute names.
        root = None
        for attr in ("element", "_element", "root", "_root"):
            if hasattr(self, attr):
                root = getattr(self, attr)
                break

        if root is None:
            raise AttributeError(
                "SimpleXMLElement instance does not contain an XML root element."
            )

        if pretty:
            _indent(root)

        xml_string = ET.tostring(root, encoding="unicode")

        if filename is not None:
            with open(filename, "w", encoding="utf-8") as f:
                f.write(xml_string)

        return xml_string

from html.parser import HTMLParser
from typing import List, Tuple

# Assumes TypeMessageEntity and the concrete MessageEntity* classes
# are already available in the surrounding codebase.

def parse(html: str) -> Tuple[str, List[TypeMessageEntity]]:
    """
    This function parses the given HTML message and returns its stripped
    representation along with a list of the MessageEntity objects that were found.

    :param html: str. The HTML message to be parsed.
    :return: Tuple[str, List[TypeMessageEntity]]. A tuple consisting of the
             stripped message and a list of MessageEntity objects.
    """

    class _HTMLToTelegramParser(HTMLParser):
        def __init__(self):
            super().__init__(convert_charrefs=True)
            self.text_parts: List[str] = []
            self.entities: List[TypeMessageEntity] = []
            self.stack = []

        def _offset(self) -> int:
            return len("".join(self.text_parts))

        def handle_starttag(self, tag, attrs):
            attrs = dict(attrs)
            offset = self._offset()

            if tag in ("b", "strong"):
                self.stack.append(("bold", offset, attrs))
            elif tag in ("i", "em"):
                self.stack.append(("italic", offset, attrs))
            elif tag == "u":
                self.stack.append(("underline", offset, attrs))
            elif tag in ("s", "strike", "del"):
                self.stack.append(("strike", offset, attrs))
            elif tag == "code":
                self.stack.append(("code", offset, attrs))
            elif tag == "pre":
                self.stack.append(("pre", offset, attrs))
            elif tag == "a":
                self.stack.append(("text_link", offset, attrs))
            elif tag == "blockquote":
                self.stack.append(("blockquote", offset, attrs))
            elif tag == "br":
                self.text_parts.append("\n")

        def handle_endtag(self, tag):
            offset = self._offset()

            tag_map = {
                "b": "bold",
                "strong": "bold",
                "i": "italic",
                "em": "italic",
                "u": "underline",
                "s": "strike",
                "strike": "strike",
                "del": "strike",
                "code": "code",
                "pre": "pre",
                "a": "text_link",
                "blockquote": "blockquote",
            }

            entity_type = tag_map.get(tag)
            if not entity_type:
                return

            for i in range(len(self.stack) - 1, -1, -1):
                kind, start, attrs = self.stack[i]
                if kind == entity_type:
                    self.stack.pop(i)
                    length = offset - start
                    if length <= 0:
                        return

                    if kind == "bold":
                        self.entities.append(MessageEntityBold(start, length))
                    elif kind == "italic":
                        self.entities.append(MessageEntityItalic(start, length))
                    elif kind == "underline":
                        self.entities.append(MessageEntityUnderline(start, length))
                    elif kind == "strike":
                        self.entities.append(MessageEntityStrike(start, length))
                    elif kind == "code":
                        self.entities.append(MessageEntityCode(start, length))
                    elif kind == "pre":
                        language = attrs.get("language") or attrs.get("class", "")
                        self.entities.append(MessageEntityPre(start, length, language=language))
                    elif kind == "text_link":
                        url = attrs.get("href", "")
                        self.entities.append(MessageEntityTextUrl(start, length, url=url))
                    elif kind == "blockquote":
                        self.entities.append(MessageEntityBlockquote(start, length))
                    return

        def handle_data(self, data):
            self.text_parts.append(data)

        def handle_entityref(self, name):
            from html import unescape
            self.text_parts.append(unescape(f"&{name};"))

        def handle_charref(self, name):
            from html import unescape
            self.text_parts.append(unescape(f"&#{name};"))

    parser = _HTMLToTelegramParser()
    parser.feed(html)
    parser.close()

    text = "".join(parser.text_parts)
    parser.entities.sort(key=lambda e: (e.offset, e.length))
    return text, parser.entities

from html import escape
from typing import Iterable

def unparse(text: str, entities: Iterable[TypeMessageEntity]) -> str:
    """
    This function takes a normal text and a list of MessageEntity objects and converts them into HTML representation. It checks for special cases, such as empty text or the absence of entities, and utilizes a dictionary to determine HTML formatting for different message entity types. The function handles surrogate pairs and generates the final HTML output by combining formatted text and escaped portions. The goal is to reverse the operation of a parser, producing HTML from plain text and associated entities.
    Input-Output Arguments
    :param text: str. The text to be converted into HTML.
    :param entities: Iterable[TypeMessageEntity]. The list of MessageEntity objects applied to the text.
    :return: str. The HTML representation of the text with applied formatting based on the entities.
    """
    if not text:
        return ""

    entities = list(entities or [])
    if not entities:
        return escape(text)

    # Telegram-style entities use UTF-16 code unit offsets, so work on a
    # surrogate-pair representation to preserve correct slicing.
    def _add_surrogates(s: str) -> str:
        return "".join(
            c if ord(c) < 0x10000 else c.encode("utf-16-le").decode("latin-1")
            for c in s
        )

    def _del_surrogates(s: str) -> str:
        return s.encode("latin-1").decode("utf-16-le")

    text = _add_surrogates(text)

    open_tags = {}
    close_tags = {}

    for entity in entities:
        start = entity.offset
        end = entity.offset + entity.length

        if isinstance(entity, MessageEntityBold):
            open_tag, close_tag = "<strong>", "</strong>"
        elif isinstance(entity, MessageEntityItalic):
            open_tag, close_tag = "<em>", "</em>"
        elif isinstance(entity, MessageEntityCode):
            open_tag, close_tag = "<code>", "</code>"
        elif isinstance(entity, MessageEntityPre):
            language = getattr(entity, "language", "") or ""
            if language:
                open_tag = f'<pre><code class="language-{escape(language, quote=True)}">'
                close_tag = "</code></pre>"
            else:
                open_tag, close_tag = "<pre>", "</pre>"
        elif isinstance(entity, MessageEntityUnderline):
            open_tag, close_tag = "<u>", "</u>"
        elif isinstance(entity, MessageEntityStrike):
            open_tag, close_tag = "<del>", "</del>"
        elif isinstance(entity, MessageEntityBlockquote):
            open_tag, close_tag = "<blockquote>", "</blockquote>"
        elif isinstance(entity, MessageEntitySpoiler):
            open_tag, close_tag = '<span class="tg-spoiler">', "</span>"
        elif isinstance(entity, MessageEntityTextUrl):
            url = escape(entity.url, quote=True)
            open_tag, close_tag = f'<a href="{url}">', "</a>"
        elif isinstance(entity, MessageEntityUrl):
            url = escape(_del_surrogates(text[start:end]), quote=True)
            open_tag, close_tag = f'<a href="{url}">', "</a>"
        elif isinstance(entity, MessageEntityEmail):
            email = escape(_del_surrogates(text[start:end]), quote=True)
            open_tag, close_tag = f'<a href="mailto:{email}">', "</a>"
        elif isinstance(entity, MessageEntityMentionName):
            user_id = getattr(entity, "user_id", None)
            open_tag, close_tag = f'<a href="tg://user?id={user_id}">', "</a>"
        elif isinstance(entity, InputMessageEntityMentionName):
            user_id = getattr(entity, "user_id", None)
            if hasattr(user_id, "user_id"):
                user_id = user_id.user_id
            open_tag, close_tag = f'<a href="tg://user?id={user_id}">', "</a>"
        else:
            continue

        open_tags.setdefault(start, []).append(open_tag)
        close_tags.setdefault(end, []).append(close_tag)

    result = []
    last = 0

    boundaries = sorted(set(open_tags.keys()) | set(close_tags.keys()) | {0, len(text)})

    for pos in boundaries:
        if pos > last:
            result.append(escape(_del_surrogates(text[last:pos])))

        if pos in close_tags:
            result.extend(reversed(close_tags[pos]))
        if pos in open_tags:
            result.extend(open_tags[pos])

        last = pos

    return "".join(result)

from datetime import datetime, date

def iso8601_date(d):
    """
    This function takes a date object and returns a string representation of the date in the format "YYYY-MM-DD". If the input is not a string, datetime, or date object, it returns None.
    Input-Output Arguments
    :param d: The date object to be converted to a string representation.
    :return: str or None. The string representation of the date in the format "YYYY-MM-DD", or None if the input is not a string, datetime, or date object.
    """
    if isinstance(d, str):
        return d
    if isinstance(d, datetime):
        return d.date().isoformat()
    if isinstance(d, date):
        return d.isoformat()
    return None

from datetime import datetime, date

def iso8601_datetime(d):
    """
    This function takes a date object and returns a string representation
    of the date in the format "%Y-%m-%dT%H:%M:%SZ" that is compatible
    with the Twilio API. If the input is not a string, datetime, or date
    object, it returns None.

    Input-Output Arguments
    :param d: The date object to be converted to a string representation.
    :return: String. The string representation of the date in the format
             "YYYY-MM-DDTHH:MM:SSZ" or None if the input is not a valid
             date object.
    """
    if isinstance(d, str):
        return d
    elif isinstance(d, datetime):
        return d.strftime("%Y-%m-%dT%H:%M:%SZ")
    elif isinstance(d, date):
        return datetime(d.year, d.month, d.day).strftime("%Y-%m-%dT%H:%M:%SZ")
    else:
        return None

class VoiceResponse:
    def say(self, message=None, voice=None, loop=None, language=None, **kwargs):
        """
        This function creates a `<Say>` element for a VoiceResponse object. It takes in parameters such as the message to say, the voice to use, the number of times to loop the message, the language of the message, and additional attributes. It then returns the created `<Say>` element.
        Input-Output Arguments
        :param self: VoiceResponse. An instance of the VoiceResponse class.
        :param message: String. The message to say.
        :param voice: String. The voice to use.
        :param loop: Integer. The number of times to loop the message.
        :param language: String. The language of the message.
        :param kwargs: Additional attributes.
        :return: `<Say>` element. The created `<Say>` element.
        """
        attrs = {}

        if voice is not None:
            attrs["voice"] = voice
        if loop is not None:
            attrs["loop"] = loop
        if language is not None:
            attrs["language"] = language

        attrs.update(kwargs)

        say_element = {
            "tag": "Say",
            "attributes": attrs,
            "message": message
        }

        if not hasattr(self, "_elements"):
            self._elements = []
        self._elements.append(say_element)

        return say_element

class ClientCapabilityToken:
    def allow_client_incoming(self, client_name):
        """
        This function allows the user of the ClientCapabilityToken to accept incoming connections.
        It sets the client name and adds the corresponding capability to the capabilities dictionary.

        Input-Output Arguments
        :param self: ClientCapabilityToken. An instance of the ClientCapabilityToken class.
        :param client_name: String. The name of the client to accept calls from.
        :return: No return values.
        """
        self.client_name = client_name
        if not hasattr(self, 'capabilities'):
            self.capabilities = {}
        self.capabilities["incoming"] = {"clientName": client_name}

class ClientCapabilityToken:
    def __init__(self):
        self.capabilities = {}

    def allow_event_stream(self, **kwargs):
        """
        This function allows the user of the ClientCapabilityToken instance to access their event stream.
        It creates a scope URI with the necessary parameters and adds it to the capabilities
        dictionary of the instance.

        Input-Output Arguments
        :param self: ClientCapabilityToken. An instance of the ClientCapabilityToken class.
        :param kwargs: Keyword arguments that can be used to specify additional parameters
                       for the event stream.
        :return: No return values.
        """
        scope = "scope:event-stream"

        if kwargs:
            params = "&".join(f"{key}={value}" for key, value in kwargs.items())
            scope = f"{scope}?{params}"

        self.capabilities[scope] = {}

class ClientCapabilityToken:
    def _generate_payload(self):

        """
        This function generates the payload for the ClientCapabilityToken. It checks if the "outgoing" capability is present in the capabilities dictionary and if the client name is not None. If both conditions are met, it adds a parameter "clientName" with the value of the client name to the "outgoing" capability. Then, it creates a list of payload values on each capability in the capabilities dictionary. Finally, it returns a dictionary with a single key "scope" and the value being a string of all the scope_uris joined by a space.
        Input-Output Arguments
        :param self: ClientCapabilityToken. An instance of the ClientCapabilityToken class.
        :return: Dictionary. The generated payload for the ClientCapabilityToken.
        """
        if "outgoing" in self.capabilities and self.client_name is not None:
            self.capabilities["outgoing"].params["clientName"] = self.client_name

        scope_uris = [
            capability.payload()
            for capability in self.capabilities.values()
        ]

        return {"scope": " ".join(scope_uris)}

class ScopeURI:
    def to_payload(self):
        """
        This function converts the instance into a payload string. It first checks if there are any parameters in the instance. If there are, it sorts the parameters alphabetically and encodes them. Then, it constructs the parameter string by adding a "?" at the beginning. If there are no parameters, an empty string is used. Finally, it returns the payload string by formatting the service, privilege, and parameter string into a specific format - "scope:{service}:{privilege}{parameter string}".
        Input-Output Arguments
        :param self: ScopeURI. An instance of the ScopeURI class.
        :return: String.
        """
        if getattr(self, "parameters", None):
            parameter_string = "?" + "&".join(
                f"{key}={self.parameters[key]}"
                for key in sorted(self.parameters)
            )
        else:
            parameter_string = ""

        return f"scope:{self.service}:{self.privilege}{parameter_string}"

