import subprocess
from typing import Any


def open_media(controller: Any, tool: str, media_path: str) -> None:
    """
    This function is a helper function that opens a media file using a specified tool.
    It creates a command to run the tool with the given media file path, and then
    executes the command using the `subprocess.run()` function. It checks the exit
    status of the process and reports any errors to the controller.

    Input-Output Arguments
    :param controller: Any. The controller object that handles error reporting.
    :param tool: str. The name or path of the tool to be used to open the media file.
    :param media_path: str. The path of the media file to be opened.
    :return: No return values.
    """
    command = [tool, media_path]

    try:
        result = subprocess.run(command, check=False)
        if result.returncode != 0:
            if hasattr(controller, "report_error"):
                controller.report_error(
                    f"Failed to open media '{media_path}' with '{tool}'. "
                    f"Exit status: {result.returncode}"
                )
    except FileNotFoundError:
        if hasattr(controller, "report_error"):
            controller.report_error(f"Tool not found: '{tool}'")
    except Exception as exc:
        if hasattr(controller, "report_error"):
            controller.report_error(
                f"An error occurred while opening media '{media_path}': {exc}"
            )

class WriteBox:
    def update_recipients(self, write_box: ReadlineEdit) -> None:
        """
        Update the recipients of the WriteBox instance based on the input from the
        ReadlineEdit instance. It extracts the recipient emails from the input text
        and sets the corresponding user IDs in the WriteBox instance.

        Input-Output Arguments
        :param self: WriteBox. An instance of the WriteBox class.
        :param write_box: ReadlineEdit. An instance of the ReadlineEdit class that
                          contains the input text.
        :return: No return values.
        """
        text = write_box.text().strip()
        if not text:
            self.recipient_ids = []
            return

        recipients = []
        for part in text.split(","):
            email = part.strip()
            if not email:
                continue

            user_id = None

            # Try common lookup patterns.
            if hasattr(self, "users_by_email") and isinstance(self.users_by_email, dict):
                user_id = self.users_by_email.get(email)

            elif hasattr(self, "users") and isinstance(self.users, dict):
                user = self.users.get(email)
                if isinstance(user, dict):
                    user_id = user.get("id")
                else:
                    user_id = getattr(user, "id", None)

            elif hasattr(self, "get_user_id_by_email") and callable(self.get_user_id_by_email):
                user_id = self.get_user_id_by_email(email)

            if user_id is not None:
                recipients.append(user_id)

        self.recipient_ids = recipients

class WriteBox:
    def _topic_box_autocomplete(self, text: str, state: Optional[int]) -> Optional[str]:
        """
        This function provides autocomplete suggestions for a given text input based on the available topics in a stream. It retrieves the list of topic names from the model and matches them with the input text to generate typeaheads. It then processes the typeaheads and returns them as suggestions.
        Input-Output Arguments
        :param self: WriteBox. An instance of the WriteBox class.
        :param text: str. The input text for which autocomplete suggestions are required.
        :param state: Optional[int]. The state of the autocomplete process. Defaults to None.
        :return: Optional[str]. The generated autocomplete suggestions for the input text.
        """
        if state is None:
            state = 0

        if not text:
            return None

        # Get available topic names from the model if present.
        topic_names = []
        model = getattr(self, "model", None)
        if model is not None:
            if hasattr(model, "stream_topics"):
                stream_topics = model.stream_topics()
                if isinstance(stream_topics, dict):
                    topic_names = list(stream_topics.keys())
                else:
                    topic_names = [
                        getattr(topic, "name", str(topic))
                        for topic in stream_topics
                    ]
            elif hasattr(model, "topics"):
                topics = model.topics
                if isinstance(topics, dict):
                    topic_names = list(topics.keys())
                else:
                    topic_names = [
                        getattr(topic, "name", str(topic))
                        for topic in topics
                    ]

        # Match topics against the entered text.
        lowered_text = text.lower()
        matches = sorted(
            [topic for topic in topic_names if topic.lower().startswith(lowered_text)]
        )

        if state < len(matches):
            return matches[state]

        return None

class WriteBox:
    def _stream_box_autocomplete(
        self, text: str, state: Optional[int]
    ) -> Optional[str]:

        """
        This function is a private method that is used for stream box autocomplete. It takes a text and a state as input parameters and returns a string or None. It retrieves a list of stream names from the view's corresponding attributes. Then, it matches the input text with the stream names. Finally, it processes the matched streams and returns the result.
        Input-Output Arguments
        :param self: WriteBox. An instance of the WriteBox class.
        :param text: String. The input text to match with stream names.
        :param state: Optional integer. The state of the autocomplete. Defaults to None.
        :return: Optional string. The processed typeaheads or None.
        """
        # Get available stream names from the view if present.
        stream_names = []
        if hasattr(self, "view"):
            if hasattr(self.view, "stream_names"):
                stream_names = list(self.view.stream_names)
            elif hasattr(self.view, "streams"):
                streams = self.view.streams
                if isinstance(streams, dict):
                    stream_names = list(streams.keys())
                else:
                    stream_names = [
                        getattr(stream, "name", str(stream)) for stream in streams
                    ]

        # Normalize and filter matches.
        text = text or ""
        matches = sorted(
            [name for name in stream_names if name.startswith(text)],
            key=str.lower,
        )

        # Return the match for the requested state, if any.
        if state is None:
            state = 0

        if 0 <= state < len(matches):
            return matches[state]

        return None

class WriteBox:
    def generic_autocomplete(self, text: str, state: Optional[int]) -> Optional[str]:
        """
        This function provides generic autocomplete functionality for a given text. It checks for specific prefixes in the text and calls the corresponding autocomplete function based on the prefix. It then processes the autocomplete suggestions and returns the updated text with the autocomplete suggestion.
        Input-Output Arguments
        :param self: WriteBox. An instance of the WriteBox class.
        :param text: String. The input text to be autocompleted.
        :param state: Optional[int]. The state of the autocomplete. Defaults to None.
        :return: Optional[str]. The updated text with the autocomplete suggestion.
        """
        if text is None:
            return None

        state = 0 if state is None else state

        # Map prefixes to their corresponding autocomplete handlers.
        # Each handler is expected to return an iterable of suggestions
        # or support indexing by state.
        handlers = {
            "@": getattr(self, "autocomplete_mentions", None),
            "#": getattr(self, "autocomplete_tags", None),
            "/": getattr(self, "autocomplete_commands", None),
        }

        matched_prefix = None
        matched_handler = None

        for prefix, handler in handlers.items():
            if text.startswith(prefix) and callable(handler):
                matched_prefix = prefix
                matched_handler = handler
                break

        if matched_handler is None:
            generic_handler = getattr(self, "autocomplete", None)
            if not callable(generic_handler):
                return None
            suggestions = generic_handler(text)
            prefix_text = ""
        else:
            suggestions = matched_handler(text[len(matched_prefix):])
            prefix_text = matched_prefix

        if suggestions is None:
            return None

        try:
            suggestion = suggestions[state]
        except (IndexError, TypeError, KeyError):
            try:
                suggestions = list(suggestions)
                suggestion = suggestions[state]
            except (IndexError, TypeError):
                return None

        if suggestion is None:
            return None

        return f"{prefix_text}{suggestion}"

class TopButton:
    def update_widget(
        self, count_text: Tuple[Optional[str], str], text_color: Optional[str]
    ) -> Any:
        """
        Update the widget with the given count text and text color. It sets the prefix, label, suffix, and text color of the widget based on the input parameters according to the prefix format.
        Input-Output Arguments
        :param self: TopButton. An instance of the TopButton class.
        :param count_text: Tuple of Optional[str] and str. The count text to be displayed on the widget. The first element is an optional prefix, and the second element is the main count text.
        :param text_color: Optional[str]. The color of the text on the widget. If not specified, the default color is used.
        :return: Any. No specific return value.
        """
        prefix, label = count_text

        # Reset displayed parts
        if hasattr(self, "prefix_label"):
            self.prefix_label.setText("")
        if hasattr(self, "label"):
            self.label.setText("")
        if hasattr(self, "suffix_label"):
            self.suffix_label.setText("")

        # Apply text color if supported
        if text_color is not None:
            style = f"color: {text_color};"
            if hasattr(self, "prefix_label"):
                self.prefix_label.setStyleSheet(style)
            if hasattr(self, "label"):
                self.label.setStyleSheet(style)
            if hasattr(self, "suffix_label"):
                self.suffix_label.setStyleSheet(style)

        # Set text according to prefix format
        if prefix:
            if "{}" in prefix:
                before, after = prefix.split("{}", 1)
                if hasattr(self, "prefix_label"):
                    self.prefix_label.setText(before)
                if hasattr(self, "label"):
                    self.label.setText(label)
                if hasattr(self, "suffix_label"):
                    self.suffix_label.setText(after)
            else:
                if hasattr(self, "prefix_label"):
                    self.prefix_label.setText(prefix)
                if hasattr(self, "label"):
                    self.label.setText(label)
        else:
            if hasattr(self, "label"):
                self.label.setText(label)

class MessageLinkButton:
    def _parse_narrow_link(cls, link: str) -> ParsedNarrowLink:
        """
        This function parses a given link and returns a dictionary with narrow parameters
        for supported links. If the link does not match any of the supported formats,
        an empty dictionary is returned.

        We expect the fragment to be one of the following types:
        a. narrow/stream/[{stream_id}-]{stream-name}
        b. narrow/stream/[{stream_id}-]{stream-name}/near/{message_id}
        c. narrow/stream/[{stream_id}-]{stream-name}/topic/{encoded.20topic.20name}
        d. narrow/stream/[{stream_id}-]{stream-name}/topic/{encoded.20topic.20name}/near/{message_id}

        :param cls: MessageLinkButton. The MessageLinkButton class.
        :param link: String. The link to be parsed.
        :return: ParsedNarrowLink. A dictionary with narrow parameters for supported links.
        """
        from urllib.parse import urlparse, unquote

        parsed = urlparse(link)
        fragment = parsed.fragment or ""

        if not fragment.startswith("narrow/stream/"):
            return {}

        parts = fragment.split("/")

        # Expected minimum: narrow/stream/{stream}
        if len(parts) < 3 or parts[0] != "narrow" or parts[1] != "stream":
            return {}

        stream_part = parts[2]
        result: ParsedNarrowLink = {}

        # Parse optional stream id from "[{stream_id}-]{stream-name}"
        if "-" in stream_part:
            possible_id, stream_name = stream_part.split("-", 1)
            if possible_id.isdigit():
                result["stream_id"] = int(possible_id)
                result["stream"] = unquote(stream_name)
            else:
                result["stream"] = unquote(stream_part)
        else:
            result["stream"] = unquote(stream_part)

        i = 3
        while i < len(parts):
            if parts[i] == "topic":
                if i + 1 >= len(parts):
                    return {}
                result["topic"] = unquote(parts[i + 1])
                i += 2
            elif parts[i] == "near":
                if i + 1 >= len(parts) or not parts[i + 1].isdigit():
                    return {}
                result["near"] = int(parts[i + 1])
                i += 2
            else:
                return {}

        return result

class MessageLinkButton:
    def _switch_narrow_to(self, parsed_link: ParsedNarrowLink) -> None:
        """
        This function switches the narrow view in the MessageLinkButton instance based on the parsed link. It determines the type of narrow view based on the "narrow" key in the parsed link and calls the corresponding narrow_to_* method in the controller.
        Input-Output Arguments
        :param self: MessageLinkButton. An instance of the MessageLinkButton class.
        :param parsed_link: ParsedNarrowLink. The parsed link containing information about the narrow view to switch to.
        :return: No return values.
        """
        narrow = parsed_link["narrow"]

        if narrow == "home":
            self.controller.narrow_to_home()
        elif narrow == "all":
            self.controller.narrow_to_all_messages()
        elif narrow == "mentions":
            self.controller.narrow_to_mentions()
        elif narrow == "starred":
            self.controller.narrow_to_starred()
        elif narrow == "dm":
            self.controller.narrow_to_direct_message(parsed_link["recipients"])
        elif narrow == "stream":
            topic = parsed_link.get("topic")
            if topic is not None:
                self.controller.narrow_to_topic(parsed_link["stream"], topic)
            else:
                self.controller.narrow_to_stream(parsed_link["stream"])
        else:
            raise ValueError(f"Unsupported narrow type: {narrow}")

class MessageLinkButton:
    def _validate_and_patch_stream_data(self, parsed_link: ParsedNarrowLink) -> str:
        """
        This function validates the stream data in a parsed link and patches the optional value in the nested DecodedStream dictionary. It checks if the stream ID and name are valid and subscribed to by the user. If not, it returns an error message. It also updates the stream ID or name in the parsed link if necessary.
        Input-Output Arguments
        :param self: MessageLinkButton. An instance of the MessageLinkButton class.
        :param parsed_link: ParsedNarrowLink. The parsed link containing the stream data.
        :return: str. An empty string if the stream data is valid and patched successfully. Otherwise, an error message indicating the issue with the stream.
        """
        stream_data = parsed_link.stream

        if stream_data is None:
            return "Invalid stream link."

        stream_id = stream_data.get("stream_id")
        stream_name = stream_data.get("stream")

        stream = None

        # If stream_id is present, try validating/fetching by ID first.
        if stream_id is not None:
            try:
                stream = access_stream_by_id(self.user_profile, stream_id)
            except Exception:
                return "Invalid stream."

            # Patch missing/incorrect stream name from canonical stream object.
            if stream_name is None or stream_name != stream.name:
                stream_data["stream"] = stream.name

        # If no valid stream found yet, try validating/fetching by name.
        if stream is None and stream_name is not None:
            try:
                stream = access_stream_by_name(self.user_profile, stream_name)
            except Exception:
                return "Invalid stream."

            # Patch missing stream_id from canonical stream object.
            if stream_id is None or stream_id != stream.id:
                stream_data["stream_id"] = stream.id

        if stream is None:
            return "Invalid stream."

        # Ensure the user can access / is subscribed to the stream.
        if not self.user_profile.is_realm_admin and not subscribed_to_stream(
            self.user_profile, stream
        ):
            return "You are not subscribed to this stream."

        return ""

class MessageLinkButton:
    def _validate_narrow_link(self, parsed_link: ParsedNarrowLink) -> str:
        """
        This function validates a narrow link and returns either an empty string
        if the validation is successful or an appropriate validation error message
        if the validation fails. It checks various conditions related to the parsed
        link and returns the corresponding error message if any condition is not met.

        Input-Output Arguments
        :param self: MessageLinkButton. An instance of the MessageLinkButton class.
        :param parsed_link: ParsedNarrowLink. The parsed narrow link to be validated.
        :return: str. Either an empty string for successful validation or an
                     appropriate validation error message.
        """

        if parsed_link is None:
            return "Invalid narrow link."

        # Validate stream/topic combinations.
        stream = getattr(parsed_link, "stream", None)
        topic = getattr(parsed_link, "topic", None)
        is_dm = getattr(parsed_link, "is_dm", False)
        message_id = getattr(parsed_link, "message_id", None)

        # Topic narrow without a stream is invalid.
        if topic is not None and stream is None and not is_dm:
            return "Topic narrow links must include a stream."

        # A link cannot be both a stream/topic narrow and a DM narrow.
        if is_dm and (stream is not None or topic is not None):
            return "Direct message narrow links cannot include stream or topic."

        # Validate message_id if present.
        if message_id is not None:
            if not isinstance(message_id, int):
                return "Message ID must be an integer."
            if message_id <= 0:
                return "Message ID must be greater than 0."

        # Validate stream if present.
        if stream is not None:
            if isinstance(stream, str):
                if not stream.strip():
                    return "Stream name cannot be empty."
            elif isinstance(stream, int):
                if stream <= 0:
                    return "Stream ID must be greater than 0."
            else:
                return "Stream must be a valid stream name or stream ID."

        # Validate topic if present.
        if topic is not None:
            if not isinstance(topic, str):
                return "Topic must be a string."
            if not topic.strip():
                return "Topic name cannot be empty."

        # Validate DM recipients if present.
        recipients = getattr(parsed_link, "dm_recipients", None)
        if is_dm:
            if not recipients:
                return "Direct message narrow links must include recipients."
            if not isinstance(recipients, (list, tuple)):
                return "Direct message recipients must be a list or tuple."
            if any(not recipient for recipient in recipients):
                return "Direct message recipients cannot be empty."

        return ""

