import sqlparse
from sqlparse.sql import Identifier, IdentifierList
from sqlparse.tokens import Keyword, DML
from collections import namedtuple

TableReference = namedtuple("TableReference", ["name", "alias"])


def extract_tables(sql):
    """
    This function extracts the table names from an SQL statement. It uses the sqlparse library to parse the SQL statement and then extracts the table names from the parsed result.
    Input-Output Arguments
    :param sql: String. The SQL statement to extract table names from.
    :return: Tuple of TableReference namedtuples. The extracted table names from the SQL statement.
    """

    def is_subselect(parsed):
        if not parsed.is_group:
            return False
        for item in parsed.tokens:
            if item.ttype is DML and item.value.upper() == "SELECT":
                return True
        return False

    def extract_from_part(parsed):
        from_seen = False
        join_keywords = {
            "JOIN", "INNER JOIN", "LEFT JOIN", "RIGHT JOIN", "FULL JOIN",
            "LEFT OUTER JOIN", "RIGHT OUTER JOIN", "FULL OUTER JOIN", "CROSS JOIN"
        }

        for item in parsed.tokens:
            if is_subselect(item):
                yield from extract_from_part(item)

            if from_seen:
                if is_subselect(item):
                    yield from extract_from_part(item)
                elif isinstance(item, IdentifierList):
                    for identifier in item.get_identifiers():
                        yield identifier
                elif isinstance(item, Identifier):
                    yield item
                elif item.ttype is Keyword and item.value.upper() in (
                    "WHERE", "GROUP", "ORDER", "HAVING", "LIMIT", "UNION", "EXCEPT", "INTERSECT"
                ):
                    from_seen = False
                elif item.ttype is Keyword and "JOIN" in item.value.upper():
                    continue

            if item.ttype is Keyword and item.value.upper() == "FROM":
                from_seen = True
            elif item.ttype is Keyword and item.value.upper() in join_keywords:
                from_seen = True

    def normalize_identifier(identifier):
        real_name = identifier.get_real_name()
        alias = identifier.get_alias()
        if real_name:
            return TableReference(name=real_name, alias=alias)
        return None

    statements = sqlparse.parse(sql)
    tables = []

    for statement in statements:
        for identifier in extract_from_part(statement):
            table_ref = normalize_identifier(identifier)
            if table_ref:
                tables.append(table_ref)

    return tuple(tables)

