if isinstance(element, str):
    element = element.encode()
elif isinstance(element, int):
    element = str(element).encode()
elif not isinstance(element, (bytes, bytearray)):
    element = bytes(element)

digest = hashlib.new('ripemd160', element).digest()
stack.append(digest)
return True

