def _normalize_group(group):
  """
  Convert a group object into a comparable set of lines.
  Supports common container types and falls back safely.
  """
  if group is None:
    return set()

  # If already a simple iterable of lines
  if isinstance(group, (list, tuple, set)):
    return set(str(item).strip() for item in group if str(item).strip())

  # If dictionary-like, compare its values or members if present
  if isinstance(group, dict):
    if 'members' in group:
      members = group['members']
      if isinstance(members, (list, tuple, set)):
        return set(str(item).strip() for item in members if str(item).strip())
    return set(
      f"{str(k).strip()}={str(v).strip()}"
      for k, v in group.items()
      if str(k).strip() or str(v).strip()
    )

  # If object has a members attribute
  if hasattr(group, 'members'):
    members = getattr(group, 'members')
    if isinstance(members, (list, tuple, set)):
      return set(str(item).strip() for item in members if str(item).strip())

  # Fallback: treat as single string/object
  text = str(group).strip()
  return {text} if text else set()

