class EnSpell:
    def correct(self, text, include_symbol=True):
        """
        This function corrects the spelling of a given text by replacing incorrect words with their most probable correct versions. It also provides details about the corrections made, such as the wrong word, the correct word, and the indices of the correction within the text. The function first ensure that necessary data is initialized. Then, it split the input text into blocks of words. The include_symbol parameter determines whether punctuations are included in the split blocks.
        The function then iterates over each block of words and their corresponding indices. If a word is more than one character long and consists of alphabetical characters, it checks if the word is confusion. If it does, the corrected item is retrieved from the dictionary. Otherwise, it parse the word to obtain the corrected item.
        If the corrected item is different from the original word, the beginning and ending indices of the word are calculated, and a detail tuple is created containing the original word, the corrected item, and the indices and saved in a list. The word is then replaced with the corrected item. Finally, the details list is sorted based on the beginning indices of the words, and the corrected text and details list are returned as a tuple.
        Input-Output Arguments
        :param self: EnSpell. An instance of the EnSpell class.
        :param text: String. The input query to be corrected.
        :param include_symbol: Bool. Whether to include symbols in the correction process. Defaults to True.
        :return: Tuple. The corrected text and a list of details about the corrections made. Each detail is represented as a list containing the wrong word, the correct word, the beginning index, and the ending index of the correction within the text.
        """
        if hasattr(self, "_init") and callable(self._init):
            self._init()

        details = []

        if hasattr(self, "split_words"):
            blocks = self.split_words(text, include_symbol=include_symbol)
        elif hasattr(self, "_split_words"):
            blocks = self._split_words(text, include_symbol=include_symbol)
        else:
            import re
            if include_symbol:
                blocks = [(m.group(), m.start(), m.end()) for m in re.finditer(r"\w+|[^\w\s]", text)]
            else:
                blocks = [(m.group(), m.start(), m.end()) for m in re.finditer(r"\w+", text)]

        corrected_parts = []
        last_end = 0

        for block in blocks:
            if len(block) == 3:
                word, begin, end = block
            else:
                word = block[0]
                begin = text.find(word, last_end)
                end = begin + len(word)

            corrected_item = word

            if len(word) > 1 and word.isalpha():
                lower_word = word.lower()

                if hasattr(self, "confusion") and lower_word in self.confusion:
                    corrected_item = self.confusion[lower_word]
                elif hasattr(self, "_confusion") and lower_word in self._confusion:
                    corrected_item = self._confusion[lower_word]
                elif hasattr(self, "parse") and callable(self.parse):
                    corrected_item = self.parse(lower_word)
                elif hasattr(self, "_parse") and callable(self._parse):
                    corrected_item = self._parse(lower_word)

                if corrected_item is None:
                    corrected_item = word

                if word.istitle():
                    corrected_item = corrected_item.title()
                elif word.isupper():
                    corrected_item = corrected_item.upper()

            corrected_parts.append(text[last_end:begin])

            if corrected_item != word:
                details.append([word, corrected_item, begin, end])

            corrected_parts.append(corrected_item)
            last_end = end

        corrected_parts.append(text[last_end:])
        details.sort(key=lambda x: x[2])

        return "".join(corrected_parts), details

class CommandStrategy:
    def find_redirection_file_path(tokens):
        """
        This function finds the path of the file to which the output of a command should be redirected.
        It checks the tokens list to determine the type of redirection and returns a 2-tuple
        containing the redirection type and the file path.

        If no redirection is found, it returns None.
        If the redirection should be done to nowhere, it returns a 2-tuple with the redirection
        type set to "quiet" and the file path set to None.

        Input-Output Arguments
        :param tokens: List of strings. The tokens representing the command and redirection symbols.
        :return: 2-tuple. The first element is the redirection type, an enumeration item of type
                 "RedirectionType". The second element is the file path to which the output should
                 be redirected. Returns None if no redirection is found.
                 Returns (RedirectionType.quiet, None) if the redirection should be done to nowhere.
        """

        if not tokens:
            return None

        # Check longer operators first to avoid partial matches
        redirection_map = {
            ">>": getattr(RedirectionType, "append", "append"),
            ">": getattr(RedirectionType, "write", "write"),
        }

        for i, token in enumerate(tokens):
            if token in redirection_map:
                redirection_type = redirection_map[token]

                # No file path provided after redirection operator
                if i + 1 >= len(tokens):
                    return (RedirectionType.quiet, None)

                file_path = tokens[i + 1]

                # Redirect to nowhere
                if file_path in ("/dev/null", "NUL", "nul", "NULL", "null"):
                    return (RedirectionType.quiet, None)

                return (redirection_type, file_path)

        return None

